async function strangettsContentLicenseActive() {
    try {
        const resp = await fetch(`${STRANGETTS_LOCAL_LICENSE_API}/api/license/status`, { cache: 'no-store' });
        const data = await resp.json().catch(() => ({}));
        return data?.license?.active === true;
    } catch {
        return false;
    }
}

function strangettsIcon(name) {
    const svg = STRANGETTS_ICON_SVG[name] || '';
    return svg.replace(/<svg /, '<svg width="16" height="16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" ');
}

function strangettsSetButtonIcon(id, icon, label = '', title = '') {
    const el = typeof id === 'string' ? document.getElementById(id) : id;
    if (!el) return;
    el.classList.add('strangetts-icon-btn');
    if (!label) el.classList.add('strangetts-icon-only');
    else el.classList.remove('strangetts-icon-only');
    const nextKey = `${icon}|${label}`;
    if (el.dataset.strangettsIconKey === nextKey && el.querySelector('.strangetts-header-svg')) {
        if (title) el.title = title;
        return;
    }
    el.dataset.strangettsIconKey = nextKey;
    el.innerHTML = `${strangettsIcon(icon)}${label ? `<span>${label}</span>` : ''}`;
    if (title) el.title = title;
}

function strangettsNormalizeFooterBrandName(name) {
    const raw = String(name || '').replace(/\s+/g, ' ').trim();
    if (!raw) return 'Strange';
    return raw.replace(/^Stonk(\b|\s|[0-9.])/i, 'Strange$1');
}

function strangettsPlainButtonLabel(el, fallback = '') {
    const text = String(el?.textContent || fallback || '')
        .replace(/[^\p{L}\p{N}\s:./|()-]/gu, ' ')
        .replace(/\s+/g, ' ')
        .trim();
    return text || fallback;
}

function strangettsApplyPanelIconPass() {
    strangettsSetButtonIcon('tt-btn-scroll-top', 'up', '', 'Lên đầu');
    strangettsSetButtonIcon('tt-btn-scroll-bottom', 'down', '', 'Xuống cuối');
    strangettsSetButtonIcon('tt-btn-theme-toggle', 'theme', '', 'Đổi giao diện sáng/tối');
    strangettsSetButtonIcon('tt-btn-fullscreen-quick', 'fullscreen', '', 'Toàn màn hình');
    strangettsSetButtonIcon('tt-btn-maximize', 'window', '', 'Tùy chọn kích thước cửa sổ');
    strangettsSetButtonIcon('tt-btn-minimize', 'minimize', '', 'Thu nhỏ');
    strangettsSetButtonIcon('tt-btn-close-x', 'close', '', 'Tắt extension');
    strangettsSetButtonIcon('tt-btn-reset-tabs', 'refresh', '', 'Reset tool nếu bị kẹt');
    strangettsSetButtonIcon('tt-btn-toggle-cfg', 'settings', '', 'Cài đặt');
    strangettsSetButtonIcon('tt-btn-load-roi', 'chart', 'ROI tắt', 'Đã tắt để giảm request khi dùng Seller');

    const scan = document.getElementById('tt-btn-scan');
    const scanLabel = /cache/i.test(scan?.textContent || '') ? strangettsPlainButtonLabel(scan, 'Cache SP') : 'Sản phẩm';
    strangettsSetButtonIcon(scan, /cache/i.test(scanLabel) ? 'cache' : 'product', scanLabel);
    const ads = document.getElementById('tt-btn-scan-ads');
    strangettsSetButtonIcon(ads, /cache/i.test(ads?.textContent || '') ? 'cache' : 'chart', strangettsPlainButtonLabel(ads, 'Chiến dịch'));

    strangettsSetButtonIcon('strangetts-api-reload', 'refresh', '', 'Reload');
    strangettsSetButtonIcon('strangetts-quick-sync-cloud', 'cloud', 'Sync');
    strangettsSetButtonIcon('strangetts-export-shop', 'export', 'Xuất');
    strangettsSetButtonIcon('strangetts-open-dashboard', 'dashboard', 'Dash');
    strangettsSetButtonIcon('strangetts-footer-feedback', 'feedback', 'Góp ý');
    strangettsSetButtonIcon('strangetts-footer-topup', 'topup', 'Nạp');

    const footerName = document.getElementById('strangetts-footer-name');
    if (footerName) {
        footerName.textContent = strangettsNormalizeFooterBrandName(footerName.textContent);
        footerName.title = strangettsNormalizeFooterBrandName(footerName.title || footerName.textContent);
    }

    const statMap = [
        ['strangetts-footer-bal', 'money'],
        ['strangetts-footer-credit', 'voucher'],
        ['strangetts-footer-budget', 'budget'],
        ['strangetts-footer-thresh-val', 'threshold']
    ];
    statMap.forEach(([id, icon]) => {
        const valueEl = document.getElementById(id);
        const wrap = valueEl?.parentElement;
        if (!valueEl || !wrap || wrap.dataset.strangettsIconized === icon) return;
        wrap.dataset.strangettsIconized = icon;
        Array.from(wrap.childNodes).forEach(node => {
            if (node.nodeType === Node.TEXT_NODE) node.textContent = '';
        });
        if (!wrap.querySelector('.strangetts-footer-stat-icon')) {
            const holder = document.createElement('span');
            holder.className = 'strangetts-footer-stat-icon';
            holder.innerHTML = strangettsIcon(icon);
            wrap.insertBefore(holder, valueEl);
        }
        wrap.classList.add('strangetts-footer-stat');
    });
}

async function strangettsEnsureLocalAppAuth() {
    const store = await new Promise(r => chrome.storage.local.get(['strangetts_v30_auth'], r));
    const auth = store.strangetts_v30_auth;
    if (auth && auth.username && auth.token && auth.serverAuth === true && Date.now() < (auth.expiry || 0)) return auth;
    if (!STRANGETTS_LOCAL_APP_MODE_CONTENT) return null;
    const next = {
        username: 'local-admin',
        role: 'admin',
        display: 'Strange',
        token: `local-pc-app-${chrome.runtime.id || 'runtime'}`,
        syncUrl: 'https://cartridges-warranty-management-incentive.trycloudflare.com',
        serverAuth: true,
        localAppMode: true,
        expiry: Date.now() + STRANGETTS_LOCAL_SESSION_TTL_CONTENT,
        loginAt: Date.now()
    };
    await new Promise(r => chrome.storage.local.set({ strangetts_v30_auth: next }, r));
    return next;
}

function strangettsEnsureThemeStylesheet() {
    if (document.getElementById('strangetts-theme-stylesheet')) return;
    const link = document.createElement('link');
    link.id = 'strangetts-theme-stylesheet';
    link.rel = 'stylesheet';
    link.href = chrome.runtime.getURL('styles/strangetts-theme.css');
    (document.head || document.documentElement).appendChild(link);
}

function strangettsApplyPanelTheme(theme) {
    strangettsEnsureThemeStylesheet();
    const panel = document.getElementById('tt-auto-ext');
    const nextTheme = theme === 'light' ? 'light' : 'dark';
    document.documentElement.dataset.strangettsTheme = nextTheme;
    if (panel) panel.dataset.theme = nextTheme;
    const btn = document.getElementById('tt-btn-theme-toggle');
    if (btn) {
        btn.textContent = nextTheme === 'light' ? '🌙' : '☀️';
        btn.title = nextTheme === 'light' ? 'Đang dùng giao diện sáng' : 'Đang dùng giao diện tối';
    }
}

async function strangettsLoadAndApplyPanelTheme() {
    const store = await new Promise(r => chrome.storage.local.get({ [STRANGETTS_UI_THEME_KEY]: 'dark' }, r));
    strangettsApplyPanelTheme(store[STRANGETTS_UI_THEME_KEY]);
}

const STRANGETTS_ACTIVE_SHOP_CONTEXT_KEY = 'strangetts_active_shop_context';
let strangettsActiveShopTitle = '';
let strangettsShopTitleObserver = null;
let strangettsShopTitleTimer = null;

function strangettsSafeText(value = '') {
    return String(value || '').replace(/\s+/g, ' ').trim();
}

function strangettsAsciiTitleText(value = '') {
    return strangettsSafeText(value)
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '')
        .replace(/[đĐ]/g, match => match === 'Đ' ? 'D' : 'd')
        .replace(/[^\x20-\x7E]/g, '')
        .trim();
}

function strangettsRenderShopHeaderBadge(ctx = {}) {
    const name = strangettsSafeText(ctx.name || ctx.shopRealName || ctx.shopKey);
    if (!name) return;
    const avatar = strangettsSafeText(ctx.avatar || ctx.shopAvatar || ctx.shopLogo);
    let badge = document.getElementById('strangetts-shop-window-badge');
    if (!badge) {
        badge = document.createElement('div');
        badge.id = 'strangetts-shop-window-badge';
        badge.style.cssText = [
            'position:fixed',
            'top:10px',
            'left:12px',
            'z-index:2147483646',
            'height:42px',
            'max-width:420px',
            'display:flex',
            'align-items:center',
            'gap:10px',
            'padding:5px 12px 5px 6px',
            'border-radius:13px',
            'background:rgba(10,14,18,0.92)',
            'border:1px solid rgba(34,211,238,0.45)',
            'box-shadow:0 12px 32px rgba(0,0,0,0.38), 0 0 18px rgba(34,211,238,0.15)',
            'backdrop-filter:blur(10px)',
            'color:#fff',
            'font-family:Inter,Segoe UI,Arial,sans-serif',
            'pointer-events:none'
        ].join(';');
        badge.innerHTML = `
            <div data-role="avatar" style="width:32px;height:32px;border-radius:9px;overflow:hidden;display:flex;align-items:center;justify-content:center;background:linear-gradient(135deg,#06b6d4,#2563eb);font-weight:900;flex:0 0 auto;color:#fff"></div>
            <div style="min-width:0;display:flex;flex-direction:column;line-height:1.05">
                <div data-role="name" style="font-size:14px;font-weight:900;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:340px"></div>
                <div data-role="sub" style="font-size:10px;font-weight:700;color:rgba(226,232,240,0.72);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:340px"></div>
            </div>
        `;
        document.documentElement.appendChild(badge);
    }
    const avatarSlot = badge.querySelector('[data-role="avatar"]');
    const nameSlot = badge.querySelector('[data-role="name"]');
    const subSlot = badge.querySelector('[data-role="sub"]');
    nameSlot.textContent = name;
    subSlot.textContent = [ctx.pageType || 'Seller', ctx.profileName || ''].filter(Boolean).join(' • ');
    if (avatar && /^https?:\/\//i.test(avatar)) {
        avatarSlot.innerHTML = '';
        const img = document.createElement('img');
        img.src = avatar;
        img.alt = name;
        img.referrerPolicy = 'no-referrer';
        img.style.cssText = 'width:100%;height:100%;object-fit:cover;display:block';
        avatarSlot.appendChild(img);
    } else {
        avatarSlot.textContent = name.slice(0, 1).toUpperCase();
    }
}

function strangettsRemoveShopHeaderBadge() {
    document.getElementById('strangetts-shop-window-badge')?.remove();
}

function strangettsApplyPinnedShopTitle() {
    if (!strangettsActiveShopTitle) return;
    if (document.title !== strangettsActiveShopTitle) document.title = strangettsActiveShopTitle;
    const head = document.head || document.documentElement;
    let titleEl = head.querySelector('title');
    if (!titleEl) {
        titleEl = document.createElement('title');
        head.prepend(titleEl);
    }
    if (titleEl.textContent !== strangettsActiveShopTitle) titleEl.textContent = strangettsActiveShopTitle;
}

function strangettsPinShopTitle(name) {
    const safeName = strangettsAsciiTitleText(name) || strangettsSafeText(name);
    if (!safeName) return;
    strangettsActiveShopTitle = `${safeName} - Seller Ads | Strange TTS`;
    strangettsApplyPinnedShopTitle();
    requestAnimationFrame(strangettsApplyPinnedShopTitle);
    setTimeout(strangettsApplyPinnedShopTitle, 500);
    setTimeout(strangettsApplyPinnedShopTitle, 1500);

    if (!strangettsShopTitleObserver && document.documentElement) {
        strangettsShopTitleObserver = new MutationObserver(strangettsApplyPinnedShopTitle);
        strangettsShopTitleObserver.observe(document.documentElement, {
            childList: true,
            subtree: true,
            characterData: true
        });
    }

    if (!strangettsShopTitleTimer) {
        strangettsShopTitleTimer = setInterval(strangettsApplyPinnedShopTitle, 1000);
    }
}

async function strangettsApplyActiveShopContext() {
    try {
        const data = await new Promise(r => chrome.storage.local.get([STRANGETTS_ACTIVE_SHOP_CONTEXT_KEY], r));
        const ctx = data?.[STRANGETTS_ACTIVE_SHOP_CONTEXT_KEY];
        const name = strangettsSafeText(ctx?.name || ctx?.shopRealName || ctx?.shopKey);
        if (!name) return;
        strangettsPinShopTitle(name);
        strangettsRemoveShopHeaderBadge();
    } catch (error) {
        console.warn('[STRANGE TTS] Shop header context failed:', error?.message || error);
    }
}

strangettsApplyActiveShopContext();
chrome.storage.onChanged.addListener((changes, area) => {
    if (area === 'local' && changes[STRANGETTS_ACTIVE_SHOP_CONTEXT_KEY]) {
        strangettsApplyActiveShopContext();
    }
});

async function strangettsSha256(str) {
    const buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(str));
    return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2, '0')).join('');
}

async function strangettsLegacyWebToolToken(username) {
    if (!STRANGETTS_WEB_TOOL_AUTH_SECRET) return '';
    const today = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Ho_Chi_Minh' });
    return (await strangettsSha256(`${username}-${STRANGETTS_WEB_TOOL_AUTH_SECRET}-${today}`)).slice(0, 16);
}

async function strangettsOpenAiDataSSOFromPage() {
    const auth = await strangettsEnsureLocalAppAuth();
    if (!auth || !auth.username) {
        alert('Bạn chưa đăng nhập extension. Hãy bấm icon Strange TTS Solution để đăng nhập trước.');
        return;
    }
    const token = await strangettsLegacyWebToolToken(auth.username);
    const url = `${STRANGETTS_AI_DATA_URL}/?auth_user=${encodeURIComponent(auth.username)}&token=${token}`;
    chrome.runtime.sendMessage({ action: 'open_tabs', urls: [{ url, active: true }] });
}

function strangettsFormatBudget(val) {
    let num = String(val).replace(/[^0-9]/g, '');
    return num.replace(/\B(?=(\d{3})+(?!\d))/g, '.');
}
async function getStrangeTTSConfig() {
    return new Promise(r => chrome.storage.local.get(['tt_bot_config'], d => {
        let c = d.tt_bot_config || {};
        r({
            pageLoadTimeout: (c.pageLoadTimeout || 60) * 1000,    // ms
            flowTimeout: (c.flowTimeout || 180) * 1000,           // ms
            editTimeout: (c.editTimeout || 120) * 1000,           // ms
            lockExpiry: (c.lockExpiry || 30) * 1000,              // ms
            spRetries: c.spRetries || 8,
            inputDelay: (c.inputDelay || 3) * 1000,               // ms
            apiScan: c.apiScan !== false,                              // load SP via API (mặc định BẬT)
            apiAds: c.apiAds !== false,                                    // quét Ads via API trực tiếp (mặc định BẬT)
            apiCreate: c.apiCreate !== false,                           // create camp via API (mặc định BẬT)
            apiEdit: c.apiEdit !== false                                // edit camp via API (mặc định BẬT)
        });
    }));
}

