// Helper: đóng tab qua background.js (window.close() không hoạt động trong content script)
function strangettsCloseTab() {
    try { chrome.runtime.sendMessage({ action: 'close_current_tab' }); } catch (e) { }
    setTimeout(() => { try { window.close(); } catch (e) { } }, 500); // Fallback
}

// Soft reload: toggle filter params on dashboard to force TikTok re-fetch data (no F5)
async function strangettsSoftReloadDashboard() {
    if (!location.href.includes('/ads-creation/dashboard')) return;
    let url = new URL(location.href);
    let origStatus = url.searchParams.get('list_status') || 'delivery_ok';
    // Step 1: switch to not_delivery
    url.searchParams.set('list_status', 'not_delivery');
    history.replaceState(null, '', url.toString());
    window.dispatchEvent(new PopStateEvent('popstate'));
    await wait(1500);
    // Step 2: switch back to original
    url.searchParams.set('list_status', origStatus);
    history.replaceState(null, '', url.toString());
    window.dispatchEvent(new PopStateEvent('popstate'));
    console.log('[STRANGE TTS] Soft reload dashboard done');
}

const strangettsProgress = {
    _ring: null,
    _badge: null,
    _circumference: 2 * Math.PI * 17,
    _timer: null,
    _retryCount: 0,

    _inject() {
        if (this._ring && this._badge) return true;
        let brandBar = document.getElementById('strangetts-brand-bar');
        if (!brandBar) {
            // Brand bar chưa load, retry sau 1s
            if (this._retryCount < 10) {
                this._retryCount++;
                setTimeout(() => this._inject(), 1000);
            }
            return false;
        }
        if (this._ring) return true; // ring đã tạo rồi
        let logoImg = brandBar.querySelector('img');
        if (!logoImg) return false;

        // Wrap logo img trong SVG ring container
        let wrap = document.createElement('div');
        wrap.id = 'strangetts-ring-wrap';
        wrap.style.cssText = 'position:relative; width:50px; height:50px; flex-shrink:0;';
        logoImg.parentElement.insertBefore(wrap, logoImg);
        logoImg.style.cssText = 'width:40px; height:40px; border-radius:50%; position:absolute; top:50%; left:50%; transform:translate(-50%,-50%);';
        wrap.appendChild(logoImg);

        // SVG ring
        let svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
        svg.setAttribute('viewBox', '0 0 40 40');
        svg.style.cssText = 'position:absolute; top:0; left:0; width:50px; height:50px; transform:rotate(-90deg);';
        svg.innerHTML = `
            <defs><linearGradient id="sp-grad" x1="0%" y1="0%" x2="100%" y2="100%">
                <stop offset="0%" style="stop-color:#E0E0E0"/><stop offset="100%" style="stop-color:#8A8D91"/>
            </linearGradient></defs>
            <circle cx="20" cy="20" r="17" fill="none" stroke="rgba(138,141,145,0.15)" stroke-width="3"/>
            <circle id="strangetts-hdr-ring" cx="20" cy="20" r="17" fill="none" stroke="url(#sp-grad)" stroke-width="3" stroke-linecap="round"
                stroke-dasharray="${this._circumference}" stroke-dashoffset="${this._circumference}" style="transition:stroke-dashoffset 0.5s ease;"/>
        `;
        wrap.appendChild(svg);
        this._ring = svg.querySelector('#strangetts-hdr-ring');

        // Status text inline (hiện bên cạnh trong header)
        let statusArea = document.getElementById('strangetts-hdr-status');
        if (!statusArea) {
            statusArea = document.createElement('div');
            statusArea.id = 'strangetts-hdr-status';
            statusArea.style.cssText = 'display:none; align-items:center; gap:6px; margin-left:8px; font-family:Inter,sans-serif;';
            statusArea.innerHTML = `<span id="strangetts-hdr-pct" style="font-size:14px; font-weight:700; background:linear-gradient(90deg,#E0E0E0,#8A8D91); -webkit-background-clip:text; -webkit-text-fill-color:transparent;">0%</span><span id="strangetts-hdr-text" style="font-size:12px; color:#8A8D91; max-width:200px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">Chuẩn bị...</span>`;
            brandBar.appendChild(statusArea);
        }
        this._badge = statusArea;
        return true;
    },

    show(text = 'Đang khởi động...') {
        if (!this._inject()) {
            // Retry khi brand bar sẵn sàng
            let self = this;
            setTimeout(() => self.show(text), 1500);
            return;
        }
        if (this._badge) this._badge.style.display = 'flex';
        this.update(0, text);
    },

    update(percent, text) {
        this._inject();
        if (!this._ring) return;
        percent = Math.max(0, Math.min(100, percent));
        let offset = this._circumference - (percent / 100) * this._circumference;
        this._ring.style.strokeDashoffset = offset;
        let pctEl = document.getElementById('strangetts-hdr-pct');
        let txtEl = document.getElementById('strangetts-hdr-text');
        if (pctEl) pctEl.textContent = Math.round(percent) + '%';
        if (txtEl && text) txtEl.textContent = text;
        if (this._badge) this._badge.style.display = 'flex';
        // Lưu progress vào storage để main panel hiển thị
        try { chrome.storage.local.set({ tt_progress: { percent, text: text || '', ts: Date.now() } }); } catch (e) { }
    },

    error(text) {
        this._inject();
        let pctEl = document.getElementById('strangetts-hdr-pct');
        let txtEl = document.getElementById('strangetts-hdr-text');
        if (pctEl) pctEl.textContent = '❌';
        if (txtEl && text) txtEl.textContent = text;
        if (this._ring) this._ring.style.stroke = '#ff4444';
        clearTimeout(this._timer);
        this._timer = setTimeout(() => this.hide(), 8000);
    },

    success(text) {
        this._inject();
        this.update(100, text || '✅ Hoàn tất!');
        if (this._ring) this._ring.style.stroke = '#00e676';
        clearTimeout(this._timer);
        this._timer = setTimeout(() => this.hide(), 5000);
    },

    hide() {
        if (this._badge) this._badge.style.display = 'none';
        if (this._ring) {
            this._ring.style.strokeDashoffset = this._circumference;
            this._ring.style.stroke = 'url(#sp-grad)';
        }
    }
};

function strangettsGetCookie(name) {
    const m = document.cookie.match(new RegExp('(^|;\s*)' + name + '=([^;]+)'));
    return m ? decodeURIComponent(m[2]) : '';
}

function strangettsGetCsrf() {
    // Ưu tiên 1: token được page_sniffer capture từ TikTok's XHR (đáng tin cậy nhất)
    if (window.__STRANGETTS_CSRF__) return window.__STRANGETTS_CSRF__;
    // Ưu tiên 2: đọc từ cookie (các tên khác nhau tùy trang)
    return strangettsGetCookie('tt_csrf_token')
        || strangettsGetCookie('csrftoken')
        || strangettsGetCookie('csrf_session_id')
        || document.cookie.match(/(?:tt_csrf_token|csrftoken|csrf_session_id|_csrf)=([^;]+)/)?.[1]
        || '';
}

// Safe timezone helpers — fallback nếu VPS không hỗ trợ Asia/Ho_Chi_Minh
function strangettsDateVN(date) {
    if (!date) date = new Date();
    try {
        return date.toLocaleDateString('en-CA', { timeZone: 'Asia/Ho_Chi_Minh' });
    } catch (e) {
        // Fallback: manual UTC+7
        let utc7 = new Date(date.getTime() + 7 * 60 * 60 * 1000);
        let y = utc7.getUTCFullYear();
        let m = String(utc7.getUTCMonth() + 1).padStart(2, '0');
        let d = String(utc7.getUTCDate()).padStart(2, '0');
        return `${y}-${m}-${d}`;
    }
}
function strangettsTimeVN(date) {
    if (!date) date = new Date();
    try {
        return date.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false, timeZone: 'Asia/Ho_Chi_Minh' });
    } catch (e) {
        let utc7 = new Date(date.getTime() + 7 * 60 * 60 * 1000);
        let h = String(utc7.getUTCHours()).padStart(2, '0');
        let mi = String(utc7.getUTCMinutes()).padStart(2, '0');
        let s = String(utc7.getUTCSeconds()).padStart(2, '0');
        return `${h}:${mi}:${s}`;
    }
}
function strangettsDateVN_DDMM(date) {
    if (!date) date = new Date();
    try {
        return date.toLocaleDateString('vi-VN', { day: '2-digit', month: '2-digit', year: 'numeric', timeZone: 'Asia/Ho_Chi_Minh' });
    } catch (e) {
        let utc7 = new Date(date.getTime() + 7 * 60 * 60 * 1000);
        let d = String(utc7.getUTCDate()).padStart(2, '0');
        let m = String(utc7.getUTCMonth() + 1).padStart(2, '0');
        let y = utc7.getUTCFullYear();
        return `${d}/${m}/${y}`;
    }
}
function strangettsDateTimeVN(date) {
    if (!date) date = new Date();
    return `${strangettsDateVN_DDMM(date)} ${strangettsTimeVN(date)}`;
}

// Finalize campaign name: giới hạn phần tên chính, suffix nằm ngoài giới hạn
const STRANGETTS_NAME_SUFFIX = ' - By Strange TTSAgency.vn';
const STRANGETTS_NAME_MAX = 480;
const STRANGETTS_PRODUCT_NAME_PREFIX_MAX = 50;
function strangettsFinalizeCampName(name) {
    name = String(name || '').trim();
    if (name.endsWith(STRANGETTS_NAME_SUFFIX)) name = name.slice(0, -STRANGETTS_NAME_SUFFIX.length).trim();
    name = name.replace(/\s*-?\s*By Strange TTSAgency\.vn\s*$/i, '').trim();
    if (name.length > STRANGETTS_NAME_MAX) {
        name = name.substring(0, STRANGETTS_NAME_MAX - 3) + '...';
    }
    let full = name + STRANGETTS_NAME_SUFFIX;
    console.log(`[STRANGE TTS] 📝 Camp name (${name.length}/${STRANGETTS_NAME_MAX} + suffix = ${full.length} ký tự): ${full}`);
    return full;
}

function strangettsSmartTruncateName(text, maxLen) {
    text = String(text || '').replace(/\s+/g, ' ').trim();
    if (!maxLen || maxLen <= 0) return '';
    if (text.length <= maxLen) return text;
    return text.substring(0, maxLen).trim();
}

function strangettsCleanCampProductName(name, { keepLivePrefix = true } = {}) {
    let s = String(name || '').replace(/\s+/g, ' ').trim();
    if (!s) return '';
    s = s.replace(/\s*-?\s*By Strange TTSAgency\.vn\s*$/i, '').trim();
    // Bỏ tag API ở cả format cũ: [API-...] Tên SP, và format mới: Tên SP [API-...]
    s = s.replace(/\s*\[API-[SE]-[^\]]+\]\s*/gi, ' ').replace(/\s+/g, ' ').trim();
    if (!keepLivePrefix) s = s.replace(/^LIVE[_\s-]*/i, '').trim();
    s = s.replace(/^ST\.?\s*AI?\s*/i, '');
    s = s.replace(/^[\d.]+\s+/, '');
    s = s.replace(/\s*(ED\s+)?(up\s+)?\d{1,2}\/\d{1,2}\s+\d{1,2}:\d{2}/gi, ' ');
    return s.replace(/\s+/g, ' ').replace(/^[\s\-–—|·]+|[\s\-–—|·]+$/g, '').trim();
}

function strangettsBuildApiTag(mode, budget, roi, date = new Date(), spCount = 0) {
    let d = date instanceof Date && !isNaN(date.getTime()) ? date : new Date();
    let dd = String(d.getDate()).padStart(2, '0');
    let mm = String(d.getMonth() + 1).padStart(2, '0');
    let hh = String(d.getHours()).padStart(2, '0');
    let mi = String(d.getMinutes()).padStart(2, '0');
    let budgetTag = strangettsShortVN(parseInt(String(budget || '').replace(/\D/g, ''), 10) || 0);
    let roiNum = parseFloat(String(roi || '').replace(/,/g, '.')) || 0;
    let roiTag = roiNum > 0 ? (Math.round(roiNum * 10) / 10) : String(roi || '').trim();
    let spPart = spCount && spCount > 1 ? `-${spCount}SP` : '';
    return `[API-${String(mode || 'S').toUpperCase()}-${budgetTag}-R${roiTag}${spPart}-${dd}/${mm} ${hh}:${mi}]`;
}

function strangettsBuildApiCampName({ mode = 'S', productName = '', budget = 0, roi = 0, spCount = 0, date = new Date(), keepLivePrefix = true } = {}) {
    let names = String(productName || '').split('|||').map(n => strangettsCleanCampProductName(n, { keepLivePrefix })).filter(Boolean);
    let joined = names.length > 1 ? names.join(' + ') : (names[0] || strangettsCleanCampProductName(productName, { keepLivePrefix }) || 'Sản phẩm');
    let shortProduct = strangettsSmartTruncateName(joined, STRANGETTS_PRODUCT_NAME_PREFIX_MAX);
    let tag = strangettsBuildApiTag(mode, budget, roi, date, spCount || names.length || 0);
    return strangettsFinalizeCampName(`${shortProduct} ${tag}`);
}

function strangettsParseNameDateToMs(day, month, hour, minute) {
    day = parseInt(day); month = parseInt(month); hour = parseInt(hour); minute = parseInt(minute);
    if (!day || !month || hour == null || minute == null) return 0;
    let now = new Date();
    let d = new Date(now.getFullYear(), month - 1, day, hour, minute, 0);
    if (isNaN(d.getTime())) return 0;
    // Nếu ngày parse ra nằm quá xa tương lai thì đó thường là tag năm trước.
    if (d.getTime() - now.getTime() > 30 * 24 * 3600000) d.setFullYear(d.getFullYear() - 1);
    return d.getTime();
}

function strangettsExtractApiNameTime(name, preferredMode = 'E') {
    let s = String(name || '');
    let tags = [];
    let re = /\[API-([SE])-([^\]]*?)-(\d{1,2})\/(\d{1,2})\s+(\d{1,2}):(\d{2})\]/gi;
    let m;
    while ((m = re.exec(s))) {
        tags.push({ mode: m[1].toUpperCase(), ts: strangettsParseNameDateToMs(m[3], m[4], m[5], m[6]), raw: m[0] });
    }
    if (preferredMode) {
        let preferred = tags.filter(t => t.mode === String(preferredMode).toUpperCase() && t.ts > 0);
        if (preferred.length) return preferred[preferred.length - 1].ts;
    }
    let any = tags.filter(t => t.ts > 0);
    if (any.length) return any[any.length - 1].ts;
    // Fallback cho tên ST.AI/legacy có timestamp ở cuối.
    let clean = s.replace(/\s*-?\s*By Strange TTSAgency\.vn\s*$/i, '').trim();
    let legacy = clean.match(/(?:^|\s)(\d{1,2})\/(\d{1,2})\s+(\d{1,2}):(\d{2})\s*$/);
    return legacy ? strangettsParseNameDateToMs(legacy[1], legacy[2], legacy[3], legacy[4]) : 0;
}

