function strangettsFormatThousandDots(val) {
    let s = String(val == null ? '' : val).trim();
    if (!s) return '';
    let hasCurrency = /vnd/i.test(s);
    let m = s.match(/-?[\d.,]+/);
    if (!m) return s;
    let num = m[0].replace(/[^\d-]/g, '');
    if (!num || num === '-') return s;
    let neg = num.startsWith('-');
    if (neg) num = num.slice(1);
    let out = num.replace(/\B(?=(\d{3})+(?!\d))/g, '.');
    if (neg) out = '-' + out;
    return hasCurrency ? out + ' VND' : out;
}

