function strangettsToNumberLoose(val) {
    if (val == null) return 0;
    if (typeof val === 'number') return val;
    let s = String(val).trim();
    if (!s) return 0;
    s = s.replace(/[^\d.,-]/g, '');
    if (!s) return 0;
    s = s.replace(/[.,](?=.*[.,])/g, '');
    let n = Number(s.replace(/,/g, ''));
    return Number.isFinite(n) ? n : 0;
}



function strangettsFindByKeys(obj, keys) {
    const wanted = new Set((keys || []).map(k => String(k).toLowerCase()));
    let found = '';
    function walk(x) {
        if (found || !x || typeof x !== 'object') return;
        if (Array.isArray(x)) {
            for (const item of x) walk(item);
            return;
        }
        for (const [k, v] of Object.entries(x)) {
            if (wanted.has(String(k).toLowerCase()) && v != null && String(v).trim()) {
                found = String(v).trim();
                return;
            }
        }
        for (const v of Object.values(x)) {
            if (v && typeof v === 'object') walk(v);
            if (found) return;
        }
    }
    walk(obj);
    return found;
}

// Tìm theo thứ tự ưu tiên: thử từng key một, key đầu tiên khớp thì dùng
function strangettsFindByKeysPriority(obj, keys) {
    for (const key of keys) {
        const val = strangettsFindByKeys(obj, [key]);
        if (val !== '') return val; // "0" là giá trị hợp lệ, không bỏ qua
    }
    return '';
}

function strangettsCollectCandidateIds(obj) {
    const out = [];
    const seen = new Set();
    function add(v) {
        const s = String(v || '').trim();
        if (/^\d{15,22}$/.test(s) && !seen.has(s)) {
            seen.add(s);
            out.push(s);
        }
    }
    function walk(x, keyHint = '') {
        if (x == null) return;
        if (typeof x === 'string' || typeof x === 'number') {
            if (/campaign|plan|id/i.test(keyHint) || /^\d{15,22}$/.test(String(x).trim())) add(x);
            return;
        }
        if (Array.isArray(x)) return x.forEach(i => walk(i, keyHint));
        if (typeof x === 'object') {
            for (const [k, v] of Object.entries(x)) walk(v, k);
        }
    }
    walk(obj);
    return out;
}

function strangettsExtractCampaignId(item) {
    const direct = strangettsFindByKeys(item, ['campaign_id', 'campaignId', 'campaignid', 'id', 'plan_id', 'ad_plan_id', 'campaign_plan_id']);
    if (/^\d{15,22}$/.test(String(direct || '').trim())) return String(direct).trim();
    const exclude = new Set([
        strangettsFindByKeys(item, ['aadvid']),
        strangettsFindByKeys(item, ['seller_id']),
        strangettsFindByKeys(item, ['oec_seller_id'])
    ].filter(Boolean));
    const candidates = strangettsCollectCandidateIds(item).filter(x => !exclude.has(x));
    return candidates[0] || '';
}

const STRANGETTS_EDIT_URL_TEMPLATE = 'https://seller-vn.tiktok.com/ads-creation/creation/edit?origin=SC_ads_tab_button_PC&btm_pre_unit_params=%7B%22btm_origin%22%3A%22sidebar_menu_Ads+Creation-SEA-REST%22%7D&shop_region=VN&type=product&mpa=1&campaign_id=';
function strangettsBuildEditUrl(campaignId) {
    const clean = String(campaignId || '').replace(/[^\d]/g, '');
    return clean ? (STRANGETTS_EDIT_URL_TEMPLATE + clean) : '';
}

// Format số tiền rút gọn kiểu Việt: 1tr, 1tr5, 500K, 300
function strangettsShortVN(num) {
    if (!num || num <= 0) return '-';
    if (num >= 1000000) {
        let tr = Math.floor(num / 1000000);
        let remainder = Math.round((num % 1000000) / 100000);
        return remainder > 0 ? tr + 'tr' + remainder : tr + 'tr';
    }
    if (num >= 1000) return Math.round(num / 1000) + 'K';
    return Math.round(num).toString();
}
function strangettsFullVN(num) {
    if (!num || num <= 0) return '0';
    return Math.round(num).toLocaleString('vi-VN');
}

// Format minutes: <= 120 phút hiển thị phút, > 120 hiển thị giờ+phút, > 48h hiển thị ngày
function strangettsFormatMinutes(mins) {
    if (mins == null || mins < 0) return '—';
    mins = Math.floor(mins);
    if (mins < 120) return mins + 'p';
    let h = Math.floor(mins / 60);
    let m = mins % 60;
    if (h >= 48) {
        let d = Math.floor(h / 24);
        let rh = h % 24;
        return rh > 0 ? d + 'n' + rh + 'h' : d + ' ngày';
    }
    return m > 0 ? h + 'h' + m + 'p' : h + 'h';
}

function injectPageSniffer() {
    if (document.getElementById('strangetts-page-sniffer')) return;
    const s = document.createElement('script');
    s.id = 'strangetts-page-sniffer';
    s.src = chrome.runtime.getURL('src/page_sniffer.js');
    s.onload = () => s.remove();
    (document.documentElement || document.head || document.body).appendChild(s);
}

