                shopping_inventory_type: adInfo.shopping_inventory_type || 1,
                flow_control_mode: adInfo.flow_control_mode || 1,
                product_video_selection_type: adInfo.product_video_selection_type || 1,
                cpa_skip_first_phrase: adInfo.cpa_skip_first_phrase || 1,
                compensation_activity_type: adInfo.compensation_activity_type || 3,
