                floatLogo.addEventListener('mouseleave', () => { floatLogo.style.transform = 'scale(1)'; floatLogo.style.opacity = '0.85'; floatLogo.style.boxShadow = '0 2px 12px rgba(138,141,145,0.5)'; });
