    setTimeout(() => {
        if (window.__STRANGETTS_BALANCE__) strangettsUpdateBalanceDisplay(window.__STRANGETTS_BALANCE__);
    }, 2000);

    // Tab Switcher
    function strangettsFlashMountPanel(target = 'home') {
        const panel = document.getElementById('tt-flash-container');
        if (!panel) return false;
        const host = target === 'live'
            ? document.getElementById('tt-live-flash-slot')
            : document.getElementById('tt-flash-home');
        if (!host) return false;
        if (panel.parentElement !== host) host.appendChild(panel);
        panel.dataset.mount = target;
        panel.style.display = 'block';
        return true;
    }

    function strangettsFlashActivateLiveMode() {
        const kindEl = document.getElementById('tt-flash-kind');
        if (kindEl && kindEl.value !== 'live') {
            kindEl.value = 'live';
            kindEl.dispatchEvent(new Event('change', { bubbles: true }));
        }
        const modeEl = document.getElementById('tt-flash-auto-mode');
        if (modeEl && !modeEl.value) modeEl.value = 'top';
        try { strangettsFlashUpdateAutoUi(); } catch (e) { }
    }

    function switchTab(active) {
        if (active === 'flash') strangettsFlashMountPanel('home');
        ['products', 'flash', 'campaigns', 'content', 'live'].forEach(t => {
            let tab = document.getElementById('tab-' + t);
            let con = document.getElementById('tt-' + t + '-container');
            if (!tab || !con) return;
            if (t === active) {
                tab.style.borderBottom = '2px solid #0D9488';
                tab.style.color = 'white';
                con.style.display = 'block';
            } else {
                tab.style.borderBottom = 'none';
                tab.style.color = 'rgba(255,255,255,0.5)';
                if (t === 'flash' && active === 'live' && con.dataset.mount === 'live') {
                    con.style.display = 'block';
                    return;
                }
                con.style.display = 'none';
            }
        });
    }

    function strangettsReloadAdsByScanButton(opts = {}) {
        const btn = document.getElementById('tt-btn-scan-ads');
        if (!btn) return false;
        const startedAt = Number(window.__STRANGETTS_ADS_SCAN_STARTED_AT__ || 0);
        if (window.__STRANGETTS_ADS_SCAN_RUNNING__ && startedAt && Date.now() - startedAt > 180000) {
            console.warn('[STRANGE TTS] Ads scan stale lock cleared');
            window.__STRANGETTS_ADS_SCAN_RUNNING__ = false;
            window.__STRANGETTS_ADS_SCAN_STARTED_AT__ = 0;
            btn.disabled = false;
        }
        if (window.__STRANGETTS_ADS_SCAN_RUNNING__) return false;
        if (btn.disabled) btn.disabled = false;
        window.__STRANGETTS_SKIP_SCAN_TAB_SWITCH__ = true;
        window.__STRANGETTS_RETURN_TAB_AFTER_SCAN__ = opts.returnTab || '';
        console.log('[STRANGE TTS] ADS tab clicked — auto scan campaigns');
        btn.click();
        return true;
    }

