// ==========================================
// LIVE SCORE ENGINE — 4-Layer Scoring (0-100)
// ==========================================
function strangettsLiveScore(camp, liveData, cfg) {
    let spend = parseFloat(String(camp.spend || '0').replace(/\./g, '').replace(/,/g, '')) || 0;
    let budget = parseFloat(String(camp.budget || '0').replace(/\./g, '').replace(/,/g, '')) || 0;
    let roi = parseFloat(String(camp.roi || '0').replace(/,/g, '.')) || 0;
    let targetRoi = parseFloat(String(camp.targetRoi || cfg.target_roi || '4').replace(/,/g, '.')) || 4;
    let orders = parseInt(String(camp.orders || '0').replace(/\D/g, '')) || 0;
    let gmv = parseFloat(String(camp.gmv || '0').replace(/\./g, '').replace(/,/g, '')) || 0;

    let enterRate = liveData?.enterRate || 0;
    let avgViewDuration = liveData?.avgViewDuration || 0;
    let orderRate = liveData?.orderRate || 0;
    let gpm = liveData?.gpm || 0;
    let spendRate = budget > 0 ? (spend / budget) * 100 : 0;

    // --- Layer 1: Ads Health (0-100) = 70% ROI + 30% spend utilization ---
    let roiRaw = Math.min(100, (roi / targetRoi) * 100);
    let spendUtil = spendRate >= 80 ? 100 : spendRate >= 50 ? 50 + (spendRate - 50) / 30 * 50 : spendRate >= 20 ? (spendRate - 20) / 30 * 50 : 0;
    let adsScore = Math.min(100, Math.round(roiRaw * 0.7 + spendUtil * 0.3));

    // --- Layer 2: Conversion (0-100) = 67% order_rate + 33% orders floor ---
    let rateScore = orderRate >= 3 ? 100 : orderRate >= 2 ? 70 + (orderRate - 2) * 30 : orderRate >= 1 ? 30 + (orderRate - 1) * 40 : orderRate > 0 ? orderRate * 30 : 0;
    if (orderRate <= 0 && orders > 0) rateScore = Math.min(100, orders * 15);
    let ordersFloor = orders >= 5 ? 100 : orders >= 3 ? 60 + (orders - 3) * 20 : orders >= 1 ? orders * 30 : 0;
    let convScore = Math.round(rateScore * 0.67 + ordersFloor * 0.33);

    // --- Layer 3: Live Quality (0-100) ---
    let enterScore = enterRate >= 5 ? 100 : enterRate >= 3 ? 60 + (enterRate - 3) * 20 : enterRate >= 1 ? 20 + (enterRate - 1) * 20 : enterRate * 20;
    let durationScore = avgViewDuration >= 60 ? 100 : avgViewDuration >= 30 ? 60 + (avgViewDuration - 30) / 30 * 40 : avgViewDuration >= 10 ? 20 + (avgViewDuration - 10) / 20 * 40 : avgViewDuration / 10 * 20;
    let gpmScore = gpm >= 30000 ? 100 : gpm >= 15000 ? 50 + (gpm - 15000) / 15000 * 50 : gpm >= 5000 ? 20 + (gpm - 5000) / 10000 * 30 : gpm / 5000 * 20;
    let qualityScore = Math.round(enterScore * 0.4 + durationScore * 0.35 + gpmScore * 0.25);
    let hasLiveData = enterRate > 0 || avgViewDuration > 0 || gpm > 0;
    if (!hasLiveData) qualityScore = 50;

    // --- Layer 4: Merch & Risk (0-100) ---
    let pinSKU = liveData?.pinSKU || null;
    let promoActive = liveData?.promoActive || false;
    let hasViolation = liveData?.hasViolation || false;
    let merchScore = 50; // neutral default
    let hasMerchData = pinSKU || promoActive || hasViolation;
    if (hasMerchData) {
        let pinScore = 50; // neutral khi không có data
        if (pinSKU) {
            let pinCTR = pinSKU.ctr || 0;
            let pinOrders = pinSKU.orders || 0;
            pinScore = Math.min(100, pinCTR >= 5 ? 80 + pinOrders * 5 : pinCTR >= 2 ? 40 + pinCTR * 10 : pinCTR * 20);
        }
        let promoScore = promoActive ? 70 : 30; // promo đang chạy = bonus
        let violationPenalty = hasViolation ? 0 : 100;
        merchScore = Math.round(pinScore * 0.4 + promoScore * 0.2 + violationPenalty * 0.4);
    }

    // --- Total Score (4-layer, adapt weights to available data) ---
    let w1 = cfg.score_ads_weight || 35, w2 = cfg.score_conv_weight || 25;
    let w3 = cfg.score_quality_weight || 25, w4 = cfg.score_merch_weight || 15;
    // If no live data, redistribute Live/Merch weight to Ads+Conv
    if (!hasLiveData && !hasMerchData) {
        w1 = 60; w2 = 40; w3 = 0; w4 = 0;
    } else if (!hasLiveData) {
        w1 = 45; w2 = 35; w3 = 0; w4 = 20;
    } else if (!hasMerchData) {
        w1 = 40; w2 = 25; w3 = 35; w4 = 0;
    }
    let totalScore = Math.round((adsScore * w1 + convScore * w2 + qualityScore * w3 + merchScore * w4) / (w1 + w2 + w3 + w4));

    // --- Live Quality Gate ---
    let qualityGateBlocked = false;
    if (cfg.lq_gate_enabled && hasLiveData) {
        if (enterRate > 0 && enterRate < cfg.lq_enter_rate_min && avgViewDuration > 0 && avgViewDuration < cfg.lq_view_duration_min) {
            qualityGateBlocked = true;
        }
    }
    // Violation gate: auto-hold if violation detected
    if (hasViolation && cfg.emergency_stop_on_violation) qualityGateBlocked = true;

    // --- Decision with GUARDRAILS ---
    let action, actionText, emoji, color, guardrailReason = '';
    if (qualityGateBlocked) {
        action = 'hold'; actionText = hasViolation ? 'GIỮ — Vi phạm detected' : 'GIỮ — Live yếu, không scale'; emoji = '🚫'; color = '#F87171';
    } else if (totalScore >= (cfg.score_strong_threshold || 80)) {
        if (spendRate >= 70 && orders >= 2) {
            action = 'scale_strong'; actionText = `TĂNG mạnh +${strangettsShortVN(cfg.score_budget_add_strong || 100000)}`; emoji = '💎'; color = '#22D3EE';
        } else {
            action = 'hold'; emoji = '🟡'; color = '#FBBF24';
            guardrailReason = spendRate < 70 ? `Spend ${Math.round(spendRate)}% (cần ≥70%)` : `${orders} đơn (cần ≥2)`;
            actionText = `Score đẹp nhưng chưa đủ ĐK scale mạnh`;
        }
    } else if (totalScore >= (cfg.score_scale_threshold || 60)) {
        if (spendRate >= 40 && orders >= 1) {
            action = 'scale_light'; actionText = `TĂNG nhẹ +${strangettsShortVN(cfg.score_budget_add_light || 50000)}`; emoji = '🚀'; color = '#4ADE80';
        } else {
            action = 'hold'; emoji = '🟡'; color = '#FBBF24';
            guardrailReason = spendRate < 40 ? `Spend ${Math.round(spendRate)}% (cần ≥40%)` : `Chưa có đơn`;
            actionText = `Score ổn nhưng chưa đủ ĐK scale`;
        }
    } else if (totalScore >= 40) {
        action = 'hold'; actionText = 'GIỮ nguyên'; emoji = '🟡'; color = '#FBBF24';
    } else {
        action = 'stop'; actionText = 'DỪNG / không tăng'; emoji = '🔴'; color = '#F87171';
    }

    let budgetAdd = 0;
    if (action === 'scale_strong') budgetAdd = cfg.score_budget_add_strong || 100000;
    else if (action === 'scale_light') budgetAdd = cfg.score_budget_add_light || 50000;

    return {
        totalScore, adsScore, convScore, qualityScore, merchScore, qualityGateBlocked, hasLiveData, hasMerchData,
        action, actionText, emoji, color, budgetAdd, guardrailReason,
        details: {
            roi, targetRoi, roiScore: Math.round(roiRaw), spendRate: Math.round(spendRate), spendUtil: Math.round(spendUtil),
            orderRate, orders, rateScore: Math.round(rateScore), ordersFloor: Math.round(ordersFloor),
            enterRate, avgViewDuration, gpm,
            enterScore: Math.round(enterScore), durationScore: Math.round(durationScore), gpmScore: Math.round(gpmScore),
            hasViolation, promoActive,
        }
    };
}

// ==========================================
// STRATEGY V3 — Rolling Metrics Updater
// Pure function: push snapshot, cắt theo thời gian thật (20 phút)
// Gọi 1 lần/tick với PRIMARY camp duy nhất
// ==========================================
function strangettsUpdateRollingMetrics(strategy, camp, dash, now) {
    const snap = {
        ts:        now,
        roi:       parseFloat(String(camp.roi   || '0').replace(/,/g, '.')) || 0,
        spend:     parseFloat(String(camp.spend || '0').replace(/\./g,'').replace(/,/g,'')) || 0,
        gmv:       parseFloat(String(camp.gmv   || '0').replace(/\./g,'').replace(/,/g,'')) || 0,
        gpm:       dash?.gpm || 0,
        enterRate: dash?.enterRate || 0,
        orderRate: dash?.orderRate || 0,
    };
    strategy.tick_history.push(snap);

    // Cắt theo THỜI GIAN THẬT — giữ 20 phút gần nhất
    const KEEP_MS = 20 * 60 * 1000;
    strategy.tick_history = strategy.tick_history.filter(s => now - s.ts <= KEEP_MS);

    // rolling_roi_15m — trung bình ROI 15 phút gần nhất
    const W15 = 15 * 60 * 1000;
    const r15 = strategy.tick_history.filter(s => now - s.ts <= W15);
    strategy.rolling_roi_15m = r15.length >= 2
        ? r15.reduce((a, s) => a + s.roi, 0) / r15.length
        : snap.roi;

    // rolling_spend_10m = chênh lệch spend trong 10 phút gần nhất
    const W10 = 10 * 60 * 1000;
    const oldest10 = strategy.tick_history.find(s => now - s.ts <= W10);
    strategy.rolling_spend_10m = oldest10 ? Math.max(0, snap.spend - oldest10.spend) : 0;
    strategy.spend_pace_per_min = strategy.rolling_spend_10m / 10;

    // rolling_gpm_10m — GPM trung bình 10 phút
    const g10 = strategy.tick_history.filter(s => now - s.ts <= W10);
    strategy.rolling_gpm_10m = g10.length > 0
        ? g10.reduce((a, s) => a + s.gpm, 0) / g10.length : 0;
}

// ==========================================
// STRATEGY V3 — P1 Traffic Heat Classifier
// Pure function: return HOT|NORMAL|SOFT_COLD|HARD_COLD|UNKNOWN
// spendOpenRate = (rolling_spend_10m / expected_spend_10m) × 100
//   với expected_spend_10m = (budget_cap / total_minutes) × 10
//   Ý nghĩa: camp tiêu được bao nhiêu % so với nhịp tuyến tính kỳ vọng?
// Không dùng GPM hoặc OrderRate — chỉ traffic signals
// ==========================================
function computeP1TrafficHeat(dash, spendOpenRate) {
    // Không có dash data → UNKNOWN, không block scale
    if (!dash || (dash.enterRate === 0 && dash.avgViewDuration === 0)) return 'UNKNOWN';

    const hasEnterData = dash.enterRate > 0;
    const hasDurData   = dash.avgViewDuration > 0;

    // HARD_COLD: CẦN CẢ HAI điều kiện xấu VÀ phải có data thật (không phải 0 default)
    if (hasEnterData && hasDurData) {
        if (dash.enterRate < 0.5 && dash.avgViewDuration < 15) return 'HARD_COLD';
    }

    // Điểm heat từ traffic signals thuần túy
    const enter_s = !hasEnterData ? 50
        : dash.enterRate >= 3 ? 100
        : dash.enterRate >= 1 ? 60
        : 30;

    const dur_s = !hasDurData ? 50
        : dash.avgViewDuration >= 45 ? 100
        : dash.avgViewDuration >= 20 ? 60
        : 30;

    const spend_s = spendOpenRate >= 80 ? 100
        : spendOpenRate >= 50 ? 65
        : spendOpenRate >= 20 ? 40
        : 20;

    // Trọng số: enter 40%, duration 35%, spend 15%, viewer neutral 10%
    const heat = enter_s * 0.40 + dur_s * 0.35 + spend_s * 0.15 + 50 * 0.10;
    return heat >= 70 ? 'HOT' : heat >= 45 ? 'NORMAL' : 'SOFT_COLD';
}

// ==========================================
// GEMINI DATA LOG — Lưu toàn bộ data gửi/nhận Gemini
// ==========================================
window.__STRANGETTS_GEMINI_LOG__ = window.__STRANGETTS_GEMINI_LOG__ || [];

const STRANGETTS_GEMINI_DEFAULT_MODEL = 'gemini-3.1-flash-lite';
const STRANGETTS_GEMINI_FALLBACK_MODELS = ['gemini-3.1-flash-lite-preview', 'gemini-2.5-flash-lite', 'gemini-3-flash-preview', 'gemini-2.5-flash'];
const STRANGETTS_GEMINI_MODEL_LABELS = {
    'gemini-3.1-flash-lite': 'Gemini 3.1 Flash Lite',
    'gemini-3.1-flash-lite-preview': 'Gemini 3.1 Flash Lite Preview',
    'gemini-3-flash-preview': 'Gemini 3 Flash Preview',
    'gemini-2.5-flash-lite': 'Gemini 2.5 Flash Lite',
    'gemini-2.5-flash': 'Gemini 2.5 Flash',
};

function strangettsGeminiCleanModel(model) {
    return String(model || '').trim().replace(/^models\//, '');
}

function strangettsGeminiModelLabel(model) {
    let clean = strangettsGeminiCleanModel(model);
    return STRANGETTS_GEMINI_MODEL_LABELS[clean] || clean || STRANGETTS_GEMINI_MODEL_LABELS[STRANGETTS_GEMINI_DEFAULT_MODEL];
}

function strangettsGeminiModelCandidates(cfg) {
    let out = [];
    let add = model => {
        let clean = strangettsGeminiCleanModel(model);
        if (clean && !out.includes(clean)) out.push(clean);
    };
    add(cfg?.gemini_model || STRANGETTS_GEMINI_DEFAULT_MODEL);
    String(cfg?.gemini_fallback_models || '').split(/[,\n]/).forEach(add);
    STRANGETTS_GEMINI_FALLBACK_MODELS.forEach(add);
    return out.slice(0, 5);
}

function strangettsGeminiRetryAfterSec(text) {
    let m = String(text || '').match(/retry in\s+([\d.]+)s/i);
    return m ? Math.ceil(parseFloat(m[1]) || 0) : 0;
}

function strangettsGeminiCanFallback(status, json) {
    let msg = String(json?.error?.message || '').toLowerCase();
    if (status === 429 || status === 404) return true;
    if (status === 400 && (msg.includes('not found') || msg.includes('not supported') || msg.includes('model'))) return true;
    return false;
}

function strangettsNormalizeGeminiParsedResult(parsed) {
    if (!parsed) return [];
    if (Array.isArray(parsed)) return parsed.filter(x => x && typeof x === 'object');
    if (typeof parsed === 'object') {
        for (let key of ['items', 'results', 'analysis', 'recommendations', 'data']) {
            if (Array.isArray(parsed[key])) return parsed[key].filter(x => x && typeof x === 'object');
        }
        if (parsed.name || parsed.summary || parsed.risk || parsed.suggestion) return [parsed];
        let flattened = [];
        for (let key of ['overview', 'campaigns', 'script', 'actions']) {
            let val = parsed[key];
            if (Array.isArray(val)) flattened.push(...val.filter(x => x && typeof x === 'object'));
            else if (val && typeof val === 'object') flattened.push(val);
        }
        return flattened;
    }
    return [];
}

function strangettsParseGeminiJsonArray(text) {
    let raw = String(text || '').trim();
    if (!raw) return [];
    raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
    const attempts = [];
    attempts.push(raw);
    let firstBracket = raw.indexOf('[');
    let lastBracket = raw.lastIndexOf(']');
    if (firstBracket >= 0 && lastBracket > firstBracket) attempts.push(raw.substring(firstBracket, lastBracket + 1));
    let firstBrace = raw.indexOf('{');
    let lastBrace = raw.lastIndexOf('}');
    if (firstBrace >= 0 && lastBrace > firstBrace) attempts.push(raw.substring(firstBrace, lastBrace + 1));
    for (let candidate of attempts) {
        try {
            let normalized = strangettsNormalizeGeminiParsedResult(JSON.parse(candidate));
            if (normalized.length) return normalized;
        } catch (e) { }
    }
    return [];
}

function strangettsGeminiNum(value, fallback = 0) {
    let n = Number(value);
    return Number.isFinite(n) ? n : fallback;
}

function strangettsGeminiShortText(value, max = 180) {
    let text = String(value ?? '').replace(/\s+/g, ' ').trim();
    return text.length > max ? text.slice(0, max - 1).trim() + '…' : text;
}

function strangettsGeminiRatePct(value, fallback = 0) {
    let n = Number(value);
    if (!Number.isFinite(n)) return fallback;
    return n > 0 && n <= 1 ? n * 100 : n;
}

function strangettsGeminiBuildLiveMetrics(liveData) {
    if (!liveData) return null;
    let gmv = strangettsGeminiNum(liveData.gmv);
    let adsCost = strangettsGeminiNum(liveData.adsCost);
    return {
        data_source: liveData.dataSource || 'live_dashboard',
        room_id: liveData.roomId || '',
        live_duration_sec: strangettsGeminiNum(liveData.liveDurationSec),
        gmv,
        gmv_per_hour: strangettsGeminiNum(liveData.gmvPerHour),
        ads_cost: adsCost,
        roi_live: adsCost > 0 ? Number((gmv / adsCost).toFixed(2)) : 0,
        current_viewers: strangettsGeminiNum(liveData.currentViewers || liveData.viewers),
        viewers: strangettsGeminiNum(liveData.viewers),
        impressions: strangettsGeminiNum(liveData.impressions),
        views: strangettsGeminiNum(liveData.views),
        impressions_per_hour: strangettsGeminiNum(liveData.impressionsPerHour),
        gpm_show: strangettsGeminiNum(liveData.gpm),
        enter_rate_preview: strangettsGeminiRatePct(liveData.enterRatePreview),
        enter_rate: strangettsGeminiRatePct(liveData.enterRate),
        ctr_live: strangettsGeminiRatePct(liveData.ctr),
        avg_view_duration: strangettsGeminiNum(liveData.avgViewDuration),
        order_rate: strangettsGeminiRatePct(liveData.orderRate),
        total_orders: strangettsGeminiNum(liveData.totalOrders),
        comment_rate: strangettsGeminiRatePct(liveData.commentRate),
        follow_rate: strangettsGeminiRatePct(liveData.followRate),
        share_rate: strangettsGeminiRatePct(liveData.shareRate),
        like_rate: strangettsGeminiRatePct(liveData.likeRate),
        watch_over_1_min: strangettsGeminiNum(liveData.watchOver1Min),
    };
}

function strangettsGeminiBuildProductInsights(products, pinnedProductId) {
    let list = Array.isArray(products) ? products : [];
    let pinned = String(pinnedProductId || '');
    return list.map(p => {
        let id = String(p.id || p.product_id || p.productId || '');
        let sold = (parseInt(p.direct_sales, 10) || 0) + (parseInt(p.sales, 10) || 0);
        let clicks = parseInt(p.exposure_cnt || p.click_cnt || p.clicks || 0, 10) || 0;
        let ctr = strangettsGeminiRatePct(p.click_through_rate);
        let cart = parseInt(p.add_shop_cart_cnt || p.cart_cnt || 0, 10) || 0;
        let gmv = strangettsGeminiNum(p.gmv || p.direct_gmv || p.direct_gmv_local?.amount);
        let stock = parseInt(p.stock_cnt || p.available_cnt || 0, 10) || 0;
        return {
            id,
            name: strangettsGeminiShortText(p.name || p.title || id, 70),
            pinned: !!(pinned && id === pinned),
            clicks,
            ctr: Number(ctr.toFixed ? ctr.toFixed(2) : ctr) || 0,
            add_to_cart: cart,
            sold,
            gmv,
            stock,
        };
    }).filter(p => p.id || p.name)
        .sort((a, b) => {
            if (a.pinned !== b.pinned) return a.pinned ? -1 : 1;
            let as = a.sold * 1000000 + a.gmv + a.clicks * 1000 + a.add_to_cart * 500;
            let bs = b.sold * 1000000 + b.gmv + b.clicks * 1000 + b.add_to_cart * 500;
            return bs - as;
        })
        .slice(0, 3);
}

function strangettsGeminiBuildTrafficInsights(data) {
    if (!data) return [];
    let srcArr = data.source_data || data.stats_data || data.sources || [];
    let sources = [];
    if (Array.isArray(srcArr)) {
        srcArr.forEach(s => {
            let name = s.source_name || s.name || s.dimension_data?.name || s.dimension_data?.source_name || '';
            let pct = strangettsGeminiRatePct(s.percentage ?? s.watch_pv_pct ?? s.pct ?? 0);
            if (name) sources.push({ name: strangettsGeminiShortText(name, 50), pct: Number(pct.toFixed ? pct.toFixed(1) : pct) || 0 });
        });
    }
    return sources.sort((a, b) => b.pct - a.pct).slice(0, 5);
}

function strangettsGeminiNormalizeItem(item, fallbackName = 'Nhận xét') {
    let confidence = String(item?.confidence || '').toLowerCase();
    if (!['low', 'medium', 'high'].includes(confidence)) confidence = 'medium';
    return {
        name: strangettsGeminiShortText(item?.name || fallbackName, 80),
        summary: strangettsGeminiShortText(item?.summary || '', 220),
        risk: strangettsGeminiShortText(item?.risk || '', 220),
        suggestion: strangettsGeminiShortText(item?.suggestion || '', 240),
        confidence
    };
}

function strangettsGeminiEnsureMinimumItems(items, activeCamps, liveMetrics, engineCtx, sessionInfo) {
    let normalized = (items || [])
        .filter(x => x && typeof x === 'object')
        .map((x, idx) => strangettsGeminiNormalizeItem(x, idx === 0 ? 'Tổng quan' : 'Nhận xét'))
        .filter(x => x.name || x.summary || x.suggestion);
    const hasName = pattern => normalized.some(x => pattern.test(x.name || ''));
    const firstCamp = (activeCamps || [])[0] || {};
    const phase = sessionInfo?.session_phase || '';
    const actualPct = String(firstCamp.actual_vs_target || '').replace(/[^\d.]/g, '');
    const actualNum = Number(actualPct) || 0;
    const spendRate = Number(firstCamp.spend_rate || 0);
    const roi = Number(firstCamp.roi || 0);
    const targetRoi = Number(firstCamp.target_roi || 0);
    const gpm = Number(liveMetrics?.gpm_show || liveMetrics?.gpm || 0);
    const enter = Number(liveMetrics?.enter_rate || 0);
    const avgView = Number(liveMetrics?.avg_view_duration || 0);
    const engineReason = engineCtx?.guardrailReason || '';

    if (!hasName(/tổng quan/i)) {
        normalized.unshift(strangettsGeminiNormalizeItem({
            name: 'Tổng quan',
            summary: `Phiên ${phase || 'đang live'} đạt ${actualNum ? actualNum + '% mục tiêu' : 'đang thu thập tiến độ'}, ROI ${roi ? roi.toFixed(2) : '—'} với GPM ${strangettsFormatVN(gpm)}.`,
            risk: actualNum > 0 && actualNum < 70 ? 'Tiến độ doanh thu còn thấp, cần tăng tốc trong 5-15 phút tới.' : '',
            suggestion: 'Ưu tiên giữ người xem, nhắc ưu đãi chính và kích hoạt CTA chốt đơn liên tục.',
            confidence: 'medium'
        }, 'Tổng quan'));
    }

    if (firstCamp.name && !hasName(/^camp/i)) {
        normalized.push(strangettsGeminiNormalizeItem({
            name: `Camp ${String(firstCamp.name).slice(0, 42)}`,
            summary: `Camp tiêu ${spendRate}% ngân sách, ROI ${roi ? roi.toFixed(2) : '—'} so với mục tiêu ${targetRoi || '—'}.`,
            risk: engineReason || (spendRate < 40 ? 'Spend còn thấp nên chưa nên kết luận scale mạnh.' : ''),
            suggestion: roi >= targetRoi && spendRate < 40 ? 'Giữ ROI hiện tại, theo dõi thêm một nhịp rồi mới tăng ngân sách.' : 'Theo dõi chi phí và đơn mới trước khi nới ngân sách.',
            confidence: 'medium'
        }, 'Camp'));
    }

    if (!hasName(/kịch bản/i)) {
        let weakPoint = avgView < 25 ? 'giữ chân người xem' : enter < 5 ? 'kéo người vào phòng' : 'chốt đơn';
        normalized.push(strangettsGeminiNormalizeItem({
            name: 'Kịch bản',
            summary: `Live đang có vào phòng ${enter.toFixed(1)}%, xem trung bình ${avgView.toFixed(0)}s.`,
            risk: avgView < 25 ? 'Thời gian xem ngắn có thể làm traffic không mở rộng ổn định.' : '',
            suggestion: `Trong 5-15 phút tới, streamer tập trung ${weakPoint}: nhắc lợi ích sản phẩm, giá/ưu đãi và kêu gọi đặt hàng ngay.`,
            confidence: 'medium'
        }, 'Kịch bản'));
    }

    return normalized.slice(0, 5);
}


// ==========================================
// GEMINI 2.5 FLASH — AI Phân tích & Giải thích
// ==========================================
async function strangettsGeminiAnalyze(camps, liveData, cfg, engineState, callSource, extraContext = {}) {
    if (!cfg.gemini_enabled || !cfg.gemini_api_key) return null;
	let logEntry = {
	    ts: Date.now(), prompt: '',
	    inputData: { campaigns: [], liveMetrics: null, products: [], engineState: null },
	    responseText: '', parsedResult: null, error: null,
	    modelUsed: '', modelTried: [],
	    durationMs: 0, status: 'pending',
	    callSource: callSource || 'scheduled_review'
	};
    let startMs = Date.now();
    try {
        camps = Array.isArray(camps) ? camps : [];
        let metricsArr = camps.map(c => {
            let spend = parseFloat(String(c.spend || '0').replace(/\./g, '').replace(/,/g, '')) || 0;
            let budget = parseFloat(String(c.budget || '0').replace(/\./g, '').replace(/,/g, '')) || 0;
            let roi = parseFloat(String(c.roi || '0').replace(/,/g, '.')) || 0;
            let gmv = parseFloat(String(c.gmv || '0').replace(/\./g, '').replace(/,/g, '')) || 0;
            let orders = parseInt(String(c.orders || '0').replace(/\D/g, '')) || 0;
            let status = c.status || '';
            let projectedRevenue = Math.round(budget * roi); // Doanh thu dự kiến = NS × ROI
            let targetRevenue = Math.round(budget * (parseFloat(String(c.targetRoi || '4').replace(/,/g, '.')) || 4)); // DT mục tiêu = NS × target ROI
            return {
                name: c.name || c.id, spend, budget, roi, gmv, orders, status,
                spend_rate: budget > 0 ? Math.round(spend / budget * 100) : 0,
                target_roi: parseFloat(String(c.targetRoi || '4').replace(/,/g, '.')) || 4,
                target_revenue: targetRevenue,
                projected_revenue: projectedRevenue,
                actual_vs_target: targetRevenue > 0 ? Math.round(gmv / targetRevenue * 100) + '%' : 'N/A',
            };
        });
        // Chỉ gửi camps có data (spend > 0 hoặc đang chạy), tối đa 10
        let activeCamps = metricsArr.filter(c => c.spend > 0 || (c.status && c.status.includes('delivery_ok')));
        if (activeCamps.length === 0) activeCamps = metricsArr.slice(0, 5); // fallback: gửi 5 camps đầu
        else activeCamps = activeCamps.slice(0, 10);
        let liveMetrics = strangettsGeminiBuildLiveMetrics(liveData);
        let productInsights = strangettsGeminiBuildProductInsights(extraContext.products, extraContext.pinnedProductId);
        let trafficInsights = strangettsGeminiBuildTrafficInsights(extraContext.trafficSources);
        let operationsCtx = {
            selected_campaign_count: Array.isArray(extraContext.selectedCampIds) ? extraContext.selectedCampIds.length : undefined,
            auto_pin: !!extraContext.autoPin,
            auto_chat: !!extraContext.autoChat,
            auto_giveaway: !!extraContext.autoGiveaway,
            note: liveMetrics?.gmv > 0 && activeCamps.some(c => c.gmv <= 0)
                ? 'Ads camp có thể delay số liệu; ưu tiên đọc LIVE_ANALYTICS/room_id khi đưa lời khuyên realtime.'
                : ''
        };

        // Engine state context for AI
        let engineCtx = engineState || {};
        let engineBlock = '';
        if (engineCtx.score !== undefined) {
            engineBlock = `\n\nTrạng thái engine hiện tại:\n${JSON.stringify({
                score: engineCtx.score,
                quality_gate: engineCtx.qualityGateBlocked ? 'blocked' : 'pass',
                engine_action: engineCtx.action || 'unknown',
                trigger_reason: engineCtx.guardrailReason || ''
            }, null, 2)}`;
        }

        // Session context
        let budgetCap = cfg.max_budget_cap || 0;
        let minRoiTotal = cfg.min_roi_total || 0;
        let liveEndTime = window.__STRANGETTS_LIVE_END_TIME__ || '';
        let liveStartTime = window.__STRANGETTS_LIVE_START_TIME__ || '';
        let sessionBlock = '';
        let sessionInfo = null;
        let now = new Date();
        if (budgetCap > 0 || minRoiTotal > 0 || liveEndTime || liveStartTime) {
            sessionInfo = {};
            if (budgetCap > 0) sessionInfo.budget_cap = budgetCap + ' (NS tối đa/camp)';
            if (minRoiTotal > 0) sessionInfo.min_roi = minRoiTotal + ' (ROI tối thiểu)';
            if (liveStartTime && liveEndTime) {
                sessionInfo.live_start = liveStartTime;
                sessionInfo.live_end = liveEndTime;
                let [sh, sm] = liveStartTime.split(':').map(Number);
                let [eh, em] = liveEndTime.split(':').map(Number);
                let startDate = new Date(); startDate.setHours(sh, sm, 0, 0);
                let endDate = new Date(); endDate.setHours(eh, em, 0, 0);
                let totalMin = Math.max(1, Math.round((endDate - startDate) / 60000));
                let elapsedMin = Math.max(0, Math.round((now - startDate) / 60000));
                let remainMin = Math.max(0, totalMin - elapsedMin);
                sessionInfo.total_minutes = totalMin;
                sessionInfo.elapsed_minutes = elapsedMin;
                sessionInfo.remaining_minutes = remainMin;
                sessionInfo.progress = Math.round(elapsedMin / totalMin * 100) + '%';
                sessionInfo.session_phase = remainMin > 60 ? 'đầu phiên' : remainMin > 30 ? 'giữa phiên' : remainMin > 10 ? 'cuối phiên' : 'gần kết thúc';
                // DT dự kiến thực tế: GMV hiện tại / giờ đã live × tổng giờ
                let totalGmv = liveMetrics?.gmv || activeCamps.reduce((s, c) => s + (c.gmv || 0), 0);
                if (elapsedMin > 0 && totalGmv > 0) {
                    let gmvPerMin = totalGmv / elapsedMin;
                    let projectedActual = Math.round(gmvPerMin * totalMin);
                    sessionInfo.actual_gmv = totalGmv;
                    sessionInfo.projected_gmv_actual = projectedActual + ' (dự kiến đạt cuối phiên dựa trên tốc độ hiện tại)';
                }
            } else if (liveEndTime) {
                sessionInfo.live_end = liveEndTime;
                let [eh, em] = liveEndTime.split(':').map(Number);
                let endDate = new Date(); endDate.setHours(eh, em, 0, 0);
                sessionInfo.remaining_minutes = Math.max(0, Math.round((endDate - now) / 60000));
                sessionInfo.session_phase = sessionInfo.remaining_minutes > 60 ? 'đầu phiên' : sessionInfo.remaining_minutes > 30 ? 'giữa phiên' : sessionInfo.remaining_minutes > 10 ? 'cuối phiên' : 'gần kết thúc';
            }
            sessionBlock = `\n\n⏰ CONTEXT PHIÊN LIVE:\n${JSON.stringify(sessionInfo, null, 2)}`;
        }

        let phaseLabel = callSource === 'post-live' ? 'TỔNG KẾT SAU LIVE' : 'ĐÁNH GIÁ ĐANG LIVE';
        let productBlock = productInsights.length
            ? `\n\n📦 PRODUCTS TOP (${productInsights.length} sản phẩm ưu tiên):\n${JSON.stringify(productInsights, null, 2)}`
            : '';
        let trafficBlock = trafficInsights.length
            ? `\n\n🚪 TRAFFIC SOURCES:\n${JSON.stringify(trafficInsights, null, 2)}`
            : '';
        let operationsBlock = `\n\n🧭 OPERATING CONTEXT:\n${JSON.stringify(operationsCtx, null, 2)}`;
        let prompt = `Bạn là chuyên gia vận hành LIVE TikTok. Đọc data và đưa lời khuyên hành động ngắn gọn cho team.
Chế độ phân tích: ${phaseLabel}.

📊 ADS CAMPAIGNS (${activeCamps.length} camp được chọn/đang chạy):
${JSON.stringify(activeCamps, null, 2)}
• target_revenue = budget × target_ROI (doanh thu MỤC TIÊU)
• projected_revenue = budget × ROI thực tế
• actual_vs_target = gmv/target_revenue (% đạt so với mục tiêu)

${liveMetrics ? `📺 LIVE_ANALYTICS (ưu tiên cho quyết định realtime nếu ads delay):\n${JSON.stringify(liveMetrics, null, 2)}` : 'Chưa có data LIVE.'}${productBlock}${trafficBlock}${engineBlock}${sessionBlock}${operationsBlock}

		Trả JSON array THUẦN, bắt buộc 3-5 object:
		- "Tổng quan": 1 item tóm phiên live + tiến độ doanh thu
		- "Ads/Camp [tên]": 1 item cho người vận hành ads (ngân sách, ROI, chờ data hay cần can thiệp)
		- "Kịch bản host": 1 item nói rõ host cần làm gì trong 5-15 phút tới
		- "Sản phẩm/Ghim": 0-1 item nếu có PRODUCTS, nêu sản phẩm nên ghim/đẩy/chuyển

Mỗi item: {"name":"...", "summary":"1 câu ngắn", "risk":"1 câu hoặc rỗng", "suggestion":"HÀNH ĐỘNG cụ thể trong 5-15p", "confidence":"low|medium|high"}

QUY TẮC:
- Mỗi field TỐI ĐA 1-2 câu
- Nếu có session_phase: điều chỉnh lời khuyên theo giai đoạn (đầu=đẩy mạnh, giữa=tối ưu, cuối=chốt đơn gấp)
- Nếu actual_vs_target thấp: cảnh báo và gợi ý tăng tốc
- Nếu ADS CAMPAIGNS chưa có spend/gmv nhưng LIVE_ANALYTICS có GMV/đơn, nói rõ ads đang delay dữ liệu và dùng số live thật để khuyến nghị.
- Tách rõ hành động cho team ads và hành động cho host; không nói chung chung.
		- Tiếng Việt. CHỈ trả JSON array thuần, bắt đầu bằng [ và kết thúc bằng ]. Không bọc markdown, không dùng \`\`\`.
		- Không trả 1 item duy nhất; nếu chỉ có 1 camp vẫn phải có đủ Tổng quan, Camp, Kịch bản.`;

        // Capture input data + prompt vào log
        logEntry.prompt = prompt;
        logEntry.inputData = {
            campaigns: activeCamps,
            liveMetrics,
            products: productInsights,
            trafficSources: trafficInsights,
            operations: operationsCtx,
            engineState: engineCtx.score !== undefined ? { score: engineCtx.score || 0, quality_gate: engineCtx.qualityGateBlocked ? 'blocked' : 'pass', engine_action: engineCtx.action || 'unknown', trigger_reason: engineCtx.guardrailReason || '' } : null
        };

        let json = null, text = '', resStatus = 0, usedModel = '';
        let lastErrorPayload = null;
        let models = strangettsGeminiModelCandidates(cfg);
        for (let model of models) {
            let res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${encodeURIComponent(model)}:generateContent?key=${cfg.gemini_api_key}`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    contents: [{ role: 'user', parts: [{ text: prompt }] }],
                    generationConfig: { temperature: 0.25, maxOutputTokens: 4096, responseMimeType: 'application/json' }
                })
            });
            resStatus = res.status;
            try { json = await res.json(); } catch (e) { json = { error: { message: e.message || String(e) } }; }
            logEntry.modelTried.push(model);
            text = json?.candidates?.[0]?.content?.parts?.[0]?.text || '';
            if (res.ok && text) {
                usedModel = model;
                break;
            }
            let finishReason = json?.candidates?.[0]?.finishReason || '';
            let blockReason = json?.promptFeedback?.blockReason || '';
            lastErrorPayload = {
                model,
                http_status: resStatus,
                finish_reason: finishReason,
                block_reason: blockReason,
                retry_after_sec: strangettsGeminiRetryAfterSec(json?.error?.message),
                error: json?.error?.message || ''
            };
            if (!strangettsGeminiCanFallback(resStatus, json)) break;
        }
        logEntry.modelUsed = usedModel;
        if (!text) {
            logEntry.responseText = JSON.stringify(lastErrorPayload || {
                model: models[0] || '',
                http_status: resStatus,
                finish_reason: json?.candidates?.[0]?.finishReason || '',
                block_reason: json?.promptFeedback?.blockReason || '',
                error: json?.error?.message || ''
            }, null, 2);
        } else {
            logEntry.responseText = text;
        }
	        logEntry.durationMs = Date.now() - startMs;
	        let parsed = strangettsParseGeminiJsonArray(text);
	        if (parsed.length) {
	            parsed = strangettsGeminiEnsureMinimumItems(parsed, activeCamps, liveMetrics, engineCtx, sessionInfo);
	            parsed._modelUsed = logEntry.modelUsed;
	            parsed._modelTried = logEntry.modelTried;
	            logEntry.parsedResult = parsed;
	            logEntry.status = 'success';
            window.__STRANGETTS_GEMINI_LOG__.unshift(logEntry);
            if (window.__STRANGETTS_GEMINI_LOG__.length > 20) window.__STRANGETTS_GEMINI_LOG__.length = 20;
            document.dispatchEvent(new CustomEvent('strangetts-gemini-log-update'));
            return parsed;
	        }
	        logEntry.status = 'empty';
	        logEntry.error = text
	            ? `Không parse được JSON array từ Gemini response (${strangettsGeminiModelLabel(logEntry.modelUsed || logEntry.modelTried?.[0] || '')})`
	            : `Gemini không trả text; đã thử ${logEntry.modelTried.map(strangettsGeminiModelLabel).join(' → ') || 'model mặc định'}`;
        window.__STRANGETTS_GEMINI_LOG__.unshift(logEntry);
        if (window.__STRANGETTS_GEMINI_LOG__.length > 20) window.__STRANGETTS_GEMINI_LOG__.length = 20;
        document.dispatchEvent(new CustomEvent('strangetts-gemini-log-update'));
        return null;
    } catch (e) {
        logEntry.error = e.message || String(e);
        logEntry.status = 'error';
        logEntry.durationMs = Date.now() - startMs;
        window.__STRANGETTS_GEMINI_LOG__.unshift(logEntry);
        if (window.__STRANGETTS_GEMINI_LOG__.length > 20) window.__STRANGETTS_GEMINI_LOG__.length = 20;
        document.dispatchEvent(new CustomEvent('strangetts-gemini-log-update'));
        console.warn('[STRANGE TTS] Gemini API error:', e);
        return null;
    }
}

// ==========================================
// TELEGRAM BOT — Notifications + Confirm (via background proxy)
// ==========================================
// Helper: returns true if Telegram notification is explicitly enabled and configured
function isTelegramReady(cfg) {
    return !!(cfg && cfg.telegram_enabled && cfg.telegram_bot_token && cfg.telegram_chat_id);
}

function strangettsStripNotifyHtml(message) {
    return String(message || '')
        .replace(/<br\s*\/?>/gi, '\n')
        .replace(/<\/(p|div|li|tr|h[1-6])>/gi, '\n')
        .replace(/<[^>]*>/g, '')
        .replace(/&nbsp;/g, ' ')
        .replace(/&amp;/g, '&')
        .replace(/&lt;/g, '<')
        .replace(/&gt;/g, '>')
        .replace(/\n{3,}/g, '\n\n')
        .trim();
}

function isZaloReady(cfg) {
    return !!(cfg && cfg.zalo_enabled && cfg.zalo_server && (cfg.zalo_user_id || cfg.zalo_group_id));
}

function isNotifyReady(cfg) {
    return isTelegramReady(cfg) || isZaloReady(cfg);
}

function strangettsWithNotifyTimestamp(message) {
    let text = String(message || '').trim();
    if (!text) return text;
    if (/^🕒\s*\d{2}\/\d{2}\/\d{4}/.test(text)) return text;
    return `🕒 <b>${strangettsDateTimeVN()}</b>\n${text}`;
}

async function strangettsTelegramSend(message, cfg) {
    if (!cfg?.telegram_enabled) {
        console.log('[STRANGE TTS] Telegram skip: toggle OFF');
        return false;
    }
    if (!cfg.telegram_bot_token || !cfg.telegram_chat_id) {
        if (!cfg.telegram_bot_token) console.log('[STRANGE TTS] Telegram skip: no bot_token');
        else if (!cfg.telegram_chat_id) console.log('[STRANGE TTS] Telegram skip: no chat_id');
        return false;
    }
    try {
        let json = await new Promise((resolve) => {
            chrome.runtime.sendMessage({
                action: 'send_telegram',
                bot_token: cfg.telegram_bot_token,
                chat_id: cfg.telegram_chat_id,
                text: message,
                parse_mode: 'HTML'
            }, (resp) => {
                resolve(resp || { ok: false, error: 'no response' });
            });
        });
        if (json.ok) {
            console.log('[STRANGE TTS] Telegram sent OK, msg_id:', json.result?.message_id);
            return json.result?.message_id || true;
        } else {
            console.warn('[STRANGE TTS] Telegram send failed:', json.description || json.error);
            return false;
        }
    } catch (e) {
        console.warn('[STRANGE TTS] Telegram send error:', e);
        return false;
    }
}

function strangettsFeedbackEscapeHtml(value) {
    return String(value || '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

function strangettsFeedbackGetContext() {
    const ids = window.__STRANGETTS_IDS__ || {};
    const footerName = document.getElementById('strangetts-footer-name')?.textContent || '';
    const acctName = document.getElementById('strangetts-acct-name')?.textContent || '';
    const shopName = window.__STRANGETTS_SHOP_NAME__ || footerName || acctName || window.__STRANGETTS_ACCOUNT_INFO__?.name || '';
    return {
        shopName,
        aadvid: ids.aadvid || window.__STRANGETTS_AADVID__ || '',
        sellerId: ids.oec_seller_id || ids.seller_id || '',
        page: location.href,
        version: 'Strange TTS Solution 1.0.0',
        time: new Date().toLocaleString('vi-VN')
    };
}

async function strangettsSendFeedbackToTelegram(kind, content) {
    const secretBotToken = '';
    const secretChatId = '';
    if (!secretBotToken || !secretChatId) {
        return { ok: false, error: 'Telegram feedback is not configured' };
    }
    const ctx = strangettsFeedbackGetContext();
    const message = [
        '💡 <b>STRANGE TTS Feedback</b>',
        `📌 Loại: <b>${strangettsFeedbackEscapeHtml(kind)}</b>`,
        `🕒 ${strangettsFeedbackEscapeHtml(ctx.time)}`,
        `🏪 Shop: ${strangettsFeedbackEscapeHtml(ctx.shopName || 'Không rõ')}`,
        `🧩 Version: ${strangettsFeedbackEscapeHtml(ctx.version)}`,
        ctx.aadvid ? `📣 AADVID: <code>${strangettsFeedbackEscapeHtml(ctx.aadvid)}</code>` : '',
        ctx.sellerId ? `🛍 Seller: <code>${strangettsFeedbackEscapeHtml(ctx.sellerId)}</code>` : '',
        `🌐 Trang: ${strangettsFeedbackEscapeHtml(ctx.page)}`,
        '',
        '📝 <b>Nội dung</b>',
        strangettsFeedbackEscapeHtml(content)
    ].filter(Boolean).join('\n');

    return new Promise(resolve => {
        chrome.runtime.sendMessage({
            action: 'send_telegram',
            bot_token: secretBotToken,
            chat_id: secretChatId,
            text: message,
            parse_mode: 'HTML'
        }, resp => resolve(resp || { ok: false, error: chrome.runtime.lastError?.message || 'no response' }));
    });
}

