    // ===== OVERVIEW METRICS RENDERING =====
    function lbRenderOverview(coreData) {
        let set = (id, val) => { let el = document.getElementById(id); if (el) el.textContent = val; };
        let fmtAmt = (v) => v != null ? strangettsFormatVN(parseFloat(v) || 0) : '—';
        let fmtPct = (v) => v != null ? (parseFloat(v) * 100).toFixed(2) + '%' : '—';
        let fmtNum = (v) => v != null ? strangettsShortVN(parseFloat(v) || 0) : '—';
        let fmtSec = (v) => v != null ? Math.round(parseFloat(v)) + 's' : '—';
        let fmtInt = (v) => v != null ? String(Math.round(parseFloat(v) || 0)) : '—';

        // Get ads data from Level 1 camps
        let totalSpend = 0, totalGmv = 0, totalOrders = 0, avgRoi = 0;
        if (state.camps && state.camps.length > 0) {
            for (let c of state.camps) {
                totalSpend += parseNum(c.spend);
                totalGmv += parseNum(c.gmv);
                totalOrders += parseInt(c.orders || '0') || 0;
            }
            avgRoi = totalSpend > 0 ? (totalGmv / totalSpend) : 0;
        }

        // Determine which levels are enabled
        let lv2On = document.getElementById('lb-lv2-toggle')?.checked;
        let lv3On = document.getElementById('lb-lv3-toggle')?.checked;

        // === CẤP 1: Ads data (always available) ===
        if (totalSpend > 0) {
            set('lb-ov-adscost', strangettsFormatVN(totalSpend));
            set('lb-ov-roi', avgRoi.toFixed(2));
        }
        if (totalGmv > 0) set('lb-ov-gmv', strangettsFormatVN(totalGmv));
        if (totalOrders > 0) set('lb-ov-orders', String(totalOrders));
        // Ads values (from camps = LV1)
        if (totalGmv > 0) set('lb-ov-gmv-ads', strangettsFormatVN(totalGmv));
        if (totalOrders > 0) set('lb-ov-orders-ads', String(totalOrders));

        // Update time
        let now = new Date();
        set('lb-ov-time', `${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`);

        // === CẤP 2: Dashboard data (override Cấp 1 if enabled) ===
        let dash = window.__STRANGETTS_LIVE_DASHBOARD__;
        if (lv2On && dash && dash.gmv > 0) {
            set('lb-ov-gmv', strangettsFormatVN(dash.gmv || 0));
            set('lb-ov-viewers', String(dash.viewers || 0));
            // LIVE duration from heartbeat
            if (state._liveDuration > 0) { let ld = state._liveDuration; set('lb-ov-duration', Math.floor(ld / 3600) + 'h' + String(Math.floor((ld % 3600) / 60)).padStart(2, '0') + 'p'); }
            set('lb-ov-ctr', dash.ctr ? (dash.ctr * 100).toFixed(1) + '%' : '—');
            set('lb-ov-gpm', dash.gpm ? strangettsShortVN(dash.gpm) : '—');
            set('lb-lv2-gmv', strangettsFormatVN(dash.gmv || 0));
            set('lb-lv2-viewers', String(dash.viewers || 0));
            set('lb-lv2-impressions', dash.impressions ? strangettsShortVN(dash.impressions) : '—');
            set('lb-lv2-views', dash.views ? strangettsShortVN(dash.views) : '—');
            set('lb-lv2-ctr', dash.ctr ? (dash.ctr * 100).toFixed(2) + '%' : '—');
            set('lb-lv2-avgwatch', dash.avgViewDuration ? Math.round(dash.avgViewDuration) + 's' : '—');
            set('lb-lv2-orderrate', dash.orderRate ? (dash.orderRate * 100).toFixed(2) + '%' : '—');
        }

        // === CẤP 3: Analytics data (override all if enabled — highest priority) ===
        if (!lv3On || !coreData || !coreData.stats) {
            // Update revenue display from whatever data we have
            lbUpdateRevenueDisplay();
            return;
        }

        // Parse flat stats object from core/stats API
        let s = coreData.stats;
        let gmv = s.direct_gmv_local ? parseFloat(s.direct_gmv_local.amount) : null;
        let viewers = s.watch_uv || s.watch_pv;
        let impressions = s.client_show_cnt;
        let views = s.watch_pv;
        let ctr = s.click_through_rate ? parseFloat(s.click_through_rate) : null;
        let avgWatch = s.avg_view_duration ? parseFloat(s.avg_view_duration) : null;
        let orders = s.direct_sales || s.sales;
        let orderRate = s.sku_order_rate ? parseFloat(s.sku_order_rate) : null;
        let adsCost = s.ads_cost_local ? parseFloat(s.ads_cost_local.amount) : null;
        let gpmVal = s.live_show_gpm_local ? parseFloat(s.live_show_gpm_local.amount) : null;
        let gmvPerHour = s.direct_gmv_local_per_hour ? parseFloat(s.direct_gmv_local_per_hour.amount) : null;
        let impPerHour = s.show_pv_per_hour;
        let enterRate = s.enter_room_rate ? parseFloat(s.enter_room_rate) * 100 : 0;
        let enterRatePreview = s.enter_room_rate_live_preview ? parseFloat(s.enter_room_rate_live_preview) * 100 : 0;

        // === Populate __STRANGETTS_LIVE_DASHBOARD__ for Live/Merch scoring in Level 1 ===
        window.__STRANGETTS_LIVE_DASHBOARD__ = {
            dataSource: 'level3_core_stats',
            roomId: lv3State.roomId || '',
            gmv: gmv || 0,
            viewers: viewers || 0,
            currentViewers: s.watch_uv || viewers || 0,
            ctr: ctr || 0,
		            gpm: gpmVal || 0,
		            adsCost: adsCost || 0,
		            impressions: impressions || 0,
            views: views || 0,
            gmvPerHour: gmvPerHour || 0,
            impressionsPerHour: impPerHour || 0,
            avgViewDuration: avgWatch || 0,
            orderRate: orderRate ? orderRate * 100 : 0,
            enterRate: enterRate,
            enterRatePreview: enterRatePreview,
            totalOrders: orders || 0,
            commentRate: s.live_comment_rate ? parseFloat(s.live_comment_rate) * 100 : 0,
            followRate: s.live_follow_rate ? parseFloat(s.live_follow_rate) * 100 : 0,
            shareRate: s.live_share_rate ? parseFloat(s.live_share_rate) * 100 : 0,
            likeRate: s.live_like_rate ? parseFloat(s.live_like_rate) * 100 : 0,
            watchOver1Min: s.watch_pv_one_min_plus || 0,
            liveDurationSec: state._liveDuration || 0,
        };

        // === OVERVIEW (top section) ===
        if (gmv != null) set('lb-ov-gmv', strangettsFormatVN(gmv));
        if (viewers != null) set('lb-ov-viewers', String(viewers));
        // LIVE duration from heartbeat
        if (state._liveDuration > 0) { let ld = state._liveDuration; set('lb-ov-duration', Math.floor(ld / 3600) + 'h' + String(Math.floor((ld % 3600) / 60)).padStart(2, '0') + 'p'); }
        if (!totalSpend && adsCost) set('lb-ov-adscost', fmtAmt(String(adsCost)));
        if (ctr != null) set('lb-ov-ctr', (ctr * 100).toFixed(2) + '%');
        if (!totalOrders && orders) set('lb-ov-orders', String(orders));
        // Always set total orders from LV3 if available (this is the real total)
        if (orders) set('lb-ov-orders', String(orders));
        if (gmvPerHour != null) set('lb-ov-gpm', strangettsShortVN(gmvPerHour));

        // === LEVEL 2: Dashboard LIVE ===
        if (gmv != null) set('lb-lv2-gmv', strangettsFormatVN(gmv));
        if (viewers != null) set('lb-lv2-viewers', String(viewers));
        if (impressions != null) set('lb-lv2-impressions', strangettsShortVN(impressions));
        if (views != null) set('lb-lv2-views', String(views));
        if (avgWatch != null) set('lb-lv2-avgwatch', Math.round(avgWatch) + 's');
        if (ctr != null) set('lb-lv2-ctr', (ctr * 100).toFixed(2) + '%');
        if (orderRate != null) set('lb-lv2-orderrate', (orderRate * 100).toFixed(2) + '%');

        // === LEVEL 3: Full Analytics ===
        if (gmv != null) set('lb-lv3-gmv', strangettsFormatVN(gmv));
        if (orders != null) set('lb-lv3-orders', String(orders));
        // Người xem hiện tại — use watch_uv (unique viewers currently watching)
        let currentViewers = s.watch_uv;
        if (currentViewers != null) set('lb-lv3-currentviewers', String(currentViewers));
        if (impressions != null) set('lb-lv3-impressions', strangettsShortVN(impressions));
        if (views != null) set('lb-lv3-views', String(views));
        if (gmvPerHour != null) set('lb-lv3-gpmh', strangettsShortVN(gmvPerHour));
        if (impPerHour != null) set('lb-lv3-iphr', strangettsShortVN(impPerHour));
        if (gpmVal != null) set('lb-lv3-gpm', strangettsShortVN(gpmVal));
        if (avgWatch != null) set('lb-lv3-avgwatch', Math.round(avgWatch) + 's');
        set('lb-lv3-commentrate', s.live_comment_rate ? (parseFloat(s.live_comment_rate) * 100).toFixed(2) + '%' : '—');
        set('lb-lv3-followrate', s.live_follow_rate ? (parseFloat(s.live_follow_rate) * 100).toFixed(2) + '%' : '—');
        // Tỷ lệ nhấn vào (bản xem trước) = enter_room_rate_live_preview
        set('lb-lv3-clickrate', s.enter_room_rate_live_preview ? (parseFloat(s.enter_room_rate_live_preview) * 100).toFixed(2) + '%' : '—');
        // Tỷ lệ nhấn = enter_room_rate
        set('lb-lv3-prodclickrate', s.enter_room_rate ? (parseFloat(s.enter_room_rate) * 100).toFixed(2) + '%' : '—');
        if (ctr != null) set('lb-lv3-ctr', (ctr * 100).toFixed(2) + '%');
        if (orderRate != null) set('lb-lv3-orderrate', (orderRate * 100).toFixed(2) + '%');
        set('lb-lv3-sharerate', s.live_share_rate ? (parseFloat(s.live_share_rate) * 100).toFixed(2) + '%' : '—');
        set('lb-lv3-likerate', s.live_like_rate ? (parseFloat(s.live_like_rate) * 100).toFixed(2) + '%' : '—');
        set('lb-lv3-watch1min', s.watch_pv_one_min_plus != null ? String(s.watch_pv_one_min_plus) : '—');
        if (adsCost != null) set('lb-lv3-adcost', strangettsShortVN(adsCost));

        // Update revenue display with latest data
        lbUpdateRevenueDisplay();
    }

    // ===== REVENUE DISPLAY CALCULATION =====
    function lbUpdateRevenueDisplay() {
        let set = (id, val) => { let el = document.getElementById(id); if (el) el.textContent = val; };

        // DT Mục tiêu = NS nhập × ROI nhập (từ ô input trên thanh top)
        let budgetInput = parseInt((document.getElementById('lb-max-budget')?.value || '0').replace(/\D/g, '')) || 0;
        let roiInput = parseFloat((document.getElementById('lb-min-roi')?.value || '0').replace(/,/g, '.')) || 0;
        if (budgetInput > 0 && roiInput > 0) {
            let targetRev = budgetInput * roiInput;
            set('lb-rev-target', strangettsShortVN(targetRev));
        }

        // DT Dự kiến = (GMV / phút đã live) × phút còn lại
        let startEl = document.getElementById('lb-live-start');
        let endEl = document.getElementById('lb-live-end');
        if (startEl?.value && endEl?.value) {
            let [sh, sm] = startEl.value.split(':').map(Number);
            let [eh, em] = endEl.value.split(':').map(Number);
            let startDate = new Date(); startDate.setHours(sh, sm, 0, 0);
            let endDate = new Date(); endDate.setHours(eh, em, 0, 0);
            let now = new Date();
            let elapsedMin = Math.max(1, (now - startDate) / 60000);
            let totalMin = Math.max(1, (endDate - startDate) / 60000);
            let remainMin = Math.max(0, (endDate - now) / 60000);

            // Get current GMV from overview
            let gmvText = document.getElementById('lb-ov-gmv')?.textContent || '0';
            // Parse VN short format: "24tr6" = 24.6M, "410K" = 410000, "1.2B" etc.
            let currentGmv = 0;
            if (gmvText.includes('tr')) {
                let parts = gmvText.replace(/[^\dtr.]/g, '').split('tr');
                currentGmv = (parseFloat(parts[0]) || 0) * 1000000 + (parseFloat(parts[1]) || 0) * 100000;
            } else if (gmvText.toUpperCase().includes('K')) {
                currentGmv = parseFloat(gmvText.replace(/[^\d.]/g, '')) * 1000 || 0;
            } else if (gmvText.toUpperCase().includes('B') || gmvText.includes('tỉ')) {
                currentGmv = parseFloat(gmvText.replace(/[^\d.]/g, '')) * 1000000000 || 0;
            } else {
                currentGmv = parseFloat(gmvText.replace(/\./g, '').replace(/,/g, '.').replace(/[^\d.]/g, '')) || 0;
            }

            // DT Dự kiến = (GMV / phút đã live) × phút còn lại
            if (currentGmv > 0 && elapsedMin > 0) {
                let gmvPerMin = currentGmv / elapsedMin;
                let projectedGmv = gmvPerMin * remainMin;
                set('lb-rev-projected', strangettsShortVN(projectedGmv));
            }

            // Thời gian còn lại
            if (remainMin > 60) {
                set('lb-time-remain', `${Math.floor(remainMin / 60)}h${Math.round(remainMin % 60)}p`);
            } else {
                set('lb-time-remain', `${Math.round(remainMin)}p`);
            }

            // Save to globals for AI
            window.__STRANGETTS_LIVE_START_TIME__ = startEl.value;
            window.__STRANGETTS_LIVE_END_TIME__ = endEl.value;
        }
    }

    // ===== PRODUCT TABLE RENDERING =====
    // Sort state for Cấp 2 product table
    if (!lv3State._sortCap2) lv3State._sortCap2 = { col: null, desc: true };

    function lbRenderProducts(products) {
        let table = document.getElementById('lb-product-table');
        let countEl = document.getElementById('lb-product-count');
        if (!table) return;
        if (!products || products.length === 0) {
            table.innerHTML = '<div style="color:#6B7280; text-align:center; padding:10px;">Chưa có dữ liệu SP</div>';
            if (countEl) countEl.textContent = '0 SP';
            return;
        }
        if (countEl) countEl.textContent = `${products.length} SP`;

        // Sort products if sort column is set
        let sorted = [...products];
        let s2 = lv3State._sortCap2;
        if (s2.col) {
            sorted.sort((a, b) => {
                let va = 0, vb = 0;
                if (s2.col === 'clicks') { va = parseInt(a.exposure_cnt) || 0; vb = parseInt(b.exposure_cnt) || 0; }
                else if (s2.col === 'ctr') { va = parseFloat(a.click_through_rate) || 0; vb = parseFloat(b.click_through_rate) || 0; }
                else if (s2.col === 'cart') { va = parseInt(a.add_shop_cart_cnt) || 0; vb = parseInt(b.add_shop_cart_cnt) || 0; }
                else if (s2.col === 'sold') {
                    va = (parseInt(a.direct_sales) || 0) + (parseInt(a.sales) || 0);
                    vb = (parseInt(b.direct_sales) || 0) + (parseInt(b.sales) || 0);
                }
                return s2.desc ? vb - va : va - vb;
            });
        }

        // 📌 ALWAYS MOVE PINNED PRODUCT TO TOP
        sorted.sort((a, b) => (b.is_pinned ? 1 : 0) - (a.is_pinned ? 1 : 0));

        // Init selected IDs set if not exists
        if (!lv3State._pinSelectedIds) lv3State._pinSelectedIds = new Set();

        let arrow = (col) => s2.col === col ? (s2.desc ? '▼' : '▲') : '⇅';
        let hdrStyle = 'cursor:pointer; user-select:none; display:flex; align-items:center; gap:1px;';
        let allChecked = sorted.length > 0 && sorted.every(p => lv3State._pinSelectedIds.has(p.id));
        let html = `<div style="display:grid; grid-template-columns:16px 20px 1fr 40px 40px 32px 32px 36px; gap:2px; padding:2px 4px; font-size:8px; color:#6B7280; font-weight:600; border-bottom:1px solid rgba(138,141,145,0.2);">
            <div><input type="checkbox" id="lb-pin-selall" ${allChecked ? 'checked' : ''} style="accent-color:#FF6B35; width:10px; height:10px; cursor:pointer;" title="Chọn tất cả"></div>
            <div>#</div><div>Tên</div>
            <div class="lb-sort-c2" data-col="clicks" style="${hdrStyle}">Clicks<span style="font-size:6px;">${arrow('clicks')}</span></div>
            <div class="lb-sort-c2" data-col="ctr" style="${hdrStyle}">CTR<span style="font-size:6px;">${arrow('ctr')}</span></div>
            <div class="lb-sort-c2" data-col="cart" style="${hdrStyle}">Cart<span style="font-size:6px;">${arrow('cart')}</span></div>
            <div class="lb-sort-c2" data-col="sold" style="${hdrStyle}">Sold<span style="font-size:6px;">${arrow('sold')}</span></div>
            <div>Pin</div>
        </div>`;
        sorted.forEach((p, i) => {
            let ctr = p.click_through_rate ? (parseFloat(p.click_through_rate) * 100).toFixed(1) + '%' : '—';
            let clicks = p.exposure_cnt || 0;
            let cart = p.add_shop_cart_cnt || 0;
            let sold = (parseInt(p.direct_sales) || 0) + (parseInt(p.sales) || 0);
            // Detect pinned từ lv3State (cap2 API không có is_pinned field)
            let pinnedPid = String(lv3State.pinnedProductId || '');
            let isPinned = pinnedPid && pinnedPid !== '0' && (String(p.id) === pinnedPid);
            let name = (p.name || '').substring(0, 25);
            let soldColor = sold > 0 ? '#4ADE80' : '#6B7280';
            let cartColor = cart > 0 ? '#FBBF24' : '#6B7280';
            let rowBg = isPinned ? 'rgba(255,107,53,0.15)' : (i % 2 === 0 ? 'rgba(0,0,0,0.1)' : 'transparent');
            let isSelected = lv3State._pinSelectedIds.has(p.id);
            let pinBtns = isPinned
                ? `<button class="lb-pin-btn" data-pid="${p.id}" data-action="unpin" style="background:#FF6B35; border:none; border-radius:4px; color:white; font-size:9px; cursor:pointer; padding:2px 5px; font-weight:800; line-height:1;" title="Đang ghim — bấm để bỏ ghim">📌</button>`
                : `<button class="lb-pin-btn" data-pid="${p.id}" data-action="pin" style="background:rgba(255,107,53,0.15); border:none; border-radius:4px; color:#FF6B35; font-size:9px; cursor:pointer; padding:2px 5px; font-weight:600; line-height:1;" title="Ghim SP này">📌</button>`;
            html += `<div style="display:grid; grid-template-columns:16px 20px 1fr 40px 40px 32px 32px 36px; gap:2px; padding:3px 4px; font-size:8px; color:#E8D5FF; background:${rowBg}; border-radius:3px; align-items:center;" data-product-id="${p.id}">
                <div><input type="checkbox" class="lb-pin-sel" data-pid="${p.id}" ${isSelected ? 'checked' : ''} style="accent-color:#FF6B35; width:10px; height:10px; cursor:pointer;"></div>
                <div style="color:#6B7280;">${i + 1}</div>
                <div style="overflow:hidden; text-overflow:ellipsis; white-space:nowrap;" title="${p.name || ''}">${name}</div>
                <div style="font-weight:700;">${clicks}</div>
                <div>${ctr}</div>
                <div style="color:${cartColor};">${cart}</div>
                <div style="color:${soldColor}; font-weight:700;">${sold}</div>
                ${pinBtns}
            </div>`;
        });
        table.innerHTML = html;

        // Add click handlers for Pin/Unpin buttons
        table.querySelectorAll('.lb-pin-btn').forEach(btn => {
            btn.addEventListener('click', async (e) => {
                e.stopPropagation();
                let pid = btn.getAttribute('data-pid');
                let action = btn.getAttribute('data-action');
                let isPin = action === 'pin';
                let roomId = document.getElementById('lb-room-id')?.value || lv3State.roomId;
                if (!roomId) { lbLog('⚠️ Chưa có room_id', 'error'); return; }

                btn.textContent = '⏳';
                btn.disabled = true;

                // TikTok tự bỏ ghim cũ khi ghim mới — chỉ cần gọi pin trực tiếp

                let result = await lbPinProduct(roomId, pid, isPin);
                if (result) {
                    let pName = products.find(p => p.id === pid)?.name || pid;
                    if (isPin) {
                        lv3State.pinnedProductId = pid;
                        try { strangettsFlashNotifyPinnedSpu(pid); } catch (e) { }
                        addResultLog(`📌 Ghim OK: <b>${(pName + '').substring(0, 25)}</b> → vị trí #1`, '#FF6B35');
                        if (chatState.autoChatPin) await strangettsAiChat('pin_post', { product_name: (pName + '').substring(0, 25) });
                    } else {
                        lv3State.pinnedProductId = null;
                        addResultLog(`📌 Bỏ ghim OK: <b>${(pName + '').substring(0, 25)}</b>`, '#FF6B35');
                    }
                    // Reload streamer list → introduce_id → pinnedProductId tự động cập nhật
                    await lbFetchStreamerProducts(roomId);
                    let upd = await lbFetchProductList(roomId);
                    if (upd && upd.length > 0) { lv3State.products = upd; }
                    lbRenderProducts(lv3State.products || []);
                } else {
                    btn.textContent = '❌';
                    setTimeout(() => { btn.disabled = false; lbRenderProducts(lv3State.products || []); }, 1500);
                }
            });
        });

        // Sort click handlers for column headers
        table.querySelectorAll('.lb-sort-c2').forEach(hdr => {
            hdr.addEventListener('click', () => {
                let col = hdr.getAttribute('data-col');
                if (s2.col === col) { s2.desc = !s2.desc; }
                else { s2.col = col; s2.desc = true; }
                lbRenderProducts(products);
            });
        });

        // Checkbox handlers for pin selection
        table.querySelectorAll('.lb-pin-sel').forEach(cb => {
            cb.addEventListener('change', () => {
                let pid = cb.getAttribute('data-pid');
                if (cb.checked) lv3State._pinSelectedIds.add(pid);
                else lv3State._pinSelectedIds.delete(pid);
                // Update select-all checkbox
                let selAll = document.getElementById('lb-pin-selall');
                if (selAll) selAll.checked = sorted.every(p => lv3State._pinSelectedIds.has(p.id));
                lbSetPinStatus(`✅ Đã chọn ${lv3State._pinSelectedIds.size} SP`);
            });
        });
        // Select All checkbox
        document.getElementById('lb-pin-selall')?.addEventListener('change', (e) => {
            sorted.forEach(p => {
                if (e.target.checked) lv3State._pinSelectedIds.add(p.id);
                else lv3State._pinSelectedIds.delete(p.id);
            });
            lbRenderProducts(products);
            lbSetPinStatus(e.target.checked ? `✅ Đã chọn ${lv3State._pinSelectedIds.size} SP` : '📌 Chưa chọn SP');
        });
    }

    // ===== AUTO-PIN ENGINE (Enhanced 3-mode) =====
    function lbStartAutoPin() {
        if (!state.running) {
            lv3State.autoPinRunning = false;
            lbSetPinStatus('Chờ live bắt đầu');
            lbLog('📌 Auto-Pin đang chờ live, không chạy khi hệ thống đã dừng', 'info');
            return false;
        }
        if (lv3State.autoPinTimer) { clearTimeout(lv3State.autoPinTimer); lv3State.autoPinTimer = null; }
        lv3State.autoPinRunning = true;
        lv3State.autoPinRunToken++;
        let token = lv3State.autoPinRunToken;
        lv3State.autoPinIndex = 0;
        lv3State._autoPinLastStrategy = null;
        lv3State._autoPinCycleComplete = false;

        let getStrategy = () => document.getElementById('lb-pin-strategy')?.value || 'continuous';
        let getIntervalSec = () => {
            let raw = parseInt(document.getElementById('lb-pin-delay')?.value || '60', 10) || 60;
            return Math.max(10, Math.min(600, raw));
        };

        let strategy = getStrategy();
        lbSetPinStatus(`🟢 ${strategy} / ${getIntervalSec()}s`);
        lbLog(`📌 Auto-Pin bắt đầu: ${strategy} / ${getIntervalSec()}s`, 'success');

        // Execute first pin immediately
        lbExecutePin(strategy, token);
        lv3State._autoPinLastStrategy = strategy;

        const scheduleNext = () => {
            if (!state.running || !lv3State.autoPinRunning || token !== lv3State.autoPinRunToken) return;
            if (lv3State.autoPinTimer) { clearTimeout(lv3State.autoPinTimer); lv3State.autoPinTimer = null; }
            let sec = getIntervalSec();
            lbSetPinStatus(`🟢 ${getStrategy()} / ${sec}s`);
            lv3State.autoPinTimer = setTimeout(() => {
                if (!state.running || !lv3State.autoPinRunning || token !== lv3State.autoPinRunToken) return;
            let curStrategy = getStrategy();
            let repeat = document.getElementById('lb-pin-repeat')?.checked !== false;

            // Reset index nếu strategy vừa thay đổi
            if (curStrategy !== lv3State._autoPinLastStrategy) {
                lv3State.autoPinIndex = 0;
                lv3State._autoPinCycleComplete = false;
                lv3State._autoPinLastStrategy = curStrategy;
                lbLog(`📌 Strategy thay đổi → ${curStrategy}, reset index`, 'info');
            }

            if (!repeat && lv3State._autoPinCycleComplete) {
                lbStopAutoPin();
                document.getElementById('lb-autopin-toggle').checked = false;
                return;
            }

            // Re-schedule with updated interval
            lbExecutePin(curStrategy, token);
                scheduleNext();
            }, sec * 1000);
        };
        lv3State.autoPinReschedule = scheduleNext;
        scheduleNext();
        return true;
    }

    function lbStopAutoPin() {
        lv3State.autoPinRunning = false;
        lv3State.autoPinRunToken++;
        lv3State._autoPinCycleComplete = false;
        lv3State.autoPinReschedule = null;
        if (lv3State.autoPinTimer) { clearTimeout(lv3State.autoPinTimer); lv3State.autoPinTimer = null; }
        lbSetPinStatus('⏹ Đã dừng');
        lbLog('📌 Auto-Pin dừng', 'info');
    }

    function lbAutoPinCanRun(token) {
        return !!(state.running && lv3State.autoPinRunning && token === lv3State.autoPinRunToken);
    }

    function lbSetPinStatus(text) {
        let el = document.getElementById('lb-pin-status');
        if (el) el.textContent = '📌 Ghim: ' + text;
    }

    async function lbExecutePin(strategy, token = lv3State.autoPinRunToken) {
        if (!lbAutoPinCanRun(token)) return;
        let roomId = state.running ? lbGetMetricRoomId() : await lbGetRoomId();
        if (!lbAutoPinCanRun(token)) return;
        if (!roomId) { lbSetPinStatus('⚠️ Chưa có room_id'); return; }

        // ✅ Lấy cả 2 nguồn:
        //    cap2Products (insights) → để CHỌN SP theo metrics
        //    streamerProducts       → để lấy product_id GHIM đúng API
        let [freshCap2, freshStreamers] = await Promise.all([
            lbFetchProductList(roomId),
            lbFetchStreamerProducts(roomId)
        ]);
        if (!lbAutoPinCanRun(token)) return;
        if (freshCap2 && freshCap2.length > 0) lv3State.products = freshCap2;
        if (freshStreamers && freshStreamers.length > 0) lv3State.streamerProducts = freshStreamers;

        let pool = lv3State.products || [];         // for selection
        let streamers = lv3State.streamerProducts || []; // for pin ID
        if (pool.length === 0) { lbSetPinStatus('⚠️ Chưa có SP'); return; }

        // ─── Lọc theo checkbox đã chọn ───
        let selectedIds = lv3State._pinSelectedIds || new Set();
        let workPool = selectedIds.size > 0 ? pool.filter(p => selectedIds.has(p.id)) : pool;
        if (workPool.length === 0) workPool = pool;

        // ─── Chọn SP theo strategy ───
        let target = null;
        let targetIdx = lv3State.autoPinIndex || 0;

        if (strategy === 'continuous') {
            let pinned = workPool.find(p => p.is_pinned);
            target = pinned || workPool[0];

        } else if (strategy === 'round') {
            if (targetIdx >= workPool.length) targetIdx = 0;
            target = workPool[targetIdx];
            lv3State.autoPinIndex = targetIdx + 1;
            if (lv3State.autoPinIndex >= workPool.length) {
                lv3State.autoPinIndex = 0;
                lv3State._autoPinCycleComplete = true;
            }

        } else if (strategy === 'top_sales' || strategy === 'top_clicks' || strategy === 'top_ctr') {
            let sorted = [...workPool].sort((a, b) => {
                if (strategy === 'top_sales') {
                    return ((parseInt(b.direct_sales) || 0) + (parseInt(b.sales) || 0)) -
                        ((parseInt(a.direct_sales) || 0) + (parseInt(a.sales) || 0));
                } else if (strategy === 'top_clicks') {
                    return (parseInt(b.exposure_cnt) || 0) - (parseInt(a.exposure_cnt) || 0);
                } else {
                    return (parseFloat(b.click_through_rate) || 0) - (parseFloat(a.click_through_rate) || 0);
                }
            });
            let candidates = sorted.slice(0, Math.min(5, sorted.length));
            if (targetIdx >= candidates.length) targetIdx = 0;
            target = candidates[targetIdx];
            lv3State.autoPinIndex = targetIdx + 1;
            if (lv3State.autoPinIndex >= candidates.length) {
                lv3State.autoPinIndex = 0;
                lv3State._autoPinCycleComplete = true;
            }
        }

        if (!target) { lbSetPinStatus('⚠️ Không tìm được SP'); return; }

        let targetName = (target.name || target.title || '').trim().toLowerCase();
        let sold = (parseInt(target.direct_sales) || 0) + (parseInt(target.sales) || 0);
        let clicks = parseInt(target.exposure_cnt) || 0;
        let ctr = target.click_through_rate ? (parseFloat(target.click_through_rate) * 100).toFixed(1) + '%' : '0%';
        let displayName = (target.name || '').substring(0, 30);

        // ─── Cross-match: tìm product_id thực từ streamerProducts ───
        // Ưu tiên: match full name, sau đó match phần đầu (30 ký tự)
        let streamerTarget = streamers.find(sp => {
            let spName = (sp.title || sp.name || '').trim().toLowerCase();
            return spName === targetName || (targetName.length > 8 && spName.includes(targetName.substring(0, Math.min(25, targetName.length))));
        });

        let pid = streamerTarget ? String(streamerTarget.product_id) : null;

        if (!pid) {
            // Fallback: nếu không match được, dùng streamer product ở cùng vị trí index
            lbLog(`⚠️ Không match được "${displayName}" → dùng streamer index ${targetIdx}`, 'error');
            let fallbackIdx = Math.min(targetIdx > 0 ? targetIdx - 1 : 0, streamers.length - 1);
            if (streamers[fallbackIdx]) pid = String(streamers[fallbackIdx].product_id);
        }

        if (!pid || pid === '0') { lbSetPinStatus('⚠️ Không lấy được product_id'); return; }

        // ─── Bỏ ghim SP cũ nếu khác SP mới ───
        let curPinned = lv3State.pinnedProductId;
        let isValidPinned = curPinned && String(curPinned) !== '0' && String(curPinned) !== '';
        if (isValidPinned && String(curPinned) !== pid) {
            if (!lbAutoPinCanRun(token)) return;
            lbLog(`📌 Bỏ ghim cũ: ${curPinned}`, 'info');
            await lbPinProduct(roomId, curPinned, false);
            if (!lbAutoPinCanRun(token)) return;
            lv3State.pinnedProductId = null;
            await new Promise(r => setTimeout(r, 500));
            if (!lbAutoPinCanRun(token)) return;
        }

        // ─── Ghim SP mới ───
        lbSetPinStatus(`📌 ${displayName}...`);
        lbLog(`📌 [${strategy}] Ghim: ${displayName} (pid:${pid}) | Bán:${sold} Clicks:${clicks} CTR:${ctr}`, 'instant');

        if (!lbAutoPinCanRun(token)) return;
        let pinResult = await lbPinProduct(roomId, pid, true);
        if (!lbAutoPinCanRun(token)) return;
        if (pinResult !== null) {
            lv3State.pinnedProductId = pid;
            try { strangettsFlashNotifyPinnedSpu(pid); } catch (e) { }
            addResultLog(`📌 Ghim OK: <b>${displayName}</b> | ${strategy} | Bán:${sold}`, '#FF6B35');
            lbRenderProducts(lv3State.products);
            if (lv3State.autoChatPinNotification || chatState.autoChatPin) {
                await strangettsAiChat('pin_post', { product_name: displayName });
            }
            let cfg = state._cfg || await strangettsGetLiveBetaConfig();
            if (isNotifyReady(cfg) && cfg.telegram_notify_pin !== false) {
                await strangettsNotifySend(`${getLiveAccountLabel()}
📌 Ghim SP: <b>${displayName}</b>
👆 ${clicks} clicks | CTR ${ctr} | Bán: ${sold}`, cfg);
            }
        } else {
            let gwActive = await lbFetchActiveGiveaway();
            let failReason = gwActive?.active ? ` (⚠️ GW đang chạy)` : '';
            addResultLog(`❌ Ghim FAIL: <b>${displayName}</b>${failReason}`, '#EF4444');
            lbSetPinStatus(`❌ Ghim FAIL${failReason}`);
        }
    }

    // ===== LEVEL 3 POLL =====
    async function lbPollLevel3() {
        let roomId = state.running ? lbGetMetricRoomId() : await lbGetRoomId();
        if (!roomId) {
            if (state.tickCount <= 1 || state.tickCount % 5 === 0) {
                lbLog('⚠️ Chưa có room_id phiên live hiện tại từ Ads API', 'error');
            }
            return;
        }
        lv3State.roomId = String(roomId);

        let lv3On = document.getElementById('lb-lv3-toggle')?.checked;
        let lv2On = document.getElementById('lb-lv2-toggle')?.checked;

        if (lv3On || lv2On) {
            // Get room info FIRST (need creator_id for core/stats)
            if (!lv3State.creatorId || state.tickCount % 3 === 0) {
                let roomInfo = await lbFetchRoomInfo(roomId);
                if (roomInfo) {
                    lv3State.creatorId = roomInfo.owner_tiktok_id || '';
                    // Try to get creator name from room info
                    lv3State.creatorName = roomInfo.creator_name || roomInfo.creator_nickname || roomInfo.nick_name || roomInfo.owner_name || roomInfo.name || null;
                    // Fallback: lookup from identity map
                    if (!lv3State.creatorName && lv3State.creatorId && window.__STRANGETTS_IDENTITY_MAP__) {
                        let idInfo = window.__STRANGETTS_IDENTITY_MAP__[lv3State.creatorId];
                        if (idInfo?.name) lv3State.creatorName = idInfo.name;
                    }
                    // Fallback: try to extract from camp name (LIVE GMV Max_Doanh thu gộp_<name>_<date>)
                    if (!lv3State.creatorName && state.camps?.length) {
                        let campName = state.camps[0]?.name || '';
                        let parts = campName.split('_');
                        if (parts.length >= 3) lv3State.creatorName = parts[parts.length - 2]; // second to last part
                    }
                    if (lv3State.creatorName) {
                        lbLogThrottled('live-creator-name', `📺 TK LIVE: ${lv3State.creatorName}`, 'success', 5 * 60000);
                        strangettsAiSyncIdentityDefaults();
                    }
                }
            }

            // Core stats (needs creator_id from room/info)
            let coreData = await lbFetchCoreStats(roomId);
            if (coreData) {
                lv3State.coreStats = coreData;
                lbRenderOverview(coreData);
            } else {
                lbRenderOverview(null);
            }

            // Product list (Level 2 + Level 3)
            let products = await lbFetchProductList(roomId);
            if (products && products.length > 0) {
                lv3State.products = products;
                try { strangettsFlashRememberLiveProducts(products, 'level3_poll'); } catch (e) { }
                lbRenderProducts(products);
                lbRenderLv3Products(products);
            }

            // Streamer products + introduce_id (mỗi tick để detect pin state)
            await lbFetchStreamerProducts(roomId);

            // Traffic sources (less frequent)
            if (state.tickCount % 3 === 0) {
                let sources = await lbFetchTrafficSources(roomId);
                if (sources) {
                    lv3State.trafficSources = sources;
                    lbRenderTrafficSources(sources);
                }
            }
        } else {
            lbRenderOverview(null);
        }

        lv3State.lastPollTime = Date.now();
    }

    // === PIN PRODUCT API ===
    async function lbPinProduct(roomId, productId, isPin) {
        let params = new URLSearchParams({
            aid: '253642',
            app_name: 'i18n_ecom_alliance',
            device_platform: 'web',
            cookie_enabled: 'true',
            browser_language: navigator.language || 'vi-VN',
            browser_platform: navigator.platform || 'MacIntel',
            browser_name: 'Mozilla',
            browser_version: navigator.userAgent || '',
            browser_online: 'true',
            timezone_name: Intl.DateTimeFormat().resolvedOptions().timeZone || 'Asia/Saigon'
        });
        let url = `https://shop.tiktok.com/api/v1/streamer_desktop/live_product/pin?${params.toString()}`;
        let body = {
            room_id: String(roomId),
            product_id: String(productId),
            op: isPin ? 3 : 2  // 3 = pin, 2 = unpin
        };
        try {
            let result = await shopApiFetch(url, body);
            lbLog(`📌 ${isPin ? 'Ghim' : 'Bỏ ghim'} product_id=${productId} op=${isPin ? 3 : 2}: ${result !== null ? 'OK' : 'FAIL'}`, result !== null ? 'success' : 'error');
            return result;
        } catch (e) {
            lbLog(`📌 Pin error: ${e.message}`, 'error');
            return null;
        }
    }

    // Fetch streamer product list (for pin operations — uses different product_id than insights API)
    async function lbFetchStreamerProducts(roomId) {
        let params = new URLSearchParams({
            aid: '253642',
            app_name: 'i18n_ecom_alliance',
            device_platform: 'web',
            room_id: String(roomId)
        });
        let url = `https://shop.tiktok.com/api/v1/streamer_desktop/live_product/list?${params.toString()}`;
        try {
            let resp;
            if (location.hostname === 'shop.tiktok.com') {
                resp = await fetch(url, { credentials: 'include' }).then(r => r.json());
            } else {
                resp = await new Promise(resolve => {
                    chrome.runtime.sendMessage({ action: 'fetch_shop_api', url, method: 'GET' }, r => {
                        resolve(r?.success ? r.data : null);
                    });
                });
            }
            if (resp && resp.code === 0 && resp.data?.products) {
                lbLogThrottled('streamer-products', `📦 Streamer products: ${resp.data.products.length} SP`, 'success', 2 * 60000);
                lv3State.streamerProducts = resp.data.products;
                try { window.__STRANGETTS_LIVE_STREAMER_PRODUCTS__ = resp.data.products; } catch (e) { }
                // introduce_id = product_id đang được ghim (xác nhận từ TikTok API)
                lv3State.pinnedProductId = resp.data.introduce_id ? String(resp.data.introduce_id) : null;
                return resp.data.products;
            }
        } catch (e) {
            lbLog('📦 Streamer products error: ' + e.message, 'error');
        }
        return null;
    }

    // Fetch currently pinned product
    async function lbFetchPinnedProduct(roomId) {
        let params = new URLSearchParams({
            aid: '253642',
            app_name: 'i18n_ecom_alliance',
            room_id: String(roomId)
        });
        let url = `https://shop.tiktok.com/api/v1/streamer_desktop/pin/get?${params.toString()}`;
        try {
            let resp;
            if (location.hostname === 'shop.tiktok.com') {
                resp = await fetch(url, { credentials: 'include' }).then(r => r.json());
            } else {
                resp = await new Promise(resolve => {
                    chrome.runtime.sendMessage({ action: 'fetch_shop_api', url, method: 'GET' }, r => {
                        resolve(r?.success ? r.data : null);
                    });
                });
            }
            if (resp && resp.code === 0) {
                lv3State.pinnedProductId = resp.product_id || resp.data?.product_id || null;
                return lv3State.pinnedProductId;
            }
        } catch (e) { }
        return null;
    }

    // ===== GIVEAWAY AUTO-PUBLISH MODULE =====
    const LB_GIVEAWAY_DEFAULT_DELAY_MIN = 10;
    const LB_GIVEAWAY_ACTIVE_GRACE_SEC = 10;
    const LB_GIVEAWAY_END_CONFIRM_MS = 5000;
    let giveawayState = {
	        templates: [],           // fetched template list
	        selectedIds: new Set(),  // selected template IDs for auto-publish
	        autoRequested: false,    // user wants auto giveaway for every live session
	        autoEnabled: false,
        mode: 'sequential',      // 'continuous' | 'sequential' | 'random'
        intervalMin: LB_GIVEAWAY_DEFAULT_DELAY_MIN,
        repeat: true,
        delayById: {},
        currentIndex: 0,         // for sequential mode
        lastPublishTime: 0,
        waitTemplateId: '',
        waitStartedAt: 0,
        waitUntil: 0,
        hasPublishedThisRun: false,
        lastRandomTemplateId: '',
        lastActiveSeenAt: 0,
        endConfirmUntil: 0,
	        activeName: '',
	        activeCountdown: 0,      // seconds of current giveaway countdown
	        timer: null,
	        wakeupTimer: null,
	        publishCount: 0,
	        runToken: 0,             // invalidates any async auto tick after LIVE stops
	    };

    function lbNormalizeGiveawayDelayMin(value, fallback = LB_GIVEAWAY_DEFAULT_DELAY_MIN) {
        const n = parseInt(value, 10);
        if (!Number.isFinite(n)) return fallback;
        return Math.max(0, Math.min(1440, n));
    }

    function giveawayApiUrl(path) {
        let params = new URLSearchParams({
            user_language: 'vi-VN', locale: 'vi-VN', aid: '253642', app_name: 'i18n_ecom_alliance',
            device_id: '0', device_platform: 'web', cookie_enabled: 'true',
            screen_width: String(screen.width || 1680), screen_height: String(screen.height || 1050),
            browser_language: navigator.language || 'vi-VN', browser_platform: navigator.platform || 'MacIntel',
            browser_name: 'Mozilla', browser_version: navigator.userAgent || '',
            browser_online: 'true', timezone_name: Intl.DateTimeFormat().resolvedOptions().timeZone || 'Asia/Saigon',
            page_scene: '0', carrier_region: 'vn'
        });
        return `https://shop.tiktok.com/aweme/v1/oec/sea_content/creator/live/giveaway/${path}?${params.toString()}`;
    }

    async function lbFetchGiveawayTemplates(roomId, authorId) {
        let url = giveawayApiUrl('templates') +
            `&author_id=${authorId}&room_id=${roomId}&page_source=12&cur_page=1&count=50&can_show_activity_template=true&cursor=`;
        try {
            let resp;
            if (location.hostname === 'shop.tiktok.com') {
                resp = await fetch(url, { credentials: 'include' }).then(r => r.json());
            } else {
                resp = await new Promise(resolve => {
                    chrome.runtime.sendMessage({ action: 'fetch_shop_api', url, method: 'GET' }, r => {
                        resolve(r?.success ? r.data : null);
                    });
                });
            }
            if (resp && resp.code === 0 && resp.data) return resp.data.template_info || [];
        } catch (e) { console.warn('[STRANGE TTS] Giveaway templates error:', e.message); }
        return [];
    }

    async function lbPublishGiveaway(templateId, roomId, authorId, bizNo, isRetry = false) {
        let url = giveawayApiUrl('templates/publish');
        let body = {
            template_id: String(templateId), room_id: String(roomId),
            author_id: String(authorId), biz_no: String(bizNo),
            session_id: '', can_show_activity_template: true
        };
        try {
            let result = await shopApiFetch(url, body);
            if (result === null || result.code !== 0) {
                let errCode = result?.code;
                if (errCode === 151005012 && !isRetry) {
                    lbLog('⚠️ Lỗi session giveaway (151005012), đang thử lại sau 3s...', 'warning');
                    await new Promise(r => setTimeout(r, 3000));
                    return await lbPublishGiveaway(templateId, roomId, authorId, bizNo, true);
                }
                lbLog(`🎁 Publish giveaway template=${templateId} FAIL: ${result?.message || 'Unknown'}`, 'error');
                return null;
            }
            lbLog(`🎁 Publish giveaway template=${templateId}: OK`, 'success');
            return result;
        } catch (e) { lbLog(`🎁 Publish error: ${e.message}`, 'error'); return null; }
    }

    function lbExtractActiveGiveawayName(info) {
        if (!info || typeof info !== 'object') return '';
        let direct = [
            info.name,
            info.title,
            info.activity_name,
            info.lucky_bag_name,
            info.lucky_bag_title,
            info.prize_name,
            info.template_name,
            info.incentive?.platform_coupon_info?.content,
            info.incentive?.draw_prize_base_info?.name,
            info.template_info?.incentive?.platform_coupon_info?.content,
            info.template_info?.incentive?.draw_prize_base_info?.name,
            info.platform_coupon_info?.content,
            info.draw_prize_base_info?.name,
            info.task_info?.task_config?.comment
        ];
        for (let val of direct) {
            if (typeof val === 'string' && val.trim()) return val.trim().slice(0, 60);
        }
        let seen = new Set();
        let stack = [info];
        while (stack.length) {
            let obj = stack.shift();
            if (!obj || typeof obj !== 'object' || seen.has(obj)) continue;
            seen.add(obj);
            for (let [key, val] of Object.entries(obj)) {
                if (typeof val === 'string') {
                    let text = val.trim();
                    if (/(name|title|content|prize|coupon)/i.test(key) && text && text.length <= 80 && !/^https?:\/\//i.test(text) && !/^\d+$/.test(text)) {
                        return text.slice(0, 60);
                    }
                } else if (val && typeof val === 'object') {
                    stack.push(val);
                }
            }
        }
        return '';
    }

    // Fetch active giveaway status via lucky_bag/get API
    async function lbFetchActiveGiveaway() {
        let params = new URLSearchParams({
            user_language: 'vi-VN', locale: 'vi-VN', aid: '253642', app_name: 'i18n_ecom_alliance',
            device_id: '0', device_platform: 'web', cookie_enabled: 'true',
            browser_language: navigator.language || 'vi-VN', browser_platform: navigator.platform || 'MacIntel',
            browser_name: 'Mozilla', browser_version: navigator.userAgent || '',
            browser_online: 'true', timezone_name: Intl.DateTimeFormat().resolvedOptions().timeZone || 'Asia/Saigon',
            page_scene: '0', carrier_region: 'vn'
        });
        let url = `https://shop.tiktok.com/api/v1/streamer_desktop/live_product/lucky_bag/get?${params.toString()}`;
        try {
            let resp;
            if (location.hostname === 'shop.tiktok.com') {
                resp = await fetch(url, { method: 'GET', credentials: 'include' }).then(r => r.json());
            } else {
                resp = await new Promise(resolve => {
                    chrome.runtime.sendMessage({ action: 'fetch_shop_api', url, method: 'GET' }, r => {
                        resolve(r?.success ? r.data : null);
                    });
                });
            }
            if (resp && resp.code === 0 && resp.data?.lucky_bag_info) {
                let info = resp.data.lucky_bag_info;
                let activityId = info.activity_id || info.lucky_bag_id || '';
                let name = lbExtractActiveGiveawayName(info);
                return { active: info.status === 2, countdownSec: parseInt(info.count_down_sec) || 0, activityId, name, raw: info };
            }
        } catch (e) { console.warn('[STRANGE TTS] lucky_bag/get error:', e.message); }
        return { active: false, countdownSec: 0, activityId: '' };
    }

