	    function lbApplyChatKey(key, source = 'auto', opts = {}) {
	        let clean = String(key || '').trim();
	        if (!clean) return '';
	        let changed = true;
	        try { changed = chatState.ecStreamerKey !== clean; chatState.ecStreamerKey = clean; } catch (e) { }
	        window.__STRANGETTS_STREAM_KEY__ = clean;
	        if (!String(source || '').startsWith('storage')) {
	            try { chrome.storage.local.set({ lb_ec_streamer_key: clean, lb_last_chat_key: clean }); } catch (e) { }
	        }
	        let inp = document.getElementById('lb-chat-key-manual');
	        if (inp && inp.value !== clean) inp.value = clean;
	        let status = document.getElementById('lb-chat-key-status');
	        if (status) {
	            status.textContent = '🔑 OK';
	            status.style.color = '#4ADE80';
	        }
	        try { lbSyncToMultiShop('ec_streamer_key', clean); } catch (e) { }
	        if (opts.log !== false && changed) {
	            try { lbLog(`🗝️ Chat Key tự động nhận (${source}): ${clean.slice(0, 12)}...`, 'success'); } catch (e) { }
	        }
	        return clean;
	    }

	    function lbPersistOpsSettings(extra = {}) {
	        try {
	            let gwAutoEl = document.getElementById('lb-giveaway-auto');
	            let autoPinEl = document.getElementById('lb-autopin-toggle');
	            let pinStrategyEl = document.getElementById('lb-pin-strategy');
	            let pinDelayEl = document.getElementById('lb-pin-delay');
	            let pinRepeatEl = document.getElementById('lb-pin-repeat');
	            let hasAutoLiveExtra = Object.prototype.hasOwnProperty.call(extra, 'autoLiveWatcher');
	            let autoLiveWatcher = hasAutoLiveExtra ? !!extra.autoLiveWatcher : false;
	            if (!hasAutoLiveExtra) {
	                try { autoLiveWatcher = !!_autoLiveState?.enabled; } catch (e) { autoLiveWatcher = false; }
	            }
	            chrome.storage.local.set({
	                [LB_OPS_SETTINGS_KEY]: {
	                    autoChatPin: !!chatState.autoChatPin,
	                    autoChatGiveaway: !!chatState.autoChatGiveaway,
	                    autoChatFlashSale: !!chatState.autoChatFlashSale,
	                    autoReminder: !!chatState.autoReminder,
	                    reminderInterval: parseInt(chatState.reminderInterval, 10) || 15,
	                    autoGiveaway: gwAutoEl ? !!gwAutoEl.checked : !!giveawayState.autoRequested,
	                    giveawayMode: giveawayState.mode || 'sequential',
	                    giveawayIntervalMin: lbNormalizeGiveawayDelayMin(giveawayState.intervalMin),
	                    giveawayDelayById: giveawayState.delayById || {},
	                    giveawaySelectedIds: [...giveawayState.selectedIds],
	                    autoPin: autoPinEl ? !!autoPinEl.checked : !!lv3State.autoPinRunning,
	                    autoPinStrategy: pinStrategyEl?.value || 'continuous',
	                    autoPinDelaySec: parseInt(pinDelayEl?.value || '60', 10) || 60,
	                    autoPinRepeat: pinRepeatEl ? !!pinRepeatEl.checked : true,
	                    autoPinChatNotification: !!lv3State.autoChatPinNotification,
	                    autoLiveWatcher,
	                    ...extra
	                }
	            });
	        } catch (e) { console.warn('[STRANGE TTS] ops settings save error:', e); }
	    }

	    function lbStartReminderTimerFromSettings() {
	        if (chatState.reminderTimer) clearInterval(chatState.reminderTimer);
	        if (!chatState.autoReminder) return;
	        if (!state.running) {
	            lbLog('⏰ Nhắc nhở đang chờ live, không gửi khi hệ thống đã dừng', 'info');
	            return;
	        }
	        chatState.reminderInterval = parseInt(chatState.reminderInterval, 10) || 15;
	        chatState.reminderTimer = setInterval(async () => {
	            if (!state.running || !chatState.autoReminder || !chatState.ecStreamerKey) return;
	            if (chatState.reminderMessages && chatState.reminderMessages.length > 0) {
	                const idx = strangettsAiNextIndex('custom:reminder', chatState.reminderMessages);
	                let msg = strangettsAiFill(chatState.reminderMessages[idx], strangettsAiBuildVars());
	                await lbSendChat(msg);
	            } else {
	                await strangettsAiChat('reminder', strangettsAiBuildVars());
	            }
	        }, chatState.reminderInterval * 60000);
	    }

	    async function lbRestoreOpsSettings() {
	        try {
	            let d = await new Promise(r => chrome.storage.local.get([LB_OPS_SETTINGS_KEY], r));
	            let s = d[LB_OPS_SETTINGS_KEY] || {};
	            if (typeof s.autoChatPin === 'boolean') chatState.autoChatPin = s.autoChatPin;
	            if (typeof s.autoChatGiveaway === 'boolean') chatState.autoChatGiveaway = s.autoChatGiveaway;
	            if (typeof s.autoChatFlashSale === 'boolean') chatState.autoChatFlashSale = s.autoChatFlashSale;
	            if (typeof s.autoReminder === 'boolean') chatState.autoReminder = s.autoReminder;
	            if (s.reminderInterval) chatState.reminderInterval = parseInt(s.reminderInterval, 10) || 15;
	            if (typeof s.autoGiveaway === 'boolean') giveawayState.autoRequested = s.autoGiveaway;
	            if (['continuous', 'sequential', 'random'].includes(s.giveawayMode)) giveawayState.mode = s.giveawayMode;
	            if (s.giveawayIntervalMin !== undefined) giveawayState.intervalMin = lbNormalizeGiveawayDelayMin(s.giveawayIntervalMin);
	            if (s.giveawayDelayById && typeof s.giveawayDelayById === 'object') {
	                giveawayState.delayById = {};
	                Object.entries(s.giveawayDelayById).forEach(([id, min]) => {
	                    let val = lbNormalizeGiveawayDelayMin(min);
	                    giveawayState.delayById[String(id)] = val;
	                });
	            }
	            if (Array.isArray(s.giveawaySelectedIds)) giveawayState.selectedIds = new Set(s.giveawaySelectedIds.map(String));
	            if (typeof s.autoPinChatNotification === 'boolean') lv3State.autoChatPinNotification = s.autoPinChatNotification;

	            let setChecked = (id, val) => { let el = document.getElementById(id); if (el) el.checked = !!val; };
	            setChecked('lb-chat-pin', chatState.autoChatPin);
	            setChecked('lb-chat-giveaway', chatState.autoChatGiveaway);
	            setChecked('lb-chat-flash', chatState.autoChatFlashSale);
	            setChecked('lb-chat-reminder', chatState.autoReminder);
	            setChecked('lb-giveaway-auto', giveawayState.autoRequested);
	            setChecked('lb-autopin-toggle', !!s.autoPin);
	            setChecked('lb-pin-notif-toggle', lv3State.autoChatPinNotification);
	            setChecked('lb-pin-repeat', s.autoPinRepeat !== false);
	            let gwMode = document.getElementById('lb-giveaway-mode');
	            if (gwMode) gwMode.value = giveawayState.mode;
	            let gwInterval = document.getElementById('lb-giveaway-interval');
	            if (gwInterval) gwInterval.value = giveawayState.intervalMin;
	            let pinStrategy = document.getElementById('lb-pin-strategy');
	            if (pinStrategy && s.autoPinStrategy) pinStrategy.value = s.autoPinStrategy;
	            let pinDelay = document.getElementById('lb-pin-delay');
	            if (pinDelay && s.autoPinDelaySec) pinDelay.value = parseInt(s.autoPinDelaySec, 10) || 60;
	            let remInterval = document.getElementById('lb-chat-reminder-interval');
	            if (remInterval) remInterval.value = chatState.reminderInterval;

	            if (chatState.autoReminder && state.running) lbStartReminderTimerFromSettings();
	            else if (chatState.autoReminder) lbLog('⏰ Nhắc nhở đã lưu, chờ live bắt đầu', 'info');
		    if (giveawayState.autoRequested) {
		        giveawayState.autoEnabled = false;
		        if (state.running) lbStartGiveawayTimer();
		        else {
		            lbSetGiveawayStatus('Chờ live bắt đầu');
		        }
		    }
	            if (s.autoPin && state.running) lbStartAutoPin();
	            else if (s.autoPin) lbSetPinStatus('Chờ live bắt đầu');
	            return s;
	        } catch (e) {
	            console.warn('[STRANGE TTS] ops settings restore error:', e);
	            return {};
	        }
	    }

