    // ⚡ V3 Strategy Engine toggle
    function _updateStratToggleUI(on) {
        const lbl = document.getElementById('lb-strat-label');
        if (!lbl) return;
        lbl.style.background = on ? 'rgba(74,222,128,0.2)' : 'rgba(255,165,0,0.12)';
        lbl.style.borderColor = on ? 'rgba(74,222,128,0.5)' : 'rgba(255,165,0,0.3)';
        lbl.style.color = on ? '#4ADE80' : '#FFA500';
        // Update text node (last child after checkbox)
        const nodes = lbl.childNodes;
        for (let n of nodes) {
            if (n.nodeType === 3 && n.textContent.trim()) {
                n.textContent = on ? ' ⚡V3 ON' : ' ⚡V3';
                break;
            }
        }
    }

