            let now = new Date();
            let startEl = document.getElementById('lb-live-start');
            let endEl = document.getElementById('lb-live-end');
            let startStr = `${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;
            let end = new Date(now.getTime() + h * 3600000);
            let endStr = `${String(end.getHours()).padStart(2, '0')}:${String(end.getMinutes()).padStart(2, '0')}`;
            if (startEl) startEl.value = startStr;
            if (endEl) endEl.value = endStr;
            window.__STRANGETTS_LIVE_START_TIME__ = startStr;
            window.__STRANGETTS_LIVE_END_TIME__ = endStr;
