    // Dev rule scenario tester — build inside test tab
    (function buildDevRuleTest() {
        let testContent = document.querySelector('[data-htab-content="test"]');
        if (!testContent) return;

        // Add rule test section
        let ruleDiv = document.createElement('div');
        ruleDiv.style.cssText = 'margin-top:10px; padding:8px; background:rgba(248,113,113,0.08); border:1px solid rgba(248,113,113,0.2); border-radius:8px;';
        ruleDiv.innerHTML = `
            <div style="font-size:10px; color:#FCA5A5; font-weight:700; margin-bottom:6px;">🔧 DEV: Kích hoạt Rule trên Camp</div>
            <div style="font-size:8px; color:#888; margin-bottom:6px;">Chọn 1 camp từ checklist → bấm rule để test kịch bản tương ứng</div>
            <div id="lb-dev-rule-btns" style="display:grid; grid-template-columns:1fr 1fr; gap:4px;">
                <button data-rule="under_spend" style="background:rgba(251,146,60,0.15); color:#FB923C; border:1px solid rgba(251,146,60,0.3); border-radius:5px; padding:5px 4px; font-size:8px; cursor:pointer; font-weight:600;">📉 R2: Tiêu yếu<br><span style="font-size:7px;color:#888;">Giảm ROI</span></button>
                <button data-rule="live_issue" style="background:rgba(248,113,113,0.15); color:#F87171; border:1px solid rgba(248,113,113,0.3); border-radius:5px; padding:5px 4px; font-size:8px; cursor:pointer; font-weight:600;">🚨 R4: 0 đơn<br><span style="font-size:7px;color:#888;">Hold+Cảnh báo</span></button>
                <button data-rule="burning_budget" style="background:rgba(239,68,68,0.15); color:#EF4444; border:1px solid rgba(239,68,68,0.3); border-radius:5px; padding:5px 4px; font-size:8px; cursor:pointer; font-weight:600;">🔥 R10: Đốt NS<br><span style="font-size:7px;color:#888;">Tăng ROI</span></button>
                <button data-rule="weak_performance" style="background:rgba(251,146,60,0.15); color:#FB923C; border:1px solid rgba(251,146,60,0.3); border-radius:5px; padding:5px 4px; font-size:8px; cursor:pointer; font-weight:600;">⚠️ R5: ROI yếu<br><span style="font-size:7px;color:#888;">Tăng ROI nhẹ</span></button>
                <button data-rule="warming" style="background:rgba(74,222,128,0.15); color:#4ADE80; border:1px solid rgba(74,222,128,0.3); border-radius:5px; padding:5px 4px; font-size:8px; cursor:pointer; font-weight:600;">🌡️ R6: Ấm<br><span style="font-size:7px;color:#888;">Tăng NS nhẹ</span></button>
                <button data-rule="ready_to_scale" style="background:rgba(74,222,128,0.15); color:#22D3EE; border:1px solid rgba(74,222,128,0.3); border-radius:5px; padding:5px 4px; font-size:8px; cursor:pointer; font-weight:600;">🚀 R7: Scale<br><span style="font-size:7px;color:#888;">Tăng NS mạnh</span></button>
                <button data-rule="scale_strong" style="background:rgba(34,211,238,0.15); color:#22D3EE; border:1px solid rgba(34,211,238,0.3); border-radius:5px; padding:5px 4px; font-size:8px; cursor:pointer; font-weight:600;">💎 R8: Cực mạnh<br><span style="font-size:7px;color:#888;">NS+ROI</span></button>
                <button data-rule="evaluate_real" style="background:rgba(168,85,247,0.15); color:#C4B5FD; border:1px solid rgba(168,85,247,0.3); border-radius:5px; padding:5px 4px; font-size:8px; cursor:pointer; font-weight:600;">📐 Evaluate Real<br><span style="font-size:7px;color:#888;">Chạy rule thật</span></button>
            </div>
            <div id="lb-dev-rule-log" style="margin-top:6px; max-height:200px; overflow-y:auto; font-size:9px; color:#E8D5FF; background:rgba(0,0,0,0.4); border-radius:6px; padding:6px; font-family:monospace;"></div>
        `;
        testContent.appendChild(ruleDiv);

        let devLog = (msg, color) => {
            let el = document.getElementById('lb-dev-rule-log');
            if (el) {
                let time = new Date().toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
                el.innerHTML = `<div style="color:${color || '#E8D5FF'};margin-bottom:2px;">[${time}] ${msg}</div>` + el.innerHTML;
            }
        };

        // Mock camp data for each rule scenario
        function getMockCamp(rule, realCamp) {
            let base = { ...realCamp };
            let cfg = state._cfg || {};
            let targetRoi = parseFloat(String(realCamp.targetRoi || cfg.target_roi || '4').replace(/,/g, '.')) || 4;
            let budget = parseFloat(String(realCamp.budget || '0').replace(/\./g, '').replace(/,/g, '')) || 220000;

            switch (rule) {
                case 'under_spend': // R2: spend_rate < spend_rate_low
                    return { ...base, spend: String(Math.round(budget * 0.1)), orders: '2', roi: String(targetRoi * 1.2), _last_adjust_time: 0 };
                case 'live_issue': // R4: spend >= min but 0 orders
                    return { ...base, spend: String(Math.round(budget * 0.5)), orders: '0', roi: '0', _last_adjust_time: 0 };
                case 'burning_budget': // R10: high spend_rate + low roi_rate
                    return { ...base, spend: String(Math.round(budget * 0.85)), orders: '3', roi: String(targetRoi * 0.3), _last_adjust_time: 0 };
                case 'weak_performance': // R5: orders >= 1 but roi_rate < weak
                    return { ...base, spend: String(Math.round(budget * 0.5)), orders: '3', roi: String(targetRoi * 0.4), _last_adjust_time: 0 };
                case 'warming': // R6: roi near target
                    return { ...base, spend: String(Math.round(budget * 0.65)), orders: '5', roi: String(targetRoi * 0.8), _last_adjust_time: 0 };
                case 'ready_to_scale': // R7: roi >= good
                    return { ...base, spend: String(Math.round(budget * 0.72)), orders: '8', roi: String(targetRoi * 1.1), _last_adjust_time: 0 };
                case 'scale_strong': // R8: roi >= strong + high spend
                    return { ...base, spend: String(Math.round(budget * 0.85)), orders: '12', roi: String(targetRoi * 1.8), _last_adjust_time: 0 };
                default: return base;
            }
        }

        let _devRuleRunning = false;
        document.getElementById('lb-dev-rule-btns').addEventListener('click', async (e) => {
            let btn = e.target.closest('button');
            if (!btn) return;
            let rule = btn.getAttribute('data-rule');
            if (!rule) return;
            // Dedup guard — prevent double execution
            if (_devRuleRunning) { console.log('[STRANGE TTS] DEV rule already running, skip'); return; }
            _devRuleRunning = true;
            setTimeout(() => { _devRuleRunning = false; }, 3000);

            // Get selected camp
            let selectedId = null;
            for (let id of state.selectedCampIds) { selectedId = id; break; }
            let camp = state.camps?.find(c => String(c.id) === selectedId) || state.allCamps?.[0];
            if (!camp) { devLog('❌ Chưa có camp — bấm Quét trước!', '#F87171'); return; }

            let cfg = state._cfg || await strangettsGetLiveBetaConfig();
            let ruleConfig = await strangettsGetLiveAdjustConfig();
            devLog(`\n🔧 === TEST RULE: ${rule} trên [${camp.name?.substring(0, 30) || camp.id}] ===`, '#C4B5FD');

            if (rule === 'evaluate_real') {
                // Run real evaluation
                let result = evaluateLiveCamp(ruleConfig, { ...camp, _last_adjust_time: 0 });
                devLog(`📐 Real: ${result.emoji} ${result.status} → ${result.action}`, result.color);
                devLog(`📝 ${result.message}`, '#B8A0D8');
                if (result.new_budget) devLog(`💰 new_budget: ${strangettsShortVN(result.new_budget)}`, '#4ADE80');
                if (result.new_roi) devLog(`📊 new_roi: ${result.new_roi}`, '#FBBF24');
                devLog(`📊 metrics: spend=${strangettsShortVN(result.metrics.spend)} budget=${strangettsShortVN(result.metrics.budget)} roi=${result.metrics.roi} spend_rate=${result.metrics.spend_rate.toFixed(0)}% roi_rate=${result.metrics.roi_rate.toFixed(0)}%`, '#6B7280');
                return;
            }

            // Mock camp data for scenario
            let mockCamp = getMockCamp(rule, camp);
            devLog(`📋 Mock data: spend=${mockCamp.spend} orders=${mockCamp.orders} roi=${mockCamp.roi}`, '#6B7280');

            let result = evaluateLiveCamp(ruleConfig, { ...mockCamp, _last_adjust_time: 0, scheduleStart: new Date(Date.now() - 30 * 60000).toISOString() });
            devLog(`${result.emoji} Result: ${result.status} → action: ${result.action}`, result.color);
            devLog(`📝 ${result.message}`, '#B8A0D8');

            if (result.action !== 'hold') {
                devLog(`⚡ Sẽ gọi applyRuleAction...`, '#FBBF24');
                if (result.new_roi) devLog(`📊 Rule new_roi=${result.new_roi} | camp.targetRoi=${camp.targetRoi}`, '#67E8F9');
                if (result.new_budget) devLog(`💰 Rule new_budget=${strangettsShortVN(result.new_budget)} | camp.budget=${camp.budget}`, '#67E8F9');
                try {
                    let apiResult = await applyRuleAction(camp, result, cfg);
                    devLog(`✅ applyRuleAction trả về: ${apiResult}`, '#4ADE80');
                    devLog(`🔍 Check Console (F12) để xem chi tiết API request/response`, '#C4B5FD');
                } catch (e) {
                    devLog(`❌ applyRuleAction LỖI: ${e.message}`, '#F87171');
                    devLog(`📋 Stack: ${e.stack?.split('\n').slice(0, 3).join(' | ')}`, '#6B7280');
                }
            } else {
                devLog(`⏸ Action=hold — không có lệnh nào được gọi`, '#FBBF24');
            }
        });
    })();

    // Section collapse/expand handlers
    ['lb-s1-hdr', 'lb-s1-body', 'lb-s1-arrow',
        'lb-s2-hdr', 'lb-s2-body', 'lb-s2-arrow',
        'lb-s3-hdr', 'lb-s3-body', 'lb-s3-arrow'].forEach((_, i, arr) => {
            if (i % 3 !== 0) return;
            let hdrId = arr[i], bodyId = arr[i + 1], arrowId = arr[i + 2];
            document.getElementById(hdrId)?.addEventListener('click', (e) => {
                if (e.target.tagName === 'BUTTON') return;
                let body = document.getElementById(bodyId);
                let arrow = document.getElementById(arrowId);
                if (!body) return;
                let isHidden = body.style.display === 'none';
                body.style.display = isHidden ? 'block' : 'none';
                if (arrow) arrow.textContent = isHidden ? '▼' : '▶';
            });
        });

    // Camp list toggle (Danh sách camp LIVE)
    document.getElementById('lb-camplist-toggle')?.addEventListener('click', (e) => {
        if (e.target.tagName === 'BUTTON') return;
        let checklist = document.getElementById('lb-camp-checklist');
        let arrow = document.getElementById('lb-camplist-arrow');
        if (!checklist) return;
        let isHidden = checklist.style.display === 'none';
        checklist.style.display = isHidden ? 'block' : 'none';
        if (arrow) arrow.textContent = isHidden ? '▼' : '▶';
    });

    // Test section toggle
    document.getElementById('lb-test-toggle')?.addEventListener('click', () => {
        let body = document.getElementById('lb-test-body');
        let arrow = document.getElementById('lb-test-arrow');
        if (!body) return;
        let isHidden = body.style.display === 'none';
        body.style.display = isHidden ? 'block' : 'none';
        if (arrow) arrow.textContent = isHidden ? '▼' : '▶';
    });

    // Activity Log collapse
    document.getElementById('lb-log-hdr')?.addEventListener('click', (e) => {
        if (e.target.tagName === 'BUTTON') return;
        let logEl = document.getElementById('lb-log');
        let arrow = document.getElementById('lb-log-arrow');
        if (!logEl) return;
        let isHidden = logEl.style.display === 'none';
        logEl.style.display = isHidden ? 'block' : 'none';
        if (arrow) arrow.textContent = isHidden ? '▼' : '▶';
    });

    // ===== AI CHAT SECTION — Chat-style Render + Handlers =====
    // Collapse/expand
    document.getElementById('lb-gemini-hdr')?.addEventListener('click', (e) => {
        if (e.target.tagName === 'BUTTON') return;
        let body = document.getElementById('lb-gemini-body');
        let arrow = document.getElementById('lb-gemini-arrow');
        if (!body) return;
        let isHidden = body.style.display === 'none';
        body.style.display = isHidden ? 'block' : 'none';
        if (arrow) arrow.textContent = isHidden ? '▼' : '▶';
    });

    // Clear chat
    document.getElementById('lb-gemini-clear')?.addEventListener('click', (e) => {
        e.stopPropagation();
        window.__STRANGETTS_GEMINI_LOG__ = [];
        renderGeminiChat();
    });

    // Sanitize: remove API keys/tokens from text
    function geminiSanitize(text) {
        if (!text) return '';
        return text
            .replace(/AIzaSy[A-Za-z0-9_-]{33}/g, 'AIza***REDACTED***')
            .replace(/\d{9,10}:[A-Za-z0-9_-]{35}/g, '***BOT_TOKEN***')
            .replace(/key=[A-Za-z0-9_-]{30,}/g, 'key=***REDACTED***');
    }

    // Format time
    function gemFmtTime(ts) {
        let d = new Date(ts);
        return d.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    }

    // Confidence badge color
    function confColor(c) {
        if (c === 'high') return '#4ADE80';
        if (c === 'medium') return '#FBBF24';
        return '#F87171';
    }

    // Copy to clipboard helper
    function gemCopy(text, btn) {
        navigator.clipboard.writeText(text).then(() => {
            let orig = btn.textContent;
            btn.textContent = '✅';
            setTimeout(() => btn.textContent = orig, 1500);
        }).catch(() => { });
    }

    // Render chat-style Gemini messages
    function renderGeminiChat() {
        let logs = window.__STRANGETTS_GEMINI_LOG__ || [];
        let badge = document.getElementById('lb-gemini-badge');
        let lastEl = document.getElementById('lb-gemini-last');
        let chatEl = document.getElementById('lb-gemini-chat');
        if (!chatEl) return;

        // Update badge + header
        if (badge) badge.textContent = logs.length + ' calls';
        if (lastEl && logs.length > 0) {
            let last = logs[0];
            let icon = last.status === 'success' ? '✅' : last.status === 'error' ? '❌' : '⚠️';
            lastEl.textContent = `| ${icon} ${gemFmtTime(last.ts)}`;
        } else if (lastEl) { lastEl.textContent = ''; }

        if (logs.length === 0) {
            chatEl.innerHTML = '<div style="text-align:center; padding:20px 10px; color:#6B7280; font-size:10px;">Bấm <b style="color:#00C9FF;">🚀 Hỏi AI</b> để gửi data hiện tại cho Gemini phân tích</div>';
            return;
        }

        function geminiUiResults(entry) {
            if (entry?.parsedResult && entry.parsedResult.length > 0) return entry.parsedResult;
            try {
                return strangettsParseGeminiJsonArray(entry?.responseText || '');
            } catch (e) {
                return [];
            }
        }

        let html = '';
        // Show oldest first (reversed, logs are newest-first)
        let reversed = [...logs].reverse();
        reversed.forEach((entry, i) => {
            let idx = logs.length - 1 - i;
            // === USER BUBBLE (data gửi) ===
            html += `<div style="display:flex; justify-content:flex-end;">`;
            html += `<div style="max-width:85%; background:linear-gradient(135deg,rgba(0,201,255,0.15),rgba(124,58,237,0.12)); border:1px solid rgba(0,201,255,0.2); border-radius:12px 12px 2px 12px; padding:8px 10px;">`;
            html += `<div style="display:flex; align-items:center; gap:4px; margin-bottom:4px;">`;
            html += `<span style="color:#67E8F9; font-size:9px; font-weight:600;">📤 Data gửi AI</span>`;
            html += `<span style="color:#6B7280; font-size:8px;">${gemFmtTime(entry.ts)}</span>`;
            html += `<span style="background:rgba(34,211,238,0.15); color:#22D3EE; padding:0px 5px; border-radius:6px; font-size:7px; font-weight:600;">${entry.callSource || '?'}</span>`;
            html += `</div>`;
            // Compact data summary
            let camps = entry.inputData?.campaigns || [];
            if (camps.length > 0) {
                html += `<div style="font-size:8px; color:#B8A0D8; margin-bottom:2px;">📊 ${camps.length} campaigns:`;
                camps.forEach(c => {
                    html += `<div style="margin-left:6px; color:#E8D5FF;">• ${geminiSanitize((c.name || '').substring(0, 20))} — spend:${(c.spend || 0).toLocaleString()} | ROI:${(c.roi || 0).toFixed(1)} | đơn:${c.orders || 0}</div>`;
                });
                html += `</div>`;
            }
            if (entry.inputData?.liveMetrics) {
                let lm = entry.inputData.liveMetrics;
	                html += `<div style="font-size:8px; color:#22D3EE;">📺 Live: 👁 ${lm.current_viewers ?? lm.viewers ?? '—'} | ↗️ ${(lm.enter_rate ?? 0).toFixed(1)}% | GPM ${(lm.gpm_show ?? lm.gpm ?? 0).toLocaleString()} | 🛒 ${lm.total_orders ?? 0}</div>`;
	            }
	            if (entry.inputData?.products?.length) {
	                html += `<div style="font-size:8px; color:#FBBF24;">📦 Top SP gửi AI: ${entry.inputData.products.length}</div>`;
	            }
            if (entry.inputData?.engineState) {
                let es = entry.inputData.engineState;
                html += `<div style="font-size:8px; color:#C4B5FD;">🧠 Score:${es.score} | ${es.quality_gate} | ${es.engine_action}</div>`;
            }
            // Expand prompt button
            html += `<details style="margin-top:3px;"><summary style="color:#6B7280; font-size:8px; cursor:pointer;">📝 Xem prompt</summary>`;
            html += `<div style="font-size:7px; color:#9CA3AF; max-height:120px; overflow-y:auto; white-space:pre-wrap; word-break:break-word; margin-top:2px; background:rgba(0,0,0,0.2); padding:4px; border-radius:4px;">${geminiSanitize(entry.prompt)}</div>`;
            html += `</details>`;
            html += `</div></div>`;

            // === AI BUBBLE (response) ===
            html += `<div style="display:flex; justify-content:flex-start;">`;
            html += `<div style="max-width:85%; background:rgba(0,0,0,0.4); border:1px solid rgba(74,222,128,0.2); border-radius:12px 12px 12px 2px; padding:8px 10px;">`;
            // Header
            let statusIcon = entry.status === 'success' ? '✅' : entry.status === 'error' ? '❌' : '⚠️';
            html += `<div style="display:flex; align-items:center; gap:4px; margin-bottom:4px;">`;
	            html += `<span style="font-size:10px;">🤖</span>`;
	            html += `<span style="color:#86EFAC; font-size:9px; font-weight:600;">Gemini AI</span>`;
	            html += `<span style="color:#6B7280; font-size:8px;">${statusIcon} ${entry.durationMs}ms</span>`;
	            if (entry.modelUsed || entry.modelTried?.length) {
	                let modelNote = entry.modelUsed
	                    ? `model: ${strangettsGeminiModelLabel(entry.modelUsed)}`
	                    : `đã thử: ${entry.modelTried.map(strangettsGeminiModelLabel).join(' → ')}`;
	                html += `<span style="color:#67E8F9; font-size:8px;">${geminiSanitize(modelNote)}</span>`;
	            }
	            html += `<button class="gem-copy-resp" data-idx="${idx}" style="background:none; border:none; color:#6B7280; font-size:8px; cursor:pointer; padding:0;">📋</button>`;
            html += `</div>`;

            let displayResults = geminiUiResults(entry);
            if (entry.error && !entry.responseText) {
                html += `<div style="color:#FCA5A5; font-size:9px; background:rgba(248,113,113,0.1); padding:4px 6px; border-radius:6px;">❌ ${geminiSanitize(entry.error)}</div>`;
            } else if (displayResults.length > 0) {
                displayResults.forEach(r => {
                    let confBadge = r.confidence ? `<span style="color:${confColor(r.confidence)}; font-size:8px; font-weight:700;">[${r.confidence}]</span>` : '';
                    html += `<div style="background:rgba(74,222,128,0.08); border-radius:6px; padding:6px; margin-bottom:3px;">`;
                    html += `<div style="color:#67E8F9; font-size:10px; font-weight:600; margin-bottom:2px;">🎯 ${geminiSanitize(r.name || '')} ${confBadge}</div>`;
                    if (r.summary) html += `<div style="color:#E8D5FF; font-size:9px;">📝 ${geminiSanitize(r.summary)}</div>`;
                    if (r.risk) html += `<div style="color:#FCA5A5; font-size:9px;">⚠️ ${geminiSanitize(r.risk)}</div>`;
                    if (r.suggestion) html += `<div style="color:#86EFAC; font-size:9px;">💡 ${geminiSanitize(r.suggestion)}</div>`;
                    html += `</div>`;
                });
            } else if (entry.responseText) {
                html += `<div style="color:#E8D5FF; font-size:9px; background:rgba(34,211,238,0.08); padding:5px 6px; border-radius:6px; white-space:pre-wrap; word-break:break-word;">${geminiSanitize(entry.responseText).slice(0, 1200)}</div>`;
            } else {
                html += `<div style="color:#FBBF24; font-size:9px;">⚠️ AI không trả kết quả hợp lệ</div>`;
            }
            // Raw response expand
            html += `<details style="margin-top:3px;"><summary style="color:#6B7280; font-size:8px; cursor:pointer;">📥 Xem raw response</summary>`;
            html += `<div style="font-size:7px; color:#9CA3AF; max-height:100px; overflow-y:auto; white-space:pre-wrap; word-break:break-word; margin-top:2px; background:rgba(0,0,0,0.2); padding:4px; border-radius:4px;">${geminiSanitize(entry.responseText || 'Không có response')}</div>`;
            html += `</details>`;
            html += `</div></div>`;
        });

        chatEl.innerHTML = html;
        // Auto scroll to bottom
        chatEl.scrollTop = chatEl.scrollHeight;

        // Bind copy buttons
        chatEl.querySelectorAll('.gem-copy-resp').forEach(btn => {
            btn.onclick = (e) => {
                e.stopPropagation();
                let i = parseInt(btn.dataset.idx);
                let entry = (window.__STRANGETTS_GEMINI_LOG__ || [])[i];
                if (entry) gemCopy(entry.responseText || '', btn);
            };
        });
    }

    // 🚀 Nút Hỏi AI — gửi data hiện tại chủ động
    document.getElementById('lb-gemini-send')?.addEventListener('click', async () => {
        let btn = document.getElementById('lb-gemini-send');
        if (!btn || btn.disabled) return;

        // Save time inputs
        let startTimeInput = document.getElementById('lb-gemini-starttime');
        let endTimeInput = document.getElementById('lb-gemini-endtime');
        if (startTimeInput && startTimeInput.value) window.__STRANGETTS_LIVE_START_TIME__ = startTimeInput.value;
        if (endTimeInput && endTimeInput.value) window.__STRANGETTS_LIVE_END_TIME__ = endTimeInput.value;

        // Show session info preview
        if (startTimeInput?.value && endTimeInput?.value) {
            let [sh, sm] = startTimeInput.value.split(':').map(Number);
            let [eh, em] = endTimeInput.value.split(':').map(Number);
            let s = new Date(); s.setHours(sh, sm, 0, 0);
            let e = new Date(); e.setHours(eh, em, 0, 0);
            let remain = Math.max(0, Math.round((e - new Date()) / 60000));
            let el = document.getElementById('lb-gemini-session-info');
            if (el) el.textContent = `⏱ Còn ${remain}p`;
        }

        // Load config (same way as engine)
        let cfg = await strangettsGetLiveBetaConfig();
        if (!cfg.gemini_enabled || !cfg.gemini_api_key) {
            alert('Chưa bật Gemini AI hoặc chưa nhập API Key.\nVào Config → Bật Gemini để sử dụng.');
            return;
        }

        btn.disabled = true;
        btn.style.opacity = '0.5';
        btn.textContent = '⏳ Đang hỏi...';

        // Add loading bubble
        let chatEl = document.getElementById('lb-gemini-chat');
        let loadingId = 'gem-loading-' + Date.now();
        if (chatEl) {
            chatEl.insertAdjacentHTML('beforeend', `<div id="${loadingId}" style="display:flex; justify-content:flex-start;"><div style="background:rgba(0,0,0,0.4); border:1px solid rgba(74,222,128,0.2); border-radius:12px; padding:8px 14px;"><span style="color:#86EFAC; font-size:10px;">🤖 Đang suy nghĩ...</span></div></div>`);
            chatEl.scrollTop = chatEl.scrollHeight;
        }

        try {
            // Get current camps — try multiple sources
            let camps = window.__STRANGETTS_LIVE_CAMPS__ || [];
            if (camps.length === 0) camps = window.__STRANGETTS_CAMPS_CACHE__ || [];
	            if (camps.length === 0 && window.__STRANGETTS_LIVEBETA_STATE__?.camps) {
	                camps = window.__STRANGETTS_LIVEBETA_STATE__.camps;
	            }
	            let selectedIds = [...state.selectedCampIds].map(String);
	            if (selectedIds.length) {
	                let statePool = state.camps?.length ? state.camps : camps;
	                let selectedCamps = statePool.filter(c => selectedIds.includes(String(c.id)));
	                if (!selectedCamps.length && camps.length) selectedCamps = camps.filter(c => selectedIds.includes(String(c.id)));
	                if (selectedCamps.length) camps = selectedCamps;
	            }

	            let liveData = window.__STRANGETTS_LIVE_DASHBOARD__ || null;

	            // Engine state
	            let engineState = {};
	            if (camps?.length > 0 && typeof strangettsLiveScore === 'function') {
	                try {
	                    let sc = strangettsLiveScore(camps[0], liveData, cfg);
	                    engineState = { score: sc.totalScore, qualityGateBlocked: sc.qualityGateBlocked, action: sc.action, guardrailReason: sc.guardrailReason || '' };
	                } catch (e) { }
	            }

	            let result = await strangettsGeminiAnalyze(camps, liveData, cfg, engineState, 'manual', lbBuildGeminiExtraContext());
            // Remove loading
            document.getElementById(loadingId)?.remove();
            // Send to Telegram if enabled
	            if (result && result.length > 0 && cfg.telegram_enabled && cfg.telegram_bot_token) {
	                let teleMsg = `🤖 <b>AI Phân tích LIVE</b>\n`;
	                if (result._modelUsed) teleMsg += `🧠 Model: <b>${strangettsGeminiModelLabel(result._modelUsed)}</b>\n`;
	                result.forEach(r => {
                    let conf = r.confidence === 'high' ? '🟢' : r.confidence === 'medium' ? '🟡' : '🔴';
                    teleMsg += `\n${conf} <b>${r.name || ''}</b>\n`;
                    if (r.summary) teleMsg += `📝 ${r.summary}\n`;
                    if (r.risk) teleMsg += `⚠️ ${r.risk}\n`;
                    if (r.suggestion) teleMsg += `💡 ${r.suggestion}\n`;
                });
                try { await strangettsNotifySend(teleMsg, cfg); } catch (e) { }
            }
            // Render updated chat
            renderGeminiChat();
        } catch (e) {
            document.getElementById(loadingId)?.remove();
            renderGeminiChat();
        }

        btn.disabled = false;
        btn.style.opacity = '1';
        btn.textContent = '🚀 Hỏi AI';
    });

    // AI auto-call interval save handler
    document.getElementById('lb-ai-save-interval')?.addEventListener('click', async () => {
        let cfg = await strangettsGetLiveBetaConfig();
        let firstMin = parseInt(document.getElementById('lb-ai-first-min')?.value) || 30;
        let intervalMin = parseInt(document.getElementById('lb-ai-interval-min')?.value) || 20;
        cfg.sched_first_min = Math.max(1, firstMin);
        cfg.sched_interval_min = Math.max(1, intervalMin);
        strangettsSaveLiveBetaConfig(cfg);
        state._cfg = cfg;
        lbLog(`🤖 Đã lưu AI: Lần đầu ${cfg.sched_first_min}p, mỗi ${cfg.sched_interval_min}p`, 'success');
        // Visual feedback on button
        let saveBtn = document.getElementById('lb-ai-save-interval');
        if (saveBtn) {
            saveBtn.textContent = '✅ Đã lưu';
            saveBtn.style.background = 'rgba(74,222,128,0.3)';
            saveBtn.style.color = '#4ADE80';
            setTimeout(() => { saveBtn.textContent = 'Lưu'; saveBtn.style.background = 'rgba(0,201,255,0.2)'; saveBtn.style.color = '#67E8F9'; }, 1500);
        }
        lbUpdateAIAutoStatus();
    });

    // Restore AI interval values from config
    (async () => {
        let cfg = await strangettsGetLiveBetaConfig();
        let el1 = document.getElementById('lb-ai-first-min');
        let el2 = document.getElementById('lb-ai-interval-min');
        if (el1 && cfg.sched_first_min) el1.value = cfg.sched_first_min;
        if (el2 && cfg.sched_interval_min) el2.value = cfg.sched_interval_min;
    })();

    // Update AI auto-call status indicator periodically
    function lbUpdateAIAutoStatus() {
        let statusEl = document.getElementById('lb-ai-auto-status');
        if (!statusEl) return;
        let cfg = state._cfg || {};
        let engineRunning = state.running || !!state.pollTimer;
        let geminiEnabled = cfg.gemini_enabled && cfg.gemini_api_key;
        let firstMin = cfg.sched_first_min || 30;
        let intervalMin = cfg.sched_interval_min || 20;

        // Build multi-part status
        let parts = [];

        // Gemini config status
	        if (geminiEnabled) {
	            parts.push('<span style="color:#4ADE80;">🟢 Gemini ON</span>');
	            parts.push(`Model: <b style="color:#67E8F9;">${strangettsGeminiModelLabel(cfg.gemini_model)}</b>`);
	        } else {
            parts.push('<span style="color:#F87171;">🔴 Gemini OFF</span>');
        }

        // Engine status & countdown
        if (!engineRunning) {
            parts.push('⏸️ Engine chưa Start');
            parts.push(`Tự gọi: đầu ${firstMin}p, mỗi ${intervalMin}p <i style="color:#9CA3AF;">(sau khi bật Engine)</i>`);
        } else {
            let elapsed = state.startTime ? Math.floor((Date.now() - state.startTime) / 60000) : 0;
            let lastCall = state.lastScheduledTime ? Math.floor((Date.now() - state.lastScheduledTime) / 60000) : -1;
            let callCount = state.scheduledCount || 0;

            parts.push('<span style="color:#4ADE80;">▶ Engine ON</span>');

            if (geminiEnabled) {
                if (!state.firstScheduledDone) {
                    let remaining = Math.max(0, firstMin - elapsed);
                    parts.push(`⏳ Gọi lần đầu sau <b style="color:#67E8F9;">${remaining}p</b> (đã chạy ${elapsed}p)`);
                } else {
                    let remaining = Math.max(0, intervalMin - lastCall);
                    parts.push(`⏳ Gọi tiếp sau <b style="color:#67E8F9;">${remaining}p</b> | Đã gọi <b>${callCount}</b> lần`);
                }
            }
        }

        statusEl.innerHTML = parts.join(' · ');
    }
