    // ===== HELPERS =====
    function lbLogThrottled(key, msg, type = 'info', intervalMs = 60000) {
        let now = Date.now();
        window.__STRANGETTS_LB_LOG_THROTTLE__ = window.__STRANGETTS_LB_LOG_THROTTLE__ || {};
        let prev = window.__STRANGETTS_LB_LOG_THROTTLE__[key] || {};
        if (prev.msg === msg && now - (prev.ts || 0) < intervalMs) return false;
        window.__STRANGETTS_LB_LOG_THROTTLE__[key] = { ts: now, msg };
        lbLog(msg, type);
        return true;
    }

    function lbLog(msg, type = 'info') {
        let now = new Date();
        let ts = String(now.getHours()).padStart(2, '0') + ':' + String(now.getMinutes()).padStart(2, '0') + ':' + String(now.getSeconds()).padStart(2, '0');
        let colors = { info: '#B8A0D8', instant: '#FB923C', scheduled: '#22D3EE', error: '#F87171', success: '#4ADE80' };
        let entry = { ts: Date.now(), text: msg, type };
        state.log.unshift(entry);
        if (state.log.length > 50) state.log.length = 50;
        let logEl = document.getElementById('lb-log');
        if (logEl) {
            let div = document.createElement('div');
            div.style.cssText = `padding:2px 0; border-bottom:1px solid rgba(138,141,145,0.1); color:${colors[type] || colors.info};`;
            div.innerHTML = `<span style="color:#6B7280;">${ts}</span> ${msg}`;
            logEl.prepend(div);
            if (logEl.children.length > 50) logEl.lastChild.remove();
        }
        console.log(`[STRANGE TTS BETA] ${msg}`);
    }

    function lbUpdateMonitor() {
        let el = (id) => document.getElementById(id);
        el('lb-mon-poll').textContent = state.running ? `#${state.tickCount}` : '—';
	        el('lb-mon-instant').textContent = `${state.instantCount}/${(state._cfg || STRANGETTS_LIVEBETA_DEFAULTS).instant_max_per_session || 5}`;
        el('lb-mon-sched').textContent = String(state.scheduledCount);
        el('lb-mon-camps').textContent = `📺 ${state.selectedCampIds.size} camp theo dõi`;
        el('lb-status-dot').style.background = state.running ? '#4ADE80' : '#6B7280';

	        if (state.running && state.startTime) {
	            let elapsed = Math.floor((Date.now() - state.startTime) / 60000);
	            let elH = Math.floor(elapsed / 60), elM = elapsed % 60;
	            let timerStr = `⏱ ${elH}h${String(elM).padStart(2, '0')}p`;
	            let cfgMon = state._cfg || STRANGETTS_LIVEBETA_DEFAULTS;
	            let stratMon = !!(cfgMon.strat_enabled && state.strategy?.enabled);
	            let firstReviewMin = stratMon
	                ? Math.min(parseInt(cfgMon.sched_first_min, 10) || 30, parseInt(cfgMon.strat_first_review_min, 10) || 10)
	                : (parseInt(cfgMon.sched_first_min, 10) || 30);
	            let reviewIntervalMin = stratMon
	                ? Math.min(parseInt(cfgMon.sched_interval_min, 10) || 20, parseInt(cfgMon.strat_review_interval_min, 10) || 10)
	                : (parseInt(cfgMon.sched_interval_min, 10) || 20);
	            // Add LIVE duration from heartbeat if available
	            if (state._liveDuration > 0) {
	                let ld = state._liveDuration;
	                timerStr += ` | 📺 LIVE: ${Math.floor(ld / 3600)}h${String(Math.floor((ld % 3600) / 60)).padStart(2, '0')}p`;
	            }
	            if (!state.firstScheduledDone) {
	                let nextIn = Math.max(0, firstReviewMin - elapsed);
	                el('lb-mon-next').textContent = `${timerStr} | 📋 Review đầu: ${nextIn}p`;
	            } else {
	                let sinceLastSched = Math.floor((Date.now() - state.lastScheduledTime) / 60000);
	                let nextIn = Math.max(0, reviewIntervalMin - sinceLastSched);
	                el('lb-mon-next').textContent = `${timerStr} | 📋 Review tiếp: ${nextIn}p`;
	            }
        } else {
            el('lb-mon-next').textContent = '🕐 Chờ bắt đầu';
        }
    }

    function parseNum(v) {
        if (v == null) return 0;
        return parseFloat(String(v).replace(/\./g, '').replace(/,/g, '')) || 0;
    }
	    function parseRoi(v) {
	        if (v == null) return 0;
	        return parseFloat(String(v).replace(/,/g, '.')) || 0;
	    }

						    function lbGetMetricRoomId() {
						        return String(state._lockedRoomId || state._resultRoomId || state._liveRoomConfirmedRoomId || state._currentRoomId || lv3State.roomId || window.__STRANGETTS_AUTO_ROOM_ID__ || '').match(/\d{10,}/)?.[0] || '';
						    }

					    function lbPlainLiveAccountName() {
					        let label = '';
					        try { label = getLiveAccountLabel(); } catch (e) { label = ''; }
					        label = String(label || '').replace(/<[^>]+>/g, '').split('\n').map(s => s.trim()).find(Boolean) || '';
					        label = label.replace(/^📺\s*/u, '').trim();
					        return label || 'LIVE';
					    }

					    function lbParseLiveSessionTime(raw) {
					        raw = String(raw || '').trim();
					        if (!raw) return null;
					        let normalized = raw.replace(' ', 'T');
					        let d = new Date(normalized);
					        return Number.isFinite(d.getTime()) ? d : null;
					    }

					    function lbParseLiveDurationMs(text) {
					        let s = String(text || '').toLowerCase().trim();
					        if (!s) return 0;
					        let hh = 0, mm = 0, ss = 0;
					        let colon = s.match(/^(\d{1,2}):(\d{1,2})(?::(\d{1,2}))?$/);
					        if (colon) {
					            hh = parseInt(colon[1], 10) || 0;
					            mm = parseInt(colon[2], 10) || 0;
					            ss = parseInt(colon[3] || '0', 10) || 0;
					            return (hh * 3600 + mm * 60 + ss) * 1000;
					        }
					        let h = s.match(/(\d+)\s*(?:h|giờ|gio)/);
					        let m = s.match(/(\d+)\s*(?:p|phút|phut)/);
					        let sec = s.match(/(\d+)\s*(?:s|giây|giay)/);
					        if (h) hh = parseInt(h[1], 10) || 0;
					        if (m) mm = parseInt(m[1], 10) || 0;
					        if (sec) ss = parseInt(sec[1], 10) || 0;
					        if (!h && !m && !sec && /^\d+$/.test(s)) mm = parseInt(s, 10) || 0;
					        return (hh * 3600 + mm * 60 + ss) * 1000;
					    }

						    function lbResolveLiveDurationMs(session = null, opts = {}) {
						        let fromOpts = lbParseLiveDurationMs(opts.durationText || opts.liveDurationText || '');
						        if (fromOpts > 0) return fromOpts;
						        let fromState = Number(state._liveDuration || 0);
						        if (fromState > 0) return fromState * 1000;
						        let fromSessionText = lbParseLiveDurationMs(session?.durationText || session?.raw?.duration || '');
						        if (fromSessionText > 0) return fromSessionText;
						        let fromSession = Number(session?.duration || 0);
						        if (fromSession > 0) return fromSession * 1000;
						        let fromRuntime = Number(opts.runtimeMin || opts.runtimeMinutes || 0);
						        return fromRuntime > 0 ? fromRuntime * 60 * 1000 : 0;
						    }

						    function lbFormatLiveSourceTime(date, includeDate = false) {
						        if (!date || !Number.isFinite(date.getTime())) return '';
						        let hh = String(date.getHours()).padStart(2, '0');
					        let mm = String(date.getMinutes()).padStart(2, '0');
						        if (!includeDate) return `${hh}:${mm}`;
						        return `${String(date.getDate()).padStart(2, '0')}/${String(date.getMonth() + 1).padStart(2, '0')} ${hh}:${mm}`;
						    }

						    function lbFormatLiveSourceDate(date) {
						        if (!date || !Number.isFinite(date.getTime())) return '';
						        return `${String(date.getDate()).padStart(2, '0')}/${String(date.getMonth() + 1).padStart(2, '0')}`;
						    }

						    function lbBuildLiveSessionSourceLabel(summary = {}, opts = {}) {
						        let session = summary.primarySession || state._currentRoomSession || null;
						        let shopName = lbPlainLiveAccountName();
						        let start = lbParseLiveSessionTime(session?.launchedTime);
					        let durationMs = lbResolveLiveDurationMs(session, opts);
					        let end = null;
					        if (start && durationMs > 0) {
					            end = new Date(start.getTime() + durationMs);
					        } else if (durationMs > 0) {
					            end = opts.endedAt instanceof Date ? opts.endedAt : new Date();
					            start = new Date(end.getTime() - durationMs);
					        } else if (start) {
					            end = opts.endedAt instanceof Date ? opts.endedAt : new Date();
						        }
						        if (start && end) {
						            let sameDay = strangettsDateVN(start) === strangettsDateVN(end);
						            if (sameDay) {
						                return `phiên live của ${shopName} lúc ${lbFormatLiveSourceTime(start)} - ${lbFormatLiveSourceTime(end)} ngày ${lbFormatLiveSourceDate(end)}`;
						            }
						            return `phiên live của ${shopName} từ ${lbFormatLiveSourceTime(start, true)} đến ${lbFormatLiveSourceTime(end, true)}`;
						        }
						        return `phiên live của ${shopName}`;
						    }

			    function lbCollectRoomSessionMetrics(roomId = '') {
			        let cleanRoomId = String(roomId || '').match(/\d{10,}/)?.[0] || '';
			        let sessions = [];
		        let seen = new Set();
		        let pushSession = (s) => {
		            if (!s) return;
		            if (cleanRoomId && String(s.roomId || '') !== cleanRoomId) return;
		            let key = `${s.campaignId || ''}|${s.roomId || ''}|${s.launchedTime || ''}|${s.spend || 0}|${s.gmv || 0}|${s.orders || 0}`;
		            if (seen.has(key)) return;
		            seen.add(key);
		            sessions.push(s);
		        };
		        if (state._currentRoomSession) pushSession(state._currentRoomSession);
		        for (let c of (state.camps || [])) {
		            if (!state.selectedCampIds.has(String(c.id))) continue;
		            pushSession(c.__roomSession);
		        }
		        let totalSpend = 0, totalGmv = 0, totalOrders = 0;
			        for (let s of sessions) {
			            totalSpend += Number(s.spend || 0);
			            totalGmv += Number(s.gmv || 0);
			            totalOrders += Number(s.orders || 0);
			        }
			        sessions.sort((a, b) => strangettsRoomSessionTimeMs(b) - strangettsRoomSessionTimeMs(a));
			        let roi = totalSpend > 0 ? totalGmv / totalSpend : 0;
			        let cpo = totalOrders > 0 ? totalSpend / totalOrders : 0;
			        return {
			            spend: totalSpend,
		            gmv: totalGmv,
		            orders: Math.round(totalOrders),
			            roi,
			            cpo,
			            sessionCount: sessions.length,
			            primarySession: sessions[0] || null,
			            roomId: cleanRoomId,
			            hasAny: sessions.length > 0 && (totalSpend > 0 || totalGmv > 0 || totalOrders > 0),
			            source: sessions.length > 0 ? 'phiên live hiện tại' : 'chưa khớp phiên live'
			        };
			    }

		    async function lbRefreshResultRoomMetricsForSummary() {
		        let roomId = lbGetMetricRoomId();
		        if ((!Array.isArray(state.camps) || !state.camps.length) && (!Array.isArray(state.allCamps) || !state.allCamps.length)) return 0;
		        try {
		            let exactApplied = roomId ? await lbFetchExactRoomMetricsForSummary(roomId, {
		                daysBack: 35,
		                pageSize: 50,
		                log: false
		            }) : 0;
		            if (exactApplied > 0) {
		                lbLog(`📊 Tổng kết lấy trực tiếp post_room_list theo room ${String(roomId).slice(-8)}`, 'success');
		                return exactApplied;
		            }
		            if (roomId) {
		                let currentApplied = await lbApplyCurrentRoomMetricsToCamps(state.camps, roomId, {
		                    force: true,
		                    cacheTtlMs: 0,
		                    allowHistory: true
		                });
		                if (currentApplied > 0) return currentApplied;
		                lbLog(`⚠️ Tổng kết không tìm thấy số liệu cho room đã khóa ${String(roomId).slice(-8)}; không fallback sang room/camp khác để tránh báo sai`, 'error');
		                return 0;
		            }
		            let activeApplied = await lbApplyActiveRoomMetricsToCamps(state.camps, {
	                force: true,
	                cacheTtlMs: 0,
	                selectedOnly: true,
	                activeOnly: false,
	                persistRoom: true,
	                log: false
	            });
	            if (activeApplied.applied > 0) {
	                lbLog('📊 Tổng kết dùng room live_status=1 từ post_room_list', 'success');
	                return activeApplied.applied;
	            }
	            let latestApplied = await lbApplyLatestRoomMetricsToSelectedCamps(state.camps, {
	                force: true,
	                cacheTtlMs: 0,
			                daysBack: 35,
			                pageSize: 10,
			                persistRoom: true,
			                log: false
			            });
			            if (latestApplied > 0) {
			                lbLog('📊 Tổng kết dùng số liệu room mới nhất từ post_room_list của camp đã chọn', 'success');
			            }
			            if (latestApplied > 0) return latestApplied;
			            return roomId
			                ? await lbApplyCurrentRoomMetricsToCamps(state.camps, roomId, { force: true, cacheTtlMs: 0, allowHistory: true })
			                : 0;
			        } catch (e) {
			            lbLog(`⚠️ Không refresh được số liệu room trước khi tổng kết: ${e.message}`, 'error');
			            return 0;
			        }
			    }

		    function lbGetLiveResultSummary(liveData = null) {
		        let roomSummary = lbCollectRoomSessionMetrics(lbGetMetricRoomId());
		        if (roomSummary.sessionCount > 0) return roomSummary;
		        return {
		            spend: 0,
		            gmv: 0,
		            orders: 0,
			            roi: 0,
			            cpo: 0,
			            hasAny: false,
			            source: 'chưa khớp phiên live',
			            roomId: lbGetMetricRoomId(),
			            warning: 'Chưa khớp được room_id với phiên Ads hiện tại nên không dùng tổng camp/ngày để tránh báo sai.'
			        };
			    }

				    function lbLiveResultLines(liveData = null, opts = {}) {
				        let s = lbGetLiveResultSummary(liveData);
				        let source = lbBuildLiveSessionSourceLabel(s, opts);
				        if (!s.hasAny) {
				            return `🧾 Nguồn số liệu: <b>${source}</b>\n⚠️ ${s.warning || 'Chưa có số liệu phiên live chính xác.'}\n`;
				        }
				        let lines = [
				            `🧾 Nguồn số liệu: <b>${source}</b>`,
			            `💰 Doanh thu: <b>${s.gmv > 0 ? strangettsFormatVN(s.gmv) : '—'}</b>`,
			            `📦 Đơn hàng: <b>${s.orders > 0 ? strangettsFormatVN(s.orders) : '0'}</b>`,
			            `💸 Chi phí ads: <b>${s.spend > 0 ? strangettsFormatVN(s.spend) : '—'}</b>`,
	            `📈 ROI cuối (doanh thu/chi phí): <b>${s.roi > 0 ? s.roi.toFixed(2) : '—'}</b>`
	        ];
	        if (s.cpo > 0) lines.push(`🎯 Chi phí/đơn: <b>${strangettsFormatVN(s.cpo)}</b>`);
	        return lines.join('\n') + '\n';
	    }

	    function lbCampActualMetricLines(camp, title = 'Số liệu hiện tại') {
	        if (!camp) return '';
	        let spend = parseNum(camp.spend);
	        let gmv = parseNum(camp.gmv);
	        let orders = parseInt(String(camp.orders || '0').replace(/\D/g, ''), 10) || 0;
	        let roi = parseRoi(camp.roi);
	        if (!roi && spend > 0 && gmv > 0) roi = gmv / spend;
	        let cpo = parseNum(camp.cpo);
	        if (!cpo && spend > 0 && orders > 0) cpo = spend / orders;
	        let source = camp.__metricSource === 'room_id' ? 'phiên live hiện tại' : 'camp hiện tại';
	        return [
	            `📊 <b>${title}</b> (${source})`,
	            `💰 Doanh thu: <b>${gmv > 0 ? strangettsFormatVN(gmv) : '0'}</b>`,
	            `📦 Đơn hàng: <b>${orders > 0 ? strangettsFormatVN(orders) : '0'}</b>`,
	            `💸 Chi phí ads: <b>${spend > 0 ? strangettsFormatVN(spend) : '0'}</b>`,
	            `📈 ROI: <b>${roi > 0 ? roi.toFixed(2) : '—'}</b>`,
	            `🎯 Chi phí/đơn: <b>${cpo > 0 ? strangettsFormatVN(cpo) : '—'}</b>`
	        ].join('\n');
	    }

			    function lbBuildLiveEndSummaryMessage(liveData = null, opts = {}) {
			        let s = lbGetLiveResultSummary(liveData);
			        let runtime = opts.runtimeMin != null ? opts.runtimeMin : (state.startTime ? Math.round((Date.now() - state.startTime) / 60000) : 0);
				        let roomId = String(opts.roomId || lbGetMetricRoomId() || '');
				        let source = lbBuildLiveSessionSourceLabel(s, opts);
	        let campNames = (state.camps || [])
	            .filter(c => state.selectedCampIds.has(String(c.id)))
	            .map(c => (c.name || c.id || '').substring(0, 45))
	            .filter(Boolean)
	            .slice(0, 3);
	        let msg = `${getLiveAccountLabel()}\n📊 <b>TỔNG KẾT PHIÊN LIVE</b>\n━━━━━━━━━━━━\n`;
	        msg += `🧾 Nguồn số liệu: <b>${source}</b>\n`;
	        if (roomId) msg += `🔑 Room: <b>${roomId.slice(-8)}</b>\n`;
	        if (campNames.length) msg += `🎯 Camp: <b>${campNames.join(' | ')}</b>\n`;
	        msg += `⏱ Thời gian theo dõi: <b>${runtime} phút</b>`;
	        if (opts.durationText) msg += ` | Thời lượng live: <b>${opts.durationText}</b>`;
	        msg += `\n`;
	        msg += `💰 Doanh thu: <b>${s.gmv > 0 ? strangettsFormatVN(s.gmv) : '0'}</b>\n`;
	        msg += `📦 Đơn hàng: <b>${s.orders > 0 ? strangettsFormatVN(s.orders) : '0'}</b>\n`;
	        msg += `💸 Chi phí ads: <b>${s.spend > 0 ? strangettsFormatVN(s.spend) : '0'}</b>\n`;
	        msg += `📈 ROI: <b>${s.roi > 0 ? s.roi.toFixed(2) : '—'}</b>\n`;
	        msg += `🎯 Chi phí/đơn: <b>${s.cpo > 0 ? strangettsFormatVN(s.cpo) : '—'}</b>\n`;
	        msg += `🔁 Số lần quét: ${state.tickCount} | Điều chỉnh nhanh: ${state.instantCount} | Đánh giá định kỳ: ${state.scheduledCount}`;
	        return msg;
	    }

	    async function lbSendLiveEndSummaryOnly(cfg, opts = {}) {
	        let roomId = String(opts.roomId || lbGetMetricRoomId() || 'unknown');
	        if (!lbHasLiveSummaryEvidence(roomId)) {
	            lbLog('📊 Bỏ qua kênh tổng kết riêng: chưa có bằng chứng phiên live thật/camp đã chạy', 'info');
	            return false;
	        }
	        if (state._liveSummarySentRoomId === roomId) return false;
	        await lbRefreshResultRoomMetricsForSummary();
	        let liveData = cfg?.data_live_dash_enabled ? (window.__STRANGETTS_LIVE_DASHBOARD__ || null) : null;
	        let msg = lbBuildLiveEndSummaryMessage(liveData, { ...opts, roomId });
	        let sent = await strangettsSendLiveSummaryChannel(msg, cfg);
	        if (sent) {
	            state._liveSummarySentRoomId = roomId;
	            state._liveSummarySentAt = Date.now();
	            lbLog('📊 Đã gửi tổng kết phiên live vào kênh riêng', 'success');
	        }
	        return sent;
	    }

			    function lbGetConfiguredTargetRoi(cfg) {
		        let uiRoi = parseFloat(String(document.getElementById('lb-min-roi')?.value || '0').replace(/,/g, '.')) || 0;
		        let configured = parseFloat(cfg?.strat_target_roi) || parseFloat(cfg?.min_roi_total) || uiRoi || 0;
		        if (state.strategy?.enabled && state.strategy.target_roi > 0) configured = state.strategy.target_roi;
		        return configured > 0 ? Math.max(5, configured) : 5;
		    }

	    function lbGetCurrentBidRoi(camp) {
	        return parseRoi(
	            window.__STRANGETTS_DETAIL_CACHE__?.[String(camp.id)]?.ad_info?.roas_bid ||
	            window.__STRANGETTS_DETAIL_CACHE__?.[String(camp.id)]?.campaign_info?.roas_bid ||
		            camp.targetRoi ||
		            camp.raw?.template_ad_roas_bid
	        );
	    }

	    function lbGetConfiguredSessionBudget(cfg) {
	        let uiBudget = parseNum(document.getElementById('lb-max-budget')?.value || 0);
	        let configured = parseNum(cfg?.strat_target_budget) || parseNum(cfg?.max_budget_cap) || uiBudget || 0;
	        return configured > 0 ? configured : LIVE_START_BASELINE_BUDGET;
	    }

	    function lbGetConfiguredSessionRoi(cfg, fallback = LIVE_START_BASELINE_ROI) {
	        let uiRoi = parseFloat(String(document.getElementById('lb-min-roi')?.value || '0').replace(/,/g, '.')) || 0;
	        let configured = parseFloat(cfg?.strat_target_roi) || parseFloat(cfg?.min_roi_total) || uiRoi || 0;
	        return configured > 0 ? configured : fallback;
	    }

	    function lbParseLiveMoneyInput(value, fallback = 0) {
	        if (typeof value === 'number') return Number.isFinite(value) ? value : fallback;
	        let raw = String(value ?? '').trim().toLowerCase();
	        if (!raw) return fallback;
	        let unit = raw.match(/(tr|triệu|trieu|m|k)\b/)?.[1] || '';
	        let num = parseFloat(raw.replace(/\./g, '').replace(/,/g, '.').replace(/[^\d.]/g, ''));
	        if (!Number.isFinite(num) || num <= 0) return fallback;
	        if (unit === 'k') return num * 1000;
	        if (['tr', 'triệu', 'trieu', 'm'].includes(unit)) return num * 1000000;
	        return num;
	    }

	    function lbGetConfiguredInitialBudget(cfg) {
	        let configured = lbParseLiveMoneyInput(cfg?.strat_initial_budget, 0);
	        return configured > 0 ? configured : LIVE_START_BASELINE_BUDGET;
	    }

	    function lbGetConfiguredInitialRoi(cfg, fallback = LIVE_START_BASELINE_ROI) {
	        let configured = parseFloat(String(cfg?.strat_initial_roi || '').replace(/,/g, '.')) || 0;
	        return configured > 0 ? Math.max(0.1, Math.min(20, configured)) : fallback;
	    }

	    function lbGetConfiguredInitialWindowMin(cfg) {
	        return Math.max(1, parseInt(cfg?.strat_initial_window_min, 10) || 30);
	    }

	    function lbParseManualStrategyPlan(cfg) {
	        if (!cfg?.strat_manual_plan_enabled) return [];
	        let text = String(cfg.strat_manual_plan || '').trim();
	        if (!text) return [];
	        let steps = [];
	        text.split(/\n|;/).forEach((line, idx) => {
	            let clean = String(line || '').trim();
	            if (!clean || clean.startsWith('#')) return;
	            let tokens = clean.match(/\d+(?:[.,]\d+)?\s*(?:tr|triệu|trieu|m|k|đ|vnd)?/gi) || [];
	            if (tokens.length < 3) return;
	            let minute = parseFloat(String(tokens[0]).replace(/,/g, '.')) || 0;
	            let roi = parseFloat(String(tokens[1]).replace(/,/g, '.').replace(/[^\d.]/g, '')) || 0;
	            let budget = lbParseLiveMoneyInput(tokens[2], 0);
	            if (minute < 0 || roi <= 0 || budget <= 0) return;
	            steps.push({
	                minute,
	                roi: Math.max(0.1, Math.min(20, Math.round(roi * 10) / 10)),
	                budget: Math.ceil(budget / 1000) * 1000,
	                key: `${idx}:${minute}:${roi}:${Math.ceil(budget / 1000) * 1000}`
	            });
	        });
	        return steps.sort((a, b) => a.minute - b.minute);
	    }

	    function lbGetDueManualStrategyDecision(camp, cfg, strategy) {
	        if (!camp || !strategy?.enabled) return null;
	        let steps = lbParseManualStrategyPlan(cfg);
	        if (!steps.length) return null;
	        strategy.manual_adjust_applied = strategy.manual_adjust_applied || {};
	        let elapsedMin = Math.max(0, (Date.now() - (strategy.live_start || Date.now())) / 60000);
	        let due = steps.filter(step => step.minute <= elapsedMin && !strategy.manual_adjust_applied[step.key]);
	        if (!due.length) return null;
	        let step = due[due.length - 1];
	        let currentBudget = parseNum(camp.budget);
	        let currentRoi = lbGetCurrentBidRoi(camp) || parseFloat(String(camp.targetRoi || '0').replace(/,/g, '.')) || 0;
	        let allowBudgetDecrease = cfg.no_decrease_budget === false;
	        let writeBudget = Math.abs(currentBudget - step.budget) > 1000 && (step.budget > currentBudget || allowBudgetDecrease);
	        let writeRoi = Math.abs(currentRoi - step.roi) > 0.11;
	        let skipped = due.filter(s => s.key !== step.key).map(s => s.key);
	        if (!writeBudget && !writeRoi) {
	            [...skipped, step.key].forEach(key => { strategy.manual_adjust_applied[key] = Date.now(); });
	            return {
	                phase: 'MANUAL',
	                action: 'evaluate_only',
	                new_budget: null,
	                new_roi: null,
	                write_budget: false,
	                write_roi: false,
	                extend_budget_cap: 0,
	                emoji: '📋',
	                reason: `Mốc ${step.minute}p đã đúng: NS ${strangettsShortVN(currentBudget)}, ROI ${currentRoi || '-'}`,
	                metrics_snapshot: {},
	                manual_key: step.key,
	                manual_mark_keys: skipped
	            };
	        }
	        return {
	            phase: 'MANUAL',
	            action: writeBudget && writeRoi ? 'manual_budget_and_roi' : writeBudget ? 'manual_budget' : 'manual_roi',
	            new_budget: writeBudget ? step.budget : null,
	            new_roi: writeRoi ? step.roi : null,
	            write_budget: writeBudget,
	            write_roi: writeRoi,
	            extend_budget_cap: Math.max(0, step.budget - (strategy.budget_cap || 0)),
	            emoji: '📋',
	            reason: `Mốc thủ công ${step.minute}p: set NS ${strangettsShortVN(step.budget)} / ROI ${step.roi}`,
	            metrics_snapshot: {},
	            manual_key: step.key,
	            manual_mark_keys: skipped
	        };
	    }

	    function lbGetCampDaySpend(camp) {
	        return parseNum(camp?.__dayMetrics?.spend ?? camp?.spend);
	    }

	    async function lbRefreshCampDetailForBid(camp, force = false) {
		        let id = String(camp.id);
		        let currentRoi = lbGetCurrentBidRoi(camp);
		        if (!force && currentRoi > 0) return currentRoi;
		        try {
		            await fetchAdIdForCampaign(id, force);
		            currentRoi = lbGetCurrentBidRoi(camp);
		        } catch (e) {
		            console.warn('[STRANGE TTS] Could not refresh camp detail for ROI ramp:', e.message);
		        }
		        return currentRoi;
		    }

		    function lbBuildBudgetRoiRamp(camp, cfg) {
		        let targetRoi = lbGetConfiguredTargetRoi(cfg);
		        let currentRoi = lbGetCurrentBidRoi(camp);
		        if (!targetRoi || !currentRoi || currentRoi >= targetRoi - 0.05) return null;

	        let startTs = state.strategy?.live_start || state.startTime || Date.now();
	        if (cfg?.live_start_time && !state.strategy?.live_start) {
	            let parts = String(cfg.live_start_time).split(':').map(Number);
	            if (parts.length >= 2 && !isNaN(parts[0]) && !isNaN(parts[1])) {
	                let d = new Date();
	                d.setHours(parts[0], parts[1], 0, 0);
	                startTs = d.getTime();
	            }
	        }
	        let elapsedMin = Math.max(0, (Date.now() - startTs) / 60000);
	        let progress = Math.min(1, elapsedMin / 120);
	        let rampBase = LIVE_START_BASELINE_ROI + (targetRoi - LIVE_START_BASELINE_ROI) * progress;
	        let desired = Math.max(rampBase, currentRoi + 0.1);
	        let nextRoi = Math.min(targetRoi, Math.round(desired * 10) / 10);
	        if (nextRoi <= currentRoi + 0.05) return null;
	        return { oldRoi: Math.round(currentRoi * 10) / 10, newRoi: nextRoi, targetRoi, elapsedMin: Math.round(elapsedMin) };
	    }

	    // ===== SNAPSHOT BUFFER =====
	    function addSnapshot(camp) {
        let id = String(camp.id);
        if (!state.snapshots[id]) state.snapshots[id] = [];
        state.snapshots[id].push({
            ts: Date.now(),
            spend: parseNum(camp.spend),
            orders: parseInt(String(camp.orders || '0').replace(/\D/g, '')) || 0,
            gmv: parseNum(camp.gmv),
            budget: parseNum(camp.budget),
            roi: parseRoi(camp.roi),
            targetRoi: parseRoi(camp.targetRoi),
            status: camp.status || '',
        });
        if (state.snapshots[id].length > MAX_SNAPSHOTS) state.snapshots[id].shift();
    }

    function getWindow(campId, minutes) {
        let snaps = state.snapshots[String(campId)] || [];
        if (snaps.length < 2) return null;
        let cutoff = Date.now() - minutes * 60000;
        let oldest = snaps.find(s => s.ts >= cutoff) || snaps[0];
        let latest = snaps[snaps.length - 1];
        if (oldest === latest) return null;
        let dt = (latest.ts - oldest.ts) / 60000; // minutes elapsed
        if (dt < 0.1) return null;
        return {
            deltaSpend: latest.spend - oldest.spend,
            deltaOrders: latest.orders - oldest.orders,
            deltaGmv: latest.gmv - oldest.gmv,
            spendPerMin: (latest.spend - oldest.spend) / dt,
            ordersPerMin: (latest.orders - oldest.orders) / dt,
            latestSpendRate: latest.budget > 0 ? (latest.spend / latest.budget) * 100 : 0,
            latestRoiRate: latest.targetRoi > 0 ? (latest.roi / latest.targetRoi) * 100 : 0,
            latest, oldest, dt,
        };
    }

    // ===== INSTANT TRIGGER ENGINE =====
    async function checkInstantTriggers(cfg, camp) {
        if (!cfg.instant_enabled) return null;
        let id = String(camp.id);
        let snaps = state.snapshots[id] || [];
        if (snaps.length < 2) return null;

        let latest = snaps[snaps.length - 1];
        let spendRate = latest.budget > 0 ? (latest.spend / latest.budget) * 100 : 0;
        let roiRate = latest.targetRoi > 0 ? (latest.roi / latest.targetRoi) * 100 : 0;

        // Cooldown check
        let lastInstant = state.lastInstantTime[id] || 0;
        if (Date.now() - lastInstant < cfg.instant_cooldown_min * 60000) return null;

        // Session limit
        if (state.instantCount >= cfg.instant_max_per_session) return null;

        // Trigger 2 (higher priority) — Critical budget
        if (spendRate >= cfg.instant_spend_rate_2 && roiRate >= cfg.instant_roi_rate_2) {
            return {
                trigger: 'budget_critical',
                addBudget: Math.min(cfg.instant_budget_add_2, cfg.instant_max_per_action),
                reason: `💥 NS cạn (${spendRate.toFixed(0)}%) + ROI mạnh (${roiRate.toFixed(0)}%)`,
            };
        }

        // Trigger 1 — Budget approaching limit
        if (spendRate >= cfg.instant_spend_rate_1 && roiRate >= cfg.instant_roi_rate_1) {
            return {
                trigger: 'budget_low',
                addBudget: Math.min(cfg.instant_budget_add_1, cfg.instant_max_per_action),
                reason: `⚠️ NS sắp hết (${spendRate.toFixed(0)}%) + ROI ổn (${roiRate.toFixed(0)}%)`,
            };
        }

        // Trigger 3 — Burst orders
        let w5 = getWindow(id, cfg.window_medium_min);
        if (w5 && w5.deltaOrders >= cfg.burst_orders_threshold
            && w5.latestRoiRate >= 100
            && w5.latestSpendRate >= cfg.burst_spend_rate_min) {
            return {
                trigger: 'burst_orders',
                addBudget: Math.min(cfg.instant_budget_add_1, cfg.instant_max_per_action),
                reason: `🔥 Bùng đơn (+${w5.deltaOrders} đơn/${cfg.window_medium_min}p) + NS ${w5.latestSpendRate.toFixed(0)}%`,
            };
        }

        // Trigger 4 — Spend velocity surge
        let w3a = getWindow(id, cfg.window_short_min);
        if (w3a && snaps.length > 12) { // need enough data
            let midpoint = Math.floor(snaps.length / 2);
            let olderSlice = snaps.slice(0, midpoint);
            let newerSlice = snaps.slice(midpoint);
            if (olderSlice.length > 1 && newerSlice.length > 1) {
                let olderRate = (olderSlice[olderSlice.length - 1].spend - olderSlice[0].spend);
                let newerRate = (newerSlice[newerSlice.length - 1].spend - newerSlice[0].spend);
                if (olderRate > 0 && newerRate > olderRate * (1 + cfg.burst_spend_velocity_pct / 100) && w3a.latestRoiRate >= 100) {
                    return {
                        trigger: 'spend_surge',
                        addBudget: Math.min(cfg.instant_budget_add_1, cfg.instant_max_per_action),
                        reason: `📈 Spend tăng vọt (+${((newerRate / olderRate - 1) * 100).toFixed(0)}%) + ROI ổn`,
                    };
                }
            }
        }

        return null;
    }

    // ===== SCHEDULED REVIEW =====
    function checkScheduledReview(cfg, camp) {
        // Reuse existing evaluateLiveCamp if available
        if (typeof evaluateLiveCamp === 'function') {
            return evaluateLiveCamp(cfg, camp);
        }
        return { status: 'hold', action: 'hold', message: 'Không có rule engine' };
    }

    // ===== APPLY ACTION =====
    async function applyBudgetIncrease(camp, addAmount, reason, opts = {}) {
        let id = String(camp.id);
        let currentBudget = parseNum(camp.budget);
        let newBudget = currentBudget + addAmount;
        let cfg = state._cfg || await strangettsGetLiveBetaConfig();
        let strategyMode = !!(state.strategy?.enabled || cfg.strat_enabled);
        let hardBudgetCap = strategyMode ? (parseInt(cfg.strat_safety_cap, 10) || 0) : (cfg.max_budget_cap || 0);

        // === GUARD: Max Budget Cap ===
        if (hardBudgetCap > 0 && newBudget > hardBudgetCap) {
            if (currentBudget >= hardBudgetCap) {
                lbLog(`🛑 ${camp.name?.substring(0, 25) || id}: NS đã đạt giới hạn ${strangettsShortVN(hardBudgetCap)} — BỎ QUA`, 'error');
                return false;
            }
            // Cap to max
            newBudget = hardBudgetCap;
            addAmount = newBudget - currentBudget;
            lbLog(`⚠️ Cap NS tối đa: +${strangettsShortVN(addAmount)} → ${strangettsShortVN(newBudget)}`, 'info');
        }

        // === GUARD: Min ROI Total ===
        if (!strategyMode && cfg.min_roi_total > 0) {
            // Calculate weighted average ROI across all tracked camps
            let totalSpend = 0, totalGmv = 0;
            for (let c of state.camps) {
                totalSpend += parseNum(c.spend);
                totalGmv += parseNum(c.gmv);
            }
            let totalRoi = totalSpend > 0 ? totalGmv / totalSpend : 0;
            if (totalRoi < cfg.min_roi_total) {
                lbLog(`🛑 ROI tổng = ${totalRoi.toFixed(2)} < min ${cfg.min_roi_total} — CHẶN tăng NS [${camp.name?.substring(0, 20) || id}]`, 'error');
                return false;
            }
        }

	        lbLog(`⚡ ${camp.name?.substring(0, 30) || id}: +${strangettsShortVN(addAmount)} (${reason})`, 'instant');

	        try {
	            camp.__lastBudgetRoiRamp = null;
	            await lbRefreshCampDetailForBid(camp, true);
	            let explicitRoi = parseRoi(opts.newRoi);
	            if (strategyMode && explicitRoi > 0) explicitRoi = Math.max(lbGetConfiguredInitialRoi(cfg, LIVE_START_BASELINE_ROI), explicitRoi);
	            let roiRamp = null;
	            if (explicitRoi > 0) {
	                let oldRoi = lbGetCurrentBidRoi(camp) || explicitRoi;
	                roiRamp = {
	                    oldRoi: Math.round(oldRoi * 10) / 10,
	                    newRoi: Math.round(explicitRoi * 10) / 10,
	                    targetRoi: lbGetConfiguredTargetRoi(cfg),
	                    elapsedMin: Math.round(Math.max(0, (Date.now() - (state.strategy?.live_start || state.startTime || Date.now())) / 60000)),
	                    source: opts.source || 'budget'
	                };
	            } else {
	                roiRamp = lbBuildBudgetRoiRamp(camp, cfg);
	                if (!roiRamp && strategyMode) {
	                    let currentRoi = lbGetCurrentBidRoi(camp);
	                    let targetRoi = lbGetConfiguredTargetRoi(cfg);
	                    let skip = !currentRoi ? 'chưa lấy được ROI bid hiện tại'
	                        : currentRoi >= targetRoi - 0.05 ? `ROI bid đã đạt mốc ${targetRoi}`
	                            : 'không đủ điều kiện ramp';
	                    lbLog(`🎯 ROI ramp skip: ${skip}`, 'info');
	                }
	            }
	            let editResult = await editCampaignViaApi({
	                campaignId: id,
	                newBudget: String(newBudget),
	                newRoi: roiRamp ? String(roiRamp.newRoi) : undefined,
	            });
	            let verify = await strangettsVerifyEditedCampState(id, {
	                budget: editResult.budget,
	                roi: roiRamp ? editResult.roi : null,
	                name: editResult.name
	            });
	            if (!verify.verified) {
	                lbLog(`⚠️ ${camp.name?.substring(0, 30) || id}: API OK nhưng TikTok chưa xác nhận NS/ROI ${strangettsShortVN(newBudget)}${roiRamp ? ' / ROI ' + roiRamp.newRoi : ''}`, 'error');
	                return false;
	            }

	            camp.budget = strangettsFormatVN(verify.actualBudget ?? newBudget);
	            camp.daily_budget = camp.budget;
	            if (roiRamp && verify.actualRoi != null) camp.targetRoi = verify.actualRoi.toFixed(1);
	            camp.__lastBudgetRoiRamp = roiRamp;
	            if (verify.actualName) camp.name = verify.actualName;
	            if (!verify.nameVerified) lbLog(`⚠️ ${camp.name?.substring(0, 30) || id}: tên camp chưa đồng bộ sau edit`, 'info');

	            let source = opts.source || 'budget';
	            state.budgetEditCount = (state.budgetEditCount || 0) + 1;
	            state.budgetEditBySource = state.budgetEditBySource || {};
	            state.budgetEditBySource[source] = (state.budgetEditBySource[source] || 0) + 1;
	            if (source === 'instant') state.instantCount++;
	            state.lastInstantTime[id] = Date.now();

            // Save adjust time
            let times = {};
            try { times = (await new Promise(r => chrome.storage.local.get(['tt_live_adjust_times'], r))).tt_live_adjust_times || {}; } catch (e) { }
            times[id] = Date.now();
            chrome.storage.local.set({ tt_live_adjust_times: times });

            state.log[0] && (state.log[0].type = 'success');
	            lbLog(`✅ ${camp.name?.substring(0, 30) || id}: NS ${strangettsShortVN(currentBudget)} → ${strangettsShortVN(verify.actualBudget ?? newBudget)}${roiRamp ? ` | ROI ${roiRamp.oldRoi} → ${verify.actualRoi != null ? verify.actualRoi.toFixed(1) : roiRamp.newRoi} (mốc ${roiRamp.targetRoi}/2h)` : ''}`, 'success');
	            return true;
        } catch (err) {
            lbLog(`❌ Lỗi sửa ${id}: ${err.message}`, 'error');
            return false;
        }
    }

    // ===== APPLY ROI CHANGE =====
    async function applyRoiChange(camp, newRoi, reason, opts = {}) {
        let id = String(camp.id);
        let cfg = state._cfg || await strangettsGetLiveBetaConfig();

        if (cfg.no_auto_roi) {
            lbLog(`🔒 ${camp.name?.substring(0, 25) || id}: no_auto_roi=true — BỎ QUA sửa ROI`, 'info');
            return false;
        }

        // Fetch ACTUAL current roas_bid from detail API (not from stale camp object)
        let actualRoi = parseFloat(String(camp.targetRoi || '0').replace(/,/g, '.')) || 0;
        try {
            let detailCache = window.__STRANGETTS_DETAIL_CACHE__?.[id];
            if (!detailCache) {
                await fetchAdIdForCampaign(id);
                detailCache = window.__STRANGETTS_DETAIL_CACHE__?.[id];
            }
            if (detailCache?.ad_info?.roas_bid) {
                actualRoi = parseFloat(detailCache.ad_info.roas_bid) || actualRoi;
            }
        } catch (e) { console.warn('[STRANGE TTS] Could not fetch actual ROI:', e); }

        let ruleOldRoi = parseFloat(String(camp.targetRoi || cfg.target_roi || '1').replace(/,/g, '.')) || 1;
        let delta = newRoi - ruleOldRoi; // e.g., 1.2 - 1.0 = +0.2
        let finalRoi = opts.absolute
            ? Math.round(parseFloat(String(newRoi).replace(/,/g, '.')) * 10) / 10
            : Math.round((actualRoi + delta) * 10) / 10;
        finalRoi = Math.max(opts.minRoi || 0.1, Math.min(20, finalRoi)); // TikTok limits

        lbLog(`🎯 ${camp.name?.substring(0, 30) || id}: ROI ${actualRoi} → ${finalRoi}${opts.absolute ? ' (absolute)' : ` (delta ${delta > 0 ? '+' : ''}${delta.toFixed(1)})`} rule: ${reason}`, 'scheduled');

        try {
            let editResult = await editCampaignViaApi({
                campaignId: id,
                newRoi: String(finalRoi),
            });
            let verify = await strangettsVerifyEditedCampState(id, {
                roi: editResult.roi,
                name: editResult.name
            });
            if (!verify.verified) {
                lbLog(`⚠️ ${camp.name?.substring(0, 30) || id}: API OK nhưng TikTok chưa xác nhận ROI ${finalRoi}`, 'error');
                return false;
            }

            if (verify.actualRoi != null) camp.targetRoi = verify.actualRoi.toFixed(1);
            if (verify.actualName) camp.name = verify.actualName;
            if (!verify.nameVerified) lbLog(`⚠️ ${camp.name?.substring(0, 30) || id}: tên camp chưa đồng bộ sau edit`, 'info');

            state.lastInstantTime[id] = Date.now();
            let times = {};
            try { times = (await new Promise(r => chrome.storage.local.get(['tt_live_adjust_times'], r))).tt_live_adjust_times || {}; } catch (e) { }
            times[id] = Date.now();
            chrome.storage.local.set({ tt_live_adjust_times: times });

            let finalVerifiedRoi = verify.actualRoi != null ? verify.actualRoi.toFixed(1) : finalRoi.toFixed(1);
            lbLog(`✅ ${camp.name?.substring(0, 30) || id}: ROI ${actualRoi} → ${finalVerifiedRoi}`, 'success');
            return true;
        } catch (err) {
            lbLog(`❌ Lỗi sửa ROI ${id}: ${err.message}`, 'error');
            return false;
        }
    }

    async function lbSaveBaselineAdjustTimes(ids, ts) {
        if (!ids || !ids.length) return;
        try {
            let data = await new Promise(r => chrome.storage.local.get(['tt_live_adjust_times'], r));
            let times = data.tt_live_adjust_times || {};
            ids.forEach(id => { times[String(id)] = ts; });
            chrome.storage.local.set({ tt_live_adjust_times: times });
        } catch (e) {
            console.warn('[STRANGE TTS] save start baseline adjust time failed:', e);
        }
    }

    function lbPatchCampWithRoomSession(camp, session) {
        if (!camp || !session) return camp;
        if (!camp.__dayMetrics) {
            camp.__dayMetrics = {
                spend: camp.spend,
                gmv: camp.gmv,
                orders: camp.orders,
                roi: camp.roi,
                cpo: camp.cpo
            };
        }
        camp.__roomSession = session;
        camp.__metricSource = 'room_id';
        camp.spend = strangettsFormatVN(session.spend || 0);
        camp.gmv = strangettsFormatVN(session.gmv || 0);
        camp.orders = String(Math.round(session.orders || 0));
        camp.roi = session.roi ? session.roi.toFixed(2) : '0.00';
        camp.cpo = strangettsFormatVN(session.cpo || (session.orders > 0 ? session.spend / session.orders : 0));
        return camp;
    }

	    async function lbFindCurrentRoomSessionForCamp(camp, roomId, opts = {}) {
	        let id = String(camp?.id || camp?.campaign_id || '').trim();
	        let cleanRoomId = String(roomId || '').match(/\d{10,}/)?.[0] || '';
	        if (!id || !cleanRoomId) return null;
	        state._roomSessionCache = state._roomSessionCache || {};
	        let key = `${id}|${cleanRoomId}`;
	        let cached = state._roomSessionCache[key];
        let ttl = opts.force ? 0 : (opts.cacheTtlMs || 25000);
        if (cached && Date.now() - cached.ts < ttl) return cached.session || null;

        let sessions = await strangettsFetchCampaignRoomListApi(id, { daysBack: opts.daysBack || 0, pageSize: 20 });
        let session = sessions.find(s => String(s.roomId) === cleanRoomId) || null;
        if (!session && opts.allowHistory && opts.daysBack !== 35) {
            sessions = await strangettsFetchCampaignRoomListApi(id, { daysBack: 35, pageSize: 20 });
            session = sessions.find(s => String(s.roomId) === cleanRoomId) || null;
        }
	        state._roomSessionCache[key] = { ts: Date.now(), session };
	        return session;
	    }

	    async function lbFindLatestRoomSessionForCamp(camp, opts = {}) {
	        let id = String(camp?.id || camp?.campaign_id || '').trim();
	        if (!id) return null;
	        state._roomSessionCache = state._roomSessionCache || {};
	        let key = `${id}|__latest`;
	        let cached = state._roomSessionCache[key];
	        let ttl = opts.force ? 0 : (opts.cacheTtlMs || 25000);
	        if (cached && Date.now() - cached.ts < ttl) return cached.session || null;

	        let sessions = await strangettsFetchCampaignRoomListApi(id, {
	            daysBack: opts.daysBack ?? 35,
	            pageSize: opts.pageSize || 10
	        });
	        let session = sessions[0] || null;
	        state._roomSessionCache[key] = { ts: Date.now(), session };
	        return session;
	    }

	    function lbHasLiveSummaryEvidence(roomId = '') {
	        return !!(
	            state._liveRoomConfirmed ||
	            state._hadRunningCamps ||
	            String(roomId || '').match(/\d{10,}/) ||
	            state._currentRoomSession?.roomId ||
	            (state.camps || []).some(c => c.__roomSession?.roomId)
	        );
	    }

	    async function lbFindActiveRoomSessionForCamp(camp, opts = {}) {
	        let id = String(camp?.id || camp?.campaign_id || '').trim();
	        if (!id) return null;
	        state._roomSessionCache = state._roomSessionCache || {};
	        let key = `${id}|__active`;
	        let cached = state._roomSessionCache[key];
	        let ttl = opts.force ? 0 : (opts.cacheTtlMs || 15000);
	        if (cached && Date.now() - cached.ts < ttl) return cached.session || null;

	        let sessions = await strangettsFetchCampaignRoomListApi(id, {
	            daysBack: opts.daysBack ?? 3,
	            pageSize: opts.pageSize || 10
	        });
	        let session = sessions.find(strangettsRoomSessionIsActive) || null;
	        state._roomSessionCache[key] = { ts: Date.now(), session };
	        return session;
	    }

		    function lbRememberRoomSessionFromAds(camp, session, opts = {}) {
		        if (!camp || !session?.roomId) return false;
		        let roomId = String(session.roomId);
		        let locked = String(state._lockedRoomId || '').match(/\d{10,}/)?.[0] || '';
		        if (state.running && locked && roomId !== locked && !opts.allowSwitchRoom) {
		            if (opts.log) lbLog(`🔒 Bỏ qua số liệu room ${roomId.slice(-8)}; phiên đang khóa ${locked.slice(-8)}`, 'info');
		            return false;
		        }
		        lbPatchCampWithRoomSession(camp, session);
		        state._resultRoomId = roomId;
		        state._currentRoomId = roomId;
		        state._currentRoomMatchedCampId = String(camp.id || camp.campaign_id || '');
	        state._currentRoomSession = session;
	        if (opts.persistRoom !== false) {
	            lbApplyRoomId(roomId, opts.source || 'post_room_list mới nhất', { log: !!opts.log });
	        }
	        return true;
	    }

    async function lbFindMatchingRoomCamp(camps, roomId, opts = {}) {
        let cleanRoomId = String(roomId || '').match(/\d{10,}/)?.[0] || '';
        if (!cleanRoomId || !Array.isArray(camps) || !camps.length) return null;
        let ordered = [...camps].sort((a, b) => {
            let ar = lbIsCampActive(a) ? 1 : 0;
            let br = lbIsCampActive(b) ? 1 : 0;
            if (ar !== br) return br - ar;
            return parseNum(b.spend) - parseNum(a.spend);
        });
        let limit = Math.max(1, parseInt(opts.limit, 10) || 12);
        for (let camp of ordered.slice(0, limit)) {
            let session = await lbFindCurrentRoomSessionForCamp(camp, cleanRoomId, opts);
            if (session) return { camp, session, roomId: cleanRoomId };
        }
        return null;
    }

	    async function lbRefreshRoomMatchedSelection(allCamps, opts = {}) {
	        let roomId = opts.roomId || await lbGetRoomId({ force: !!opts.forceRoom, log: !!opts.forceRoom });
	        if (!roomId) return { roomId: null, match: null };
        let match = await lbFindMatchingRoomCamp(allCamps, roomId, { force: !!opts.forceFetch, daysBack: opts.daysBack || 0 });
        if (match?.camp) {
            lbPatchCampWithRoomSession(match.camp, match.session);
            let id = String(match.camp.id);
            state._currentRoomId = roomId;
            state._currentRoomMatchedCampId = id;
            state._currentRoomSession = match.session;
            if (!state.selectedCampIds.has(id) || opts.replaceSelection) {
                lbSelectCampIds([id], true);
                lbLog(`🎯 Khớp room ${String(roomId).slice(-6)} với camp ${match.camp.name?.substring(0, 35) || id} → tự chọn camp này`, 'success');
            }
        }
	        return { roomId, match };
	    }

	    async function lbApplyActiveRoomMetricsToCamps(camps, opts = {}) {
	        if (!Array.isArray(camps) || !camps.length) return { applied: 0, roomId: null, camp: null, session: null };
	        let applied = 0;
	        let newest = null;
	        let primaryCamp = null;
		        for (let camp of camps) {
		            if (opts.selectedOnly && !state.selectedCampIds.has(String(camp.id))) continue;
		            if (opts.activeOnly !== false && !lbIsCampActive(camp)) continue;
		            let session = await lbFindActiveRoomSessionForCamp(camp, {
	                force: !!opts.force,
	                daysBack: opts.daysBack ?? 3,
	                pageSize: opts.pageSize || 10,
		                cacheTtlMs: opts.cacheTtlMs
		            });
		            if (!session?.roomId) continue;
		            let locked = String(state._lockedRoomId || '').match(/\d{10,}/)?.[0] || '';
		            if (state.running && locked && String(session.roomId) !== locked && !opts.allowSwitchRoom) {
		                if (opts.log) lbLog(`🔒 Bỏ qua room active ${String(session.roomId).slice(-8)}; phiên đang khóa ${locked.slice(-8)}`, 'info');
		                continue;
		            }
		            lbPatchCampWithRoomSession(camp, session);
	            applied++;
	            if (!newest || strangettsRoomSessionTimeMs(session) > strangettsRoomSessionTimeMs(newest)) {
	                newest = session;
	                primaryCamp = camp;
	            }
	        }
	        if (newest && primaryCamp) {
	            lbRememberRoomSessionFromAds(primaryCamp, newest, {
	                source: 'post_room_list live_status=1',
	                log: !!opts.log,
	                persistRoom: opts.persistRoom !== false
	            });
	            state._liveRoomConfirmed = true;
	            state._liveRoomConfirmedRoomId = String(newest.roomId);
	        }
	        return { applied, roomId: newest?.roomId || null, camp: primaryCamp, session: newest };
	    }

	    async function lbApplyCurrentRoomMetricsToCamps(camps, roomId, opts = {}) {
	        if (!Array.isArray(camps) || !camps.length) return 0;
	        let cleanRoomId = String(roomId || state._currentRoomId || '').match(/\d{10,}/)?.[0] || '';
        if (!cleanRoomId) return 0;
        let applied = 0;
        for (let camp of camps) {
            if (!state.selectedCampIds.has(String(camp.id))) continue;
            let session = null;
            if (!opts.force && String(state._currentRoomMatchedCampId || '') === String(camp.id) && state._currentRoomSession?.roomId === cleanRoomId) {
                session = state._currentRoomSession;
            } else {
                session = await lbFindCurrentRoomSessionForCamp(camp, cleanRoomId, opts);
            }
            if (session) {
                lbPatchCampWithRoomSession(camp, session);
                applied++;
            }
	        }
	        return applied;
	    }

	    function lbGetSummaryCandidateCamps() {
	        let map = new Map();
	        let add = (camp) => {
	            if (!camp) return;
	            let id = String(camp.id || camp.campaign_id || '').trim();
	            if (!id) return;
	            if (state.selectedCampIds.size && !state.selectedCampIds.has(id) && id !== String(state._currentRoomMatchedCampId || '')) return;
	            map.set(id, camp);
	        };
	        (state.camps || []).forEach(add);
	        (state.allCamps || []).forEach(add);
	        if (state._currentRoomMatchedCampId) {
	            let id = String(state._currentRoomMatchedCampId);
	            add((state.camps || []).find(c => String(c.id) === id));
	            add((state.allCamps || []).find(c => String(c.id) === id));
	        }
	        return [...map.values()];
	    }

	    async function lbFetchExactRoomMetricsForSummary(roomId, opts = {}) {
	        let cleanRoomId = String(roomId || '').match(/\d{10,}/)?.[0] || '';
	        if (!cleanRoomId) return 0;
	        let candidates = lbGetSummaryCandidateCamps();
	        if (!candidates.length) return 0;
	        let applied = 0;
	        for (let camp of candidates) {
	            let id = String(camp.id || camp.campaign_id || '').trim();
	            if (!id) continue;
	            let sessions = await strangettsFetchCampaignRoomListApi(id, {
	                daysBack: opts.daysBack ?? 35,
	                pageSize: opts.pageSize || 50
	            });
	            let session = sessions.find(s => String(s.roomId || '') === cleanRoomId) || null;
	            if (!session) continue;
	            lbRememberRoomSessionFromAds(camp, session, {
	                source: 'post_room_list theo room_id tổng kết',
	                log: !!opts.log,
	                persistRoom: true
	            });
	            if (!(state.camps || []).some(c => String(c.id) === id)) {
	                state.camps = [...(state.camps || []), camp];
	            }
	            applied++;
	        }
	        if (applied > 0) {
	            state._resultRoomId = cleanRoomId;
	            state._liveRoomConfirmed = true;
	            state._liveRoomConfirmedRoomId = cleanRoomId;
	        }
	        return applied;
	    }

	    async function lbApplyLatestRoomMetricsToSelectedCamps(camps, opts = {}) {
	        if (!Array.isArray(camps) || !camps.length) return 0;
	        let applied = 0;
	        let newest = null;
	        for (let camp of camps) {
	            if (!state.selectedCampIds.has(String(camp.id))) continue;
	            let session = await lbFindLatestRoomSessionForCamp(camp, {
	                force: !!opts.force,
	                daysBack: opts.daysBack ?? 35,
	                pageSize: opts.pageSize || 10,
	                cacheTtlMs: opts.cacheTtlMs
	            });
	            if (!session?.roomId) continue;
	            lbPatchCampWithRoomSession(camp, session);
	            applied++;
	            if (!newest || strangettsRoomSessionTimeMs(session) > strangettsRoomSessionTimeMs(newest)) {
	                newest = session;
	            }
	        }
	        if (newest) {
	            let primaryCamp = camps.find(c => state.selectedCampIds.has(String(c.id)) && c.__roomSession?.roomId === newest.roomId);
	            if (primaryCamp) lbRememberRoomSessionFromAds(primaryCamp, newest, {
	                source: 'post_room_list mới nhất',
	                log: !!opts.log,
	                persistRoom: opts.persistRoom
	            });
	        }
	        return applied;
	    }

	    async function lbApplyStartBaseline(camps, cfg) {
	        if (state._startBaselineApplied) return true;
	        state._startBaselineApplied = true;

        if (!cfg.data_ads_enabled) {
            lbLog('⏭ Bỏ qua set khởi động NS/ROI vì data_ads_enabled=false', 'info');
            return true;
        }

	        let selected = (camps || state.camps || []).filter(c => state.selectedCampIds.has(String(c.id)));
	        let lockedRoomId = String(state._lockedRoomId || '').match(/\d{10,}/)?.[0] || '';
	        let activeRoomResult = lockedRoomId
	            ? {
	                applied: selected.some(c => String(c.__roomSession?.roomId || '') === lockedRoomId) ? 1 : 0,
	                roomId: lockedRoomId,
	                camp: selected.find(c => String(c.__roomSession?.roomId || '') === lockedRoomId) || selected[0] || null,
	                session: selected.find(c => String(c.__roomSession?.roomId || '') === lockedRoomId)?.__roomSession || state._currentRoomSession || null
	            }
	            : (selected.length ? await lbApplyActiveRoomMetricsToCamps(selected, {
	                force: true,
	                selectedOnly: false,
	                activeOnly: false,
	                persistRoom: true,
	                log: true
	            }) : { applied: 0, roomId: null, camp: null, session: null });
	        let liveRoomId = activeRoomResult.roomId || lbGetMetricRoomId();
        if (liveRoomId) {
            let matched = activeRoomResult.camp
                ? { match: { camp: activeRoomResult.camp, session: activeRoomResult.session, roomId: liveRoomId } }
                : await lbRefreshRoomMatchedSelection(camps || state.camps || [], { roomId: liveRoomId, forceFetch: true });
            if (!matched.match) {
                lbLog('⏳ Đã có room LIVE nhưng Ads chưa gắn room vào camp. Sẽ thử lại trong lúc khởi động.', 'info');
            }
            selected = (camps || state.camps || []).filter(c => state.selectedCampIds.has(String(c.id)));
        }
        if (!selected.length) {
            lbLog('⚠️ Không có camp LIVE đã chọn để set khởi động', 'error');
            return false;
        }

		        let nowTs = Date.now();
		        let touchedIds = [];
		        let maxCampaignTargetBudget = 0;
		        let maxStartupBudget = 0;
		        let maxSessionBudgetGoal = 0;
		        let maxStrategyTargetRevenue = 0;
		        let matchedSessionCount = 0;
		        let startupBudget = lbGetConfiguredInitialBudget(cfg);
		        let startupRoi = lbGetConfiguredInitialRoi(cfg);
		        let startupWindowMin = lbGetConfiguredInitialWindowMin(cfg);
		        let sessionBudgetGoal = lbGetConfiguredSessionBudget(cfg);
		        let sessionTargetRoi = lbGetConfiguredSessionRoi(cfg, 5.0);
		        let ok = 0, skipped = 0, failed = 0;
		        lbLog(`🎬 Khởi động LIVE: baseline ${startupWindowMin}p = đã tiêu trước phiên + ${strangettsShortVN(startupBudget)} và ROI ${startupRoi}; mốc phiên ${strangettsShortVN(sessionBudgetGoal)} / ROI mục tiêu ${sessionTargetRoi}`, 'scheduled');

		        for (let camp of selected) {
		            let id = String(camp.id);
		            let spentToday = lbGetCampDaySpend(camp);
		            let roomSession = liveRoomId ? (camp.__roomSession || await lbFindCurrentRoomSessionForCamp(camp, liveRoomId, { force: true })) : null;
		            if (roomSession) {
		                lbPatchCampWithRoomSession(camp, roomSession);
		                matchedSessionCount++;
		            }
			            let currentSessionSpend = roomSession ? Number(roomSession.spend || 0) : 0;
			            let previousSessionSpend = roomSession ? Math.max(0, spentToday - currentSessionSpend) : spentToday;
			            let dayGmv = roomSession ? parseNum(camp.__dayMetrics?.gmv ?? camp.gmv) : parseNum(camp.gmv);
			            let currentSessionGmv = roomSession ? Number(roomSession.gmv || 0) : 0;
			            let previousSessionGmv = roomSession ? Math.max(0, dayGmv - currentSessionGmv) : dayGmv;
			            let targetBudget = Math.ceil((previousSessionSpend + startupBudget) / 1000) * 1000;
			            let sessionCampaignGoal = Math.ceil((previousSessionSpend + sessionBudgetGoal) / 1000) * 1000;
			            let sessionCapForStrategy = roomSession ? sessionBudgetGoal : sessionCampaignGoal;
			            let strategyTargetRevenue = roomSession
			                ? sessionBudgetGoal * sessionTargetRoi
			                : previousSessionGmv + (sessionBudgetGoal * sessionTargetRoi);
			            maxStartupBudget = Math.max(maxStartupBudget, targetBudget);
			            maxCampaignTargetBudget = Math.max(maxCampaignTargetBudget, sessionCampaignGoal);
			            maxSessionBudgetGoal = Math.max(maxSessionBudgetGoal, sessionCapForStrategy);
			            maxStrategyTargetRevenue = Math.max(maxStrategyTargetRevenue, strategyTargetRevenue);
		            let currentBudget = parseNum(camp.budget);
		            let currentRoi = parseRoi(camp.targetRoi || camp.roi);
		            let needBudget = Math.abs(currentBudget - targetBudget) > 1000;
		            let needRoi = Math.abs(currentRoi - startupRoi) > 0.11;

		            if (!needBudget && !needRoi) {
                skipped++;
                touchedIds.push(id);
                state.lastInstantTime[id] = nowTs;
                continue;
            }

		            try {
		                let editResult = await editCampaignViaApi({
		                    campaignId: id,
		                    newBudget: String(targetBudget),
		                    newRoi: String(startupRoi),
		                });
		                let verify = await strangettsVerifyEditedCampState(id, {
		                    budget: editResult.budget,
                    roi: editResult.roi,
                    name: editResult.name
		                });
		                if (!verify.verified) {
		                    failed++;
		                    lbLog(`⚠️ ${camp.name?.substring(0, 30) || id}: API OK nhưng TikTok chưa xác nhận NS ${strangettsShortVN(targetBudget)} + ROI ${startupRoi}`, 'error');
		                    continue;
		                }

		                camp.budget = strangettsFormatVN(verify.actualBudget ?? targetBudget);
		                camp.daily_budget = camp.budget;
		                camp.targetRoi = (verify.actualRoi ?? startupRoi).toFixed(1);
		                if (verify.actualName) camp.name = verify.actualName;
		                state.lastInstantTime[id] = nowTs;
		                touchedIds.push(id);
		                ok++;
		                let sourceText = roomSession
		                    ? `phiên ${String(liveRoomId).slice(-6)}: đã tiêu phiên ${strangettsShortVN(currentSessionSpend)}, đã tiêu trước đó ${strangettsShortVN(previousSessionSpend)}`
		                    : `fallback hôm nay: đã tiêu ${strangettsShortVN(spentToday)}`;
		                lbLog(`✅ ${camp.name?.substring(0, 30) || id}: ${sourceText} → set baseline ${startupWindowMin}p ${strangettsShortVN(targetBudget)} + ROI ${startupRoi}; mốc phiên ${strangettsShortVN(sessionBudgetGoal)} (đích camp ${strangettsShortVN(sessionCampaignGoal)})`, 'success');
		            } catch (err) {
                failed++;
                lbLog(`❌ ${camp.name?.substring(0, 30) || id}: lỗi set khởi động — ${err.message}`, 'error');
            }
        }

        await lbSaveBaselineAdjustTimes(touchedIds, nowTs);

        if (state.strategy?.enabled) {
		            if (maxSessionBudgetGoal > 0) {
		                state.strategy.budget_cap = maxSessionBudgetGoal;
		                state.strategy.target_revenue = maxStrategyTargetRevenue || (maxSessionBudgetGoal * (state.strategy.target_roi || 1));
		                state.strategy.session_budget_source = matchedSessionCount > 0 ? 'room_id' : 'camp_day_fallback';
	                state.strategy.campaign_budget_target = maxCampaignTargetBudget;
	                state.strategy.startup_budget_target = maxStartupBudget;
	                state.strategy.session_budget_goal = sessionBudgetGoal;
	                state.strategy.room_id = liveRoomId || null;
	                lbLog(`⚡ V3 dùng mốc phiên: ${strangettsShortVN(maxSessionBudgetGoal)} | khởi động ${strangettsShortVN(maxStartupBudget)} | đích camp ${strangettsShortVN(maxCampaignTargetBudget)} (${matchedSessionCount > 0 ? 'khớp room_id' : 'fallback hôm nay'})`, matchedSessionCount > 0 ? 'success' : 'info');
	            }
            state.strategy.last_budget_edit_at = nowTs;
            state.strategy.last_roi_edit_at = nowTs;
            state.strategy.p1_roi_set = true;
            state.strategy.api_last_edit_ok = failed === 0;
        }

	        lbLog(`🎬 Set khởi động xong: ${ok} sửa | ${skipped} đã đúng | ${failed} lỗi`, failed ? 'error' : 'success');
	        return failed === 0 || ok > 0 || skipped > 0;
	    }

	    function lbAbortStartWithoutNotification(reason) {
	        state.running = false;
	        state._ending = true;
	        if (state.pollTimer) { clearInterval(state.pollTimer); state.pollTimer = null; }
	        _stopHeartbeat();
	        lbStopGiveawayTimer();
	        lbStopAutoPin();
	        if (chatState.reminderTimer) { clearInterval(chatState.reminderTimer); chatState.reminderTimer = null; }
	        if (_gwCountdownTimer) { clearInterval(_gwCountdownTimer); _gwCountdownTimer = null; }
	        let btn = document.getElementById('lb-toggle');
	        if (btn) {
	            btn.textContent = '▶ Bắt đầu';
	            btn.style.background = 'linear-gradient(135deg,#16A34A,#22C55E)';
	        }
	        let sosBtn = document.getElementById('lb-emergency-stop');
	        if (sosBtn) sosBtn.style.display = 'none';
	        updateToggleBtn();
	        lbUpdateMonitor();
	        lbLog(reason || '⚠️ Không thể bắt đầu vì chưa có camp hợp lệ', 'error');
	    }

		    function lbCurrentLiveEndKey(reason = 'end') {
		        let roomId = String(lbGetMetricRoomId() || state._liveRoomConfirmedRoomId || state._resultRoomId || 'no-room');
		        let start = state.startTime || 'no-start';
		        return roomId && roomId !== 'no-room' ? `room:${roomId}` : `no-room:${start}`;
		    }

	    function lbStopRuntimeLoopsForEnd(reason = 'live_end') {
	        if (state.pollTimer) { clearInterval(state.pollTimer); state.pollTimer = null; }
	        _stopHeartbeat();
	        lbStopGiveawayTimer();
	        lbStopAutoPin();
	        if (chatState.reminderTimer) { clearInterval(chatState.reminderTimer); chatState.reminderTimer = null; }
	        if (_gwCountdownTimer) { clearInterval(_gwCountdownTimer); _gwCountdownTimer = null; }
	        let btn = document.getElementById('lb-toggle');
	        if (btn) {
	            btn.textContent = '▶ Bắt đầu';
	            btn.style.background = 'linear-gradient(135deg,#16A34A,#22C55E)';
	        }
	        let sosBtn = document.getElementById('lb-emergency-stop');
	        if (sosBtn) sosBtn.style.display = 'none';
	        updateToggleBtn();
	        lbUpdateMonitor();
	        chrome.storage.local.remove('tt_livebeta_state');
	        lbLog(`🔒 Đã khóa vòng lặp LIVE end (${reason}) để tránh gửi lặp`, 'info');
	    }

		    function lbBeginLiveEndOnce(reason = 'live_end') {
		        let endKey = lbCurrentLiveEndKey(reason);
		        window.__STRANGETTS_LIVE_END_SENT_KEYS__ = window.__STRANGETTS_LIVE_END_SENT_KEYS__ || {};
		        let sentMap = window.__STRANGETTS_LIVE_END_SENT_KEYS__;
		        let now = Date.now();
		        for (let [key, ts] of Object.entries(sentMap)) {
		            if (now - ts > 30 * 60 * 1000) delete sentMap[key];
		        }
		        if (sentMap[endKey] && now - sentMap[endKey] < 30 * 60 * 1000) {
		            lbLog(`🔒 Bỏ qua LIVE end đã gửi cho phiên này (${reason})`, 'info');
		            return false;
		        }
		        if (state._ending) {
		            lbLog(`🔒 Bỏ qua LIVE end lặp (${reason})`, 'info');
		            return false;
		        }
		        state._ending = true;
		        state.running = false;
		        state._liveEndNotifyKey = endKey;
		        state._liveEndNotifySentAt = now;
		        sentMap[endKey] = now;
	        try {
	            let endedRoomId = String(lbGetMetricRoomId() || state._liveRoomConfirmedRoomId || state._resultRoomId || '');
	            if (endedRoomId && _autoLiveState) {
	                _autoLiveState.lastEndedRoomId = endedRoomId;
	                _autoLiveState.lastEndedAt = Date.now();
	            }
	        } catch (e) { }
	        lbStopRuntimeLoopsForEnd(reason);
	        return true;
	    }

	    async function lbPrimeStartCamps(cfg) {
	        try {
		            let allCamps = await lbEnsureLevel1AdsLoaded('khởi động live', {
		                clickUi: true,
		                force: true,
		                rawFallback: true
		            });

		            let selectedInitialCamps = state.selectedCampIds.size
		                ? state.allCamps.filter(c => state.selectedCampIds.has(String(c.id)))
		                : [];
		            let pendingStartRoomId = String(state._pendingStartRoomId || '').match(/\d{10,}/)?.[0] || '';
		            let pendingStartSession = state._pendingStartRoomSession || null;
		            let pendingStartCampId = String(state._pendingStartCampId || '').trim();
		            let activeRoomResult = { applied: 0, roomId: null, camp: null, session: null };
		            if (pendingStartRoomId) {
		                let pendingCamp = (state.allCamps || []).find(c => String(c.id || c.campaign_id || '') === pendingStartCampId)
		                    || selectedInitialCamps.find(c => String(c.__roomSession?.roomId || '') === pendingStartRoomId)
		                    || selectedInitialCamps[0]
		                    || (state.allCamps || [])[0]
		                    || null;
		                if (pendingCamp && pendingStartSession?.roomId) {
		                    lbPatchCampWithRoomSession(pendingCamp, pendingStartSession);
		                }
		                lbLockRoomIdForSession(pendingStartRoomId, 'post_room_list live_status=1');
		                activeRoomResult = {
		                    applied: pendingCamp ? 1 : 0,
		                    roomId: pendingStartRoomId,
		                    camp: pendingCamp,
		                    session: pendingStartSession
		                };
		                lbLog(`🔒 Dùng room đã lấy lúc phát hiện LIVE: ${pendingStartRoomId.slice(-8)} — không gọi lại room khi khởi động`, 'success');
		            } else {
		                activeRoomResult = selectedInitialCamps.length
		                    ? await lbApplyActiveRoomMetricsToCamps(selectedInitialCamps, {
		                        force: true,
		                        selectedOnly: false,
		                        activeOnly: false,
		                        persistRoom: true,
		                        log: true
		                    })
		                    : { applied: 0, roomId: null, camp: null, session: null };
		                if (!activeRoomResult.applied && !state.selectedCampIds.size) {
		                    activeRoomResult = await lbApplyActiveRoomMetricsToCamps(state.allCamps, {
		                        force: true,
		                        selectedOnly: false,
		                        activeOnly: false,
		                        persistRoom: true,
		                        log: true
		                    });
		                }
		            }
	            if (activeRoomResult.camp && !state.selectedCampIds.size) {
	                lbSelectCampIds([activeRoomResult.camp.id], true);
	                lbLog(`🎯 post_room_list đang LIVE → tự chọn camp ${activeRoomResult.camp.name?.substring(0, 35) || activeRoomResult.camp.id}`, 'success');
	            }
	            let roomId = activeRoomResult.roomId || null;
	            let roomMatched = activeRoomResult.camp ? { camp: activeRoomResult.camp, session: activeRoomResult.session, roomId } : null;
            if (roomId && state.allCamps.length && !roomMatched) {
                for (let attempt = 1; attempt <= 6; attempt++) {
                    let result = await lbRefreshRoomMatchedSelection(state.allCamps, {
                        roomId,
                        forceFetch: true,
                        replaceSelection: attempt === 1 && !state.selectedCampIds.size
                    });
                    roomMatched = result.match;
                    if (roomMatched) break;
                    if (attempt < 6) {
                        lbLog(`⏳ Chưa thấy camp Ads gắn room ${String(roomId).slice(-6)} (lần ${attempt}/6). Chờ 10s rồi quét lại...`, 'info');
                        await new Promise(r => setTimeout(r, 10000));
	                        allCamps = await lbEnsureLevel1AdsLoaded('chờ camp gắn room', {
	                            clickUi: true,
	                            force: true,
	                            rawFallback: true
	                        });
                    }
                }
            }

            let camps = (state.allCamps || []).filter(c => state.selectedCampIds.has(String(c.id)));
            if (roomId && !roomMatched && camps.length && !camps.some(c => lbIsCampActive(c))) {
                lbLog('⏳ Room LIVE đã có nhưng camp Ads đã chọn chưa hoạt động/chưa khớp room. Auto sẽ tiếp tục chờ để tránh chạy sai phiên.', 'info');
                return false;
            }
            if (!camps || camps.length === 0) return false;
            if (!roomId) {
                lbLog('⏳ Chưa có room_id live_status=1 từ post_room_list của camp Ads. Auto sẽ chờ để tránh lấy room/số liệu phiên cũ.', 'info');
                return false;
            }

            state._emptyTicks = 0;
            if (camps.some(c => lbIsCampActive(c) || strangettsRoomSessionIsActive(c.__roomSession))) state._hadRunningCamps = true;
            state.camps = camps;
            await lbApplyCurrentRoomMetricsToCamps(state.camps, roomId, { force: true });
            state.camps.forEach(c => addSnapshot(c));
            renderCampList();

            await lbApplyStartBaseline(state.camps, cfg);
            state.camps.forEach(c => addSnapshot(c));
            renderCampList();

            let lv3Toggle = document.getElementById('lb-lv3-toggle');
            if (lv3Toggle && lv3Toggle.checked) {
                try { await lbPollLevel3(); } catch (e) { console.warn('[STRANGE TTS] LV3 start poll error:', e); }
            }

		            state.tickCount = Math.max(state.tickCount, 1);
		            lbUpdateMonitor();
		            state._pendingStartRoomId = null;
		            state._pendingStartRoomSession = null;
		            state._pendingStartCampId = null;
		            return true;
		        } catch (err) {
		            state._pendingStartRoomId = null;
		            state._pendingStartRoomSession = null;
		            state._pendingStartCampId = null;
		            lbLog(`❌ Load camp khởi động lỗi: ${err.message}`, 'error');
		            return false;
		        }
    }

    // ===== APPLY RULE ENGINE ACTION =====
    async function applyRuleAction(camp, ruleResult, cfg) {
        let campName = camp.name?.substring(0, 30) || camp.id;
        let id = String(camp.id);
        let action = ruleResult.action;

        // Log the rule result
        lbLog(`📐 Rule: ${campName}: ${ruleResult.emoji} ${ruleResult.message}`,
            action.includes('increase') || action.includes('decrease') ? 'scheduled' : action === 'hold' ? 'info' : 'error');

        if (action === 'hold') return false;

        // === Determine what to change ===
        let currentBudget = parseNum(camp.budget);
        let newBudget = null;
        let newRoi = null;

        // Budget changes
        if (ruleResult.new_budget != null) {
            newBudget = ruleResult.new_budget;
            // Guard: max budget cap
            if (cfg.max_budget_cap > 0 && newBudget > cfg.max_budget_cap) {
                if (currentBudget >= cfg.max_budget_cap) {
                    lbLog(`🛑 ${campName}: NS đã đạt giới hạn ${strangettsShortVN(cfg.max_budget_cap)} — BỎ QUA`, 'error');
                    newBudget = null; // Skip budget change
                } else {
                    newBudget = cfg.max_budget_cap;
                    lbLog(`⚠️ Cap NS tối đa: → ${strangettsShortVN(newBudget)}`, 'info');
                }
            }
        }

        // ROI changes — delta-based using actual API bid
        if (ruleResult.new_roi != null) {
            if (cfg.no_auto_roi) {
                lbLog(`🔒 ${campName}: no_auto_roi=true — BỎ QUA sửa ROI`, 'info');
            } else {
                // Fetch ACTUAL current roas_bid from detail API
                let actualRoi = parseFloat(String(camp.targetRoi || '0').replace(/,/g, '.')) || 0;
                console.log('[STRANGE TTS] 🎯 ROI TRACE — camp.targetRoi:', camp.targetRoi, '→ actualRoi initial:', actualRoi);
                try {
                    let detailCache = window.__STRANGETTS_DETAIL_CACHE__?.[id];
                    console.log('[STRANGE TTS] 🎯 ROI TRACE — detailCache exists:', !!detailCache, '| cached roas_bid:', detailCache?.ad_info?.roas_bid);
                    if (!detailCache) {
                        console.log('[STRANGE TTS] 🎯 ROI TRACE — fetching detail for', id);
                        await fetchAdIdForCampaign(id);
                        detailCache = window.__STRANGETTS_DETAIL_CACHE__?.[id];
                        console.log('[STRANGE TTS] 🎯 ROI TRACE — after fetch, cached roas_bid:', detailCache?.ad_info?.roas_bid);
                    }
                    if (detailCache?.ad_info?.roas_bid) {
                        actualRoi = parseFloat(detailCache.ad_info.roas_bid) || actualRoi;
                    }
                } catch (e) { console.warn('[STRANGE TTS] Could not fetch actual ROI:', e); }

                // Calculate delta: how much the rule wants to change from its reference
                let ruleOldRoi = parseFloat(String(camp.targetRoi || cfg.target_roi || '1').replace(/,/g, '.')) || 1;
                let delta = ruleResult.new_roi - ruleOldRoi;
                let finalRoi = Math.round((actualRoi + delta) * 10) / 10;
                finalRoi = Math.max(0.1, Math.min(20, finalRoi));

                console.log('[STRANGE TTS] 🎯 ROI TRACE — ruleResult.new_roi:', ruleResult.new_roi, '| ruleOldRoi:', ruleOldRoi, '| delta:', delta, '| actualRoi:', actualRoi, '| FINAL:', finalRoi);

                newRoi = finalRoi;
                lbLog(`🎯 ${campName}: ROI ${actualRoi} → ${finalRoi} (delta ${delta > 0 ? '+' : ''}${delta.toFixed(1)})`, 'scheduled');
            }
        }

        // Nothing to change
        if (newBudget == null && newRoi == null) return false;

        // Send Telegram notification
        if (isNotifyReady(cfg) && ['decrease_roi', 'increase_roi_light', 'increase_roi_strong', 'increase_budget_light', 'increase_budget_and_roi'].includes(action)) {
	            let teleMsg = `${getLiveAccountLabel()}\n${ruleResult.emoji} <b>Tự động điều chỉnh theo luật</b>\n`;
	            teleMsg += `🎯 <b>${campName}</b>\n`;
	            teleMsg += `📐 Lý do: ${ruleResult.message}\n`;
            if (newRoi != null) teleMsg += `🎯 ROI → ${newRoi}\n`;
            if (newBudget != null) teleMsg += `💰 NS: ${strangettsShortVN(currentBudget)} → ${strangettsShortVN(newBudget)}\n`;
            await strangettsNotifySend(teleMsg, cfg);
        }

        // === SINGLE API CALL with both budget + ROI ===
        try {
            let apiParams = { campaignId: id };
            if (newBudget != null) {
                apiParams.newBudget = String(newBudget);
            } else {
                // Always pass current budget — prevents stale detail cache budget (100K) from being used
                let campBudget = parseInt(String(camp.budget || '0').replace(/\D/g, ''), 10);
                if (campBudget > 0) apiParams.newBudget = String(campBudget);
            }
            if (newRoi != null) apiParams.newRoi = String(newRoi);

            lbLog(`⚡ ${campName}: API call — ${newBudget ? 'NS→' + strangettsShortVN(newBudget) : ''} ${newRoi ? 'ROI→' + newRoi : ''}`, 'instant');
            await editCampaignViaApi(apiParams);

            state.lastInstantTime[id] = Date.now();
	            if (newBudget) {
	                state.budgetEditCount = (state.budgetEditCount || 0) + 1;
	                state.budgetEditBySource = state.budgetEditBySource || {};
	                state.budgetEditBySource.v1 = (state.budgetEditBySource.v1 || 0) + 1;
	            }
            let times = {};
            try { times = (await new Promise(r => chrome.storage.local.get(['tt_live_adjust_times'], r))).tt_live_adjust_times || {}; } catch (e) { }
            times[id] = Date.now();
            chrome.storage.local.set({ tt_live_adjust_times: times });

            lbLog(`✅ ${campName}: Đã áp dụng thành công!`, 'success');
            return true;
        } catch (err) {
            lbLog(`❌ Lỗi API ${campName}: ${err.message}`, 'error');
            return false;
        }
    }

    // ===== RENDER CAMP LIST =====
    function renderCampList() {
        let listEl = document.getElementById('lb-camp-list');
        if (!listEl) return;
        if (state.camps.length === 0) {
            listEl.innerHTML = '<div style="color:#6B7280; text-align:center; padding:10px; font-size:10px;">Chưa có camp LIVE — chờ poll...</div>';
            listEl.style.display = 'none';
            return;
        }
        let cfgForRender = { ...STRANGETTS_LIVEBETA_DEFAULTS, ...(state._cfg || {}) };
        let liveData = cfgForRender.data_live_dash_enabled ? (window.__STRANGETTS_LIVE_DASHBOARD__ || null) : null;
        // Preserve collapsed state — don't force-show if user collapsed
        if (listEl.style.display !== 'none') {
            listEl.style.display = 'flex';
            listEl.style.flexDirection = 'column';
        }
        listEl.innerHTML = '';
        state.camps.forEach(c => {
            let spend = parseNum(c.spend), budget = parseNum(c.budget);
            let roi = parseRoi(c.roi), targetRoi = parseRoi(c.targetRoi);
            let snaps = state.snapshots[String(c.id)] || [];
            let lastAction = state.lastInstantTime[String(c.id)];
            let lastActionStr = lastAction ? strangettsFormatMinutes(Math.floor((Date.now() - lastAction) / 60000)) + ' trước' : '—';
            let cfgSync = { ...STRANGETTS_LIVEBETA_DEFAULTS, ...(state._cfg || {}) };
            let score = strangettsLiveScore(c, liveData, cfgSync);
            let d = score.details;
            let aiResult = state.aiResults?.[String(c.id)] || state.aiResults?.[c.name] || null;
            let bdg = (val, mx) => val >= mx * 0.7 ? '✅' : val >= mx * 0.4 ? '⚠️' : '❌';
            let gradColor = score.totalScore < 40 ? '#F87171,#EF4444' : score.totalScore < 60 ? '#FBBF24,#F59E0B' : score.totalScore < 80 ? '#4ADE80,#22C55E' : '#22D3EE,#06B6D4';

            let div = document.createElement('div');
            div.style.cssText = 'background:linear-gradient(135deg,rgba(26,10,46,0.95),rgba(45,27,78,0.9)); border:1px solid rgba(138,141,145,0.2); border-radius:10px; padding:10px; margin-bottom:6px;';
            div.innerHTML = `
                <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:6px;">
                    <span style="font-size:11px; font-weight:700; color:white; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; max-width:65%;">${c.name || c.id}</span>
                    <div style="display:flex; gap:4px; align-items:center; font-size:8px; color:#6B7280;">
                        <span>📷${snaps.length}</span><span>⚡${lastActionStr}</span>
                    </div>
                </div>
                <div style="display:grid; grid-template-columns:1fr 1fr 1fr 1fr; gap:3px; margin-bottom:6px;">
                    <div style="text-align:center; padding:4px 2px; background:rgba(59,130,246,0.15); border-radius:6px; border:1px solid rgba(59,130,246,0.2);">
                        <div style="font-size:7px; color:#93C5FD;">🔵 Ads</div>
                        <div style="font-size:12px;">${bdg(score.adsScore, 100)}</div>
                        <div style="font-size:9px; color:#60A5FA; font-weight:700;">${score.adsScore}</div>
                        <div style="font-size:6px; color:#6B7280;">ROI ${d.roi.toFixed(1)} | ${d.spendRate}%</div>
                    </div>
                    <div style="text-align:center; padding:4px 2px; background:rgba(34,197,94,0.15); border-radius:6px; border:1px solid rgba(34,197,94,0.2);">
                        <div style="font-size:7px; color:#86EFAC;">🟢 Conv</div>
                        <div style="font-size:12px;">${bdg(score.convScore, 100)}</div>
                        <div style="font-size:9px; color:#4ADE80; font-weight:700;">${score.convScore}</div>
                        <div style="font-size:6px; color:#6B7280;">${d.orderRate > 0 ? d.orderRate.toFixed(1) + '%' : d.orders + ' đơn'}</div>
                    </div>
                    <div style="text-align:center; padding:4px 2px; background:rgba(251,146,60,0.15); border-radius:6px; border:1px solid rgba(251,146,60,0.2);">
                        <div style="font-size:7px; color:#FDBA74;">🟠 Live</div>
                        <div style="font-size:12px;">${score.hasLiveData ? bdg(score.qualityScore, 100) : '—'}</div>
                        <div style="font-size:9px; color:#FB923C; font-weight:700;">${score.hasLiveData ? score.qualityScore : '—'}</div>
                        <div style="font-size:6px; color:#6B7280;">${score.hasLiveData ? d.enterRate.toFixed(1) + '% / ' + d.avgViewDuration.toFixed(0) + 's' : 'N/A'}</div>
                    </div>
                    <div style="text-align:center; padding:4px 2px; background:rgba(244,63,94,0.15); border-radius:6px; border:1px solid rgba(244,63,94,0.2);">
                        <div style="font-size:7px; color:#FDA4AF;">🔴 Merch</div>
                        <div style="font-size:12px;">${score.hasMerchData ? bdg(score.merchScore, 100) : '—'}</div>
                        <div style="font-size:9px; color:#FB7185; font-weight:700;">${score.hasMerchData ? score.merchScore : '—'}</div>
                        <div style="font-size:6px; color:#6B7280;">${d.hasViolation ? '⚠️VP' : d.promoActive ? '🎁Promo' : 'OK'}</div>
                    </div>
                </div>
                <div style="margin-bottom:5px;">
                    <div style="display:flex; justify-content:space-between; font-size:9px; margin-bottom:2px;">
                        <span style="color:#A78BFA; font-weight:700;">📈 Score</span>
                        <span style="color:${score.color}; font-weight:800;">${score.totalScore}/100</span>
                    </div>
                    <div style="height:6px; background:rgba(138,141,145,0.15); border-radius:3px; overflow:hidden;">
                        <div style="height:100%; width:${score.totalScore}%; border-radius:3px; background:linear-gradient(90deg,${gradColor}); transition:width 0.5s;"></div>
                    </div>
                </div>
                <div style="background:rgba(0,0,0,0.2); border-radius:6px; padding:5px 8px; font-size:9px;">
                    <div style="color:${score.color}; font-weight:700;">${score.emoji} ${score.actionText}</div>
                    ${score.qualityGateBlocked ? '<div style="color:#F87171; font-size:8px; margin-top:2px;">🚫 Quality gate: live yếu → chặn</div>' : ''}
                    ${score.guardrailReason ? '<div style="color:#FBBF24; font-size:8px; margin-top:2px;">⚠️ ' + score.guardrailReason + '</div>' : ''}
                    ${aiResult ? '<div style="color:#A78BFA; font-size:8px; margin-top:2px;">🤖 ' + (aiResult.summary || '') + (aiResult.risk ? ' ⚠️' + aiResult.risk : '') + '</div>' : ''}
                </div>
                <div style="display:grid; grid-template-columns:1fr 1fr 1fr 1fr 1fr; gap:3px; margin-top:5px;">
                    <div style="text-align:center; padding:3px 2px; background:rgba(251,191,36,0.15); border-radius:5px; border:1px solid rgba(251,191,36,0.2);">
                        <div style="font-size:7px; color:#FCD34D;">💰 DT</div>
                        <div style="font-size:12px; font-weight:700; color:#FBBF24;">${strangettsShortVN(parseNum(c.gmv))}</div>
                    </div>
                    <div style="text-align:center; padding:3px 2px; background:rgba(139,92,246,0.1); border-radius:5px;">
                        <div style="font-size:7px; color:#A78BFA;">💼 NS</div>
                        <div style="font-size:12px; font-weight:700; color:#C4B5FD;">${strangettsShortVN(budget)}</div>
                    </div>
                    <div style="text-align:center; padding:3px 2px; background:rgba(239,68,68,0.1); border-radius:5px;">
                        <div style="font-size:7px; color:#FCA5A5;">💸 CP</div>
                        <div style="font-size:12px; font-weight:700; color:#F87171;">${strangettsShortVN(spend)}</div>
                    </div>
                    <div style="text-align:center; padding:3px 2px; background:rgba(34,211,238,0.1); border-radius:5px;">
                        <div style="font-size:7px; color:#67E8F9;">🎯 ROI</div>
                        <div style="font-size:12px; font-weight:700; color:#22D3EE;">${roi.toFixed(1)}/${targetRoi.toFixed(1)}</div>
                    </div>
                    <div style="text-align:center; padding:3px 2px; background:rgba(74,222,128,0.1); border-radius:5px;">
                        <div style="font-size:7px; color:#86EFAC;">📦 Đơn</div>
                        <div style="font-size:12px; font-weight:700; color:#4ADE80;">${c.orders || '0'}</div>
                    </div>
                </div>
                ${lbRenderTrendRow(snaps, spend, roi)}
            `;
            listEl.appendChild(div);
        });
    }

    // ===== TREND CALCULATION (5m/15m/30m) =====
    function lbCalcTrend(snaps, windowMin) {
        if (!snaps || snaps.length < 2) return null;
        let now = Date.now();
        let cutoff = now - windowMin * 60 * 1000;
        // Find the snapshot closest to the cutoff time
        let old = null;
        for (let i = 0; i < snaps.length; i++) {
            if (snaps[i].ts >= cutoff) { old = snaps[i]; break; }
        }
        if (!old) old = snaps[0]; // oldest available
        let latest = snaps[snaps.length - 1];
        if (old.ts === latest.ts) return null;
        let spendDelta = (parseNum(latest.spend) || 0) - (parseNum(old.spend) || 0);
        let roiOld = parseFloat(old.roi) || 0;
        let roiNew = parseFloat(latest.roi) || 0;
        let roiDelta = roiNew - roiOld;
        let ordersOld = parseInt(old.orders) || 0;
        let ordersNew = parseInt(latest.orders) || 0;
        let ordersDelta = ordersNew - ordersOld;
        let elapsed = (latest.ts - old.ts) / 60000; // actual minutes
        return { spendDelta, roiDelta, ordersDelta, elapsed: elapsed.toFixed(0) };
    }

    function lbRenderTrendRow(snaps, currentSpend, currentRoi) {
        let t5 = lbCalcTrend(snaps, 5);
        let t15 = lbCalcTrend(snaps, 15);
        let t30 = lbCalcTrend(snaps, 30);
        if (!t5 && !t15 && !t30) return '';

        let fmtDelta = (t, field) => {
            if (!t) return '<span style="color:#4B5563;">—</span>';
            let val = t[field];
            if (field === 'spendDelta') {
                let color = val > 0 ? '#F87171' : '#4ADE80';
                let arrow = val > 0 ? '↑' : val < 0 ? '↓' : '—';
                return `<span style="color:${color}; font-weight:600;">${arrow}${strangettsShortVN(Math.abs(val))}</span>`;
            } else if (field === 'roiDelta') {
                let color = val > 0 ? '#4ADE80' : val < 0 ? '#F87171' : '#6B7280';
                let arrow = val > 0 ? '↑' : val < 0 ? '↓' : '—';
                return `<span style="color:${color}; font-weight:600;">${arrow}${Math.abs(val).toFixed(2)}</span>`;
            } else {
                let color = val > 0 ? '#4ADE80' : '#6B7280';
                return `<span style="color:${color}; font-weight:600;">${val > 0 ? '+' : ''}${val}</span>`;
            }
        };

        return `<div style="margin-top:5px; padding:5px 6px; background:rgba(59,130,246,0.08); border-radius:6px; border:1px solid rgba(59,130,246,0.15);">
            <div style="font-size:8px; color:#93C5FD; font-weight:600; margin-bottom:3px;">📊 Trend (Chi phí | ROI | Đơn)</div>
            <div style="display:grid; grid-template-columns:35px 1fr 1fr 1fr; gap:3px; font-size:9px; color:#E8D5FF;">
                <div style="color:#6B7280; font-weight:600;">5m</div>
                <div>${fmtDelta(t5, 'spendDelta')}</div>
                <div>${fmtDelta(t5, 'roiDelta')}</div>
                <div>${fmtDelta(t5, 'ordersDelta')}</div>
                <div style="color:#6B7280; font-weight:600;">15m</div>
                <div>${fmtDelta(t15, 'spendDelta')}</div>
                <div>${fmtDelta(t15, 'roiDelta')}</div>
                <div>${fmtDelta(t15, 'ordersDelta')}</div>
                <div style="color:#6B7280; font-weight:600;">30m</div>
                <div>${fmtDelta(t30, 'spendDelta')}</div>
                <div>${fmtDelta(t30, 'roiDelta')}</div>
                <div>${fmtDelta(t30, 'ordersDelta')}</div>
            </div>
        </div>`;
    }

    // ===== MAIN POLL TICK =====
    async function pollTick(cfg) {
        if (!state.running || state._ending) return;
        if (state._pollBusy) {
            lbLog('⏳ Poll trước chưa xong, bỏ qua tick chồng để tránh gửi lặp', 'info');
            return;
        }
        state._pollBusy = true;
        state.tickCount++;

        try {
            // Refresh config on each tick so settings changes (e.g. Telegram toggle) take effect immediately
            cfg = await strangettsGetLiveBetaConfig();
            state._cfg = cfg;

		            // Fetch LIVE campaigns (type 305) through the same scan path as the Cấp 1 button.
			            let allCamps = await lbEnsureLevel1AdsLoaded('poll', {
			                clickUi: state.tickCount <= 2 || state.tickCount % 6 === 0,
			                rawFallback: true,
			                minIntervalMs: 30000
			            });
			            let lockedRoomId = String(state._lockedRoomId || '').match(/\d{10,}/)?.[0] || '';
			            let activeRoomResult = lockedRoomId
			                ? { applied: 0, roomId: lockedRoomId, camp: null, session: null }
			                : await lbApplyActiveRoomMetricsToCamps(state.allCamps, {
			                    force: state.tickCount <= 2 || state.tickCount % 4 === 0,
			                    selectedOnly: true,
			                    activeOnly: false,
			                    persistRoom: true,
			                    log: state.tickCount <= 2
			                });
			            if (!state.running || state._ending) return;
			            let currentRoomId = lockedRoomId || activeRoomResult.roomId || lbGetMetricRoomId();
			            if (currentRoomId && state.allCamps.length) {
	                let shouldSearchRoomCamp = !lockedRoomId && (state.tickCount <= 2
	                    || !state._currentRoomMatchedCampId
	                    || !state.selectedCampIds.has(String(state._currentRoomMatchedCampId))
	                    || state.tickCount % 4 === 0);
	                if (shouldSearchRoomCamp) {
	                    await lbRefreshRoomMatchedSelection(state.allCamps, {
	                        roomId: currentRoomId,
	                        forceFetch: state.tickCount <= 2 || state.tickCount % 4 === 0
	                    });
	                    if (!state.running || state._ending) return;
	                }
	            }
            let camps = state.allCamps;
            // Filter to only selected camps
            if (camps && camps.length > 0) {
                camps = camps.filter(c => state.selectedCampIds.has(String(c.id)));
            }
            if (!camps || camps.length === 0) {
                // Track consecutive empty ticks
                state._emptyTicks = (state._emptyTicks || 0) + 1;
                if (state.tickCount <= 3) {
                    lbLog('📺 Không tìm thấy camp đã chọn (kiểm tra checkbox camp)', 'info');
                } else if (state._emptyTicks >= 3 && state._emptyTicks < 5) {
                    lbLog(`📺 Không có camp (${state._emptyTicks} tick liên tiếp)`, 'info');
                }

                // Only auto-stop if we previously HAD running camps (real LIVE ended)
	                if (state._emptyTicks >= 5 && state.tickCount > 5 && state._hadRunningCamps) {
	                    if (!lbBeginLiveEndOnce('auto_no_selected_camps')) return;
	                    lbLog('🔴 Phiên LIVE đã kết thúc — tự động dừng engine', 'info');
			                    if (isNotifyReady(cfg)) {
			                        let runtime = Math.round((Date.now() - state.startTime) / 60000);
			                        let liveData = cfg.data_live_dash_enabled ? (window.__STRANGETTS_LIVE_DASHBOARD__ || null) : null;
			                        await lbRefreshResultRoomMetricsForSummary();
			                        let ld = state._liveDuration || 0;
			                        let durStr = ld > 0 ? (Math.floor(ld / 3600) + 'h' + String(Math.floor((ld % 3600) / 60)).padStart(2, '0') + 'p') : '';
					                    let resultLines = lbLiveResultLines(liveData, { durationText: durStr, runtimeMin: runtime, endedAt: new Date() });
				                        await strangettsNotifySend(
			                            `${getLiveAccountLabel()}\n🔴 <b>LIVE ĐÃ KẾT THÚC</b>\n` +
		                            `⏱ Thời gian theo dõi: ${runtime} phút\n` +
		                            resultLines +
		                            `📊 Số lần quét: ${state.tickCount} | Điều chỉnh nhanh: ${state.instantCount} | Đánh giá định kỳ: ${state.scheduledCount}\n` +
		                            `✅ Hệ thống đã tự dừng.`, cfg
		                        );
		                    }
			                    try {
			                        let runtime = Math.round((Date.now() - state.startTime) / 60000);
			                        await lbSendLiveEndSummaryOnly(cfg, { runtimeMin: runtime, durationText: durStr, endedAt: new Date(), reason: 'no_selected_camps_end' });
			                    } catch (e) {
			                        console.warn('[STRANGE TTS] live summary channel send failed:', e);
			                    }
	                    stopEngine('auto_no_selected_camps');
	                    return;
	                }
                state.camps = [];
                renderCampList();
                lbUpdateMonitor();
                return;
            }
            // Reset empty tick counter when camps are found
            state._emptyTicks = 0;
            // Track if we ever had running camps (for auto-stop logic)
	            let hasRunning = camps.some(c => lbIsCampActive(c) || strangettsRoomSessionIsActive(c.__roomSession));
		    if (hasRunning) state._hadRunningCamps = true;
		    state.camps = camps;
			    let roomApplied = activeRoomResult.applied || await lbApplyCurrentRoomMetricsToCamps(state.camps, currentRoomId, { force: state.tickCount <= 2 || !!lockedRoomId, allowHistory: !!lockedRoomId });
	            if (roomApplied > 0 && state.strategy?.session_budget_source !== 'room_id') {
	                lbRebaseStrategyToRoomSession(state.camps, 'Ads vừa trả room cho camp');
	            }

	            // Update snapshots (only selected)
	            state.camps.forEach(c => addSnapshot(c));

            // Render
            renderCampList();

            // === LEVEL 3 DATA POLLING (only if Cấp 3 checkbox is checked) ===
            let lv3Toggle = document.getElementById('lb-lv3-toggle');
	            if (lv3Toggle && lv3Toggle.checked) {
	                try { await lbPollLevel3(); } catch (e) { console.warn('[STRANGE TTS] LV3 poll error:', e); }
	                if (!state.running || state._ending) return;
	            }

	            // Check instant triggers for each camp
	            for (let camp of camps) {
	                if (!state.running || state._ending) return;
	                let trigger = await checkInstantTriggers(cfg, camp);
	                if (!state.running || state._ending) return;
	                if (trigger) {
                    let oldBudget = parseFloat(String(camp.budget || '0').replace(/\./g, '').replace(/,/g, '')) || 0;
	                    let applied = await applyBudgetIncrease(camp, trigger.addBudget, trigger.reason, { source: 'instant' });
                    // Send Telegram for instant trigger adjustments
	                    if (applied && isNotifyReady(cfg)) {
	                        let newBudget = oldBudget + trigger.addBudget;
	                        let roiRamp = camp.__lastBudgetRoiRamp || null;
	                        let teleMsg = `${getLiveAccountLabel()}\n⚡ <b>Điều chỉnh nhanh</b>\n`;
	                        teleMsg += `🎯 <b>${camp.name?.substring(0, 30) || camp.id}</b>\n`;
	                        teleMsg += `📐 Lý do: ${trigger.reason}\n`;
	                        teleMsg += `${lbCampActualMetricLines(camp)}\n`;
	                        teleMsg += `💰 NS: ${strangettsShortVN(oldBudget)} → ${strangettsShortVN(newBudget)} (+${strangettsShortVN(trigger.addBudget)})`;
	                        if (roiRamp) teleMsg += `\n🎯 ROI: ${roiRamp.oldRoi} → ${roiRamp.newRoi} (mốc ${roiRamp.targetRoi}/2h)`;
	                        await strangettsNotifySend(teleMsg, cfg);
		                }
	            }
            }

	            // Check scheduled review
	            let elapsedMin = Math.floor((Date.now() - state.startTime) / 60000);
	            let shouldScheduled = false;
	            let stratActive = !!(cfg.strat_enabled && state.strategy?.enabled);
	            let firstReviewMin = stratActive
	                ? Math.min(parseInt(cfg.sched_first_min, 10) || 30, parseInt(cfg.strat_first_review_min, 10) || 10)
	                : (parseInt(cfg.sched_first_min, 10) || 30);
	            let reviewIntervalMin = stratActive
	                ? Math.min(parseInt(cfg.sched_interval_min, 10) || 20, parseInt(cfg.strat_review_interval_min, 10) || 10)
	                : (parseInt(cfg.sched_interval_min, 10) || 20);

	            if (!state.firstScheduledDone && elapsedMin >= firstReviewMin) {
	                shouldScheduled = true;
	                state.firstScheduledDone = true;
	            } else if (state.firstScheduledDone) {
	                let sinceLast = Math.floor((Date.now() - state.lastScheduledTime) / 60000);
	                if (sinceLast >= reviewIntervalMin) shouldScheduled = true;
	            }

            if (shouldScheduled) {
                state.lastScheduledTime = Date.now();
                state.scheduledCount++;
	                lbLog(`📋 Đánh giá định kỳ #${state.scheduledCount} (${strangettsFormatMinutes(elapsedMin)} đang chạy)`, 'scheduled');

                let liveData = cfg.data_live_dash_enabled ? (window.__STRANGETTS_LIVE_DASHBOARD__ || null) : null;

                // Build aggregated engine state for Gemini context
                let firstScore = state.camps.length > 0 ? strangettsLiveScore(state.camps[0], liveData, cfg) : null;
                let aggEngineState = firstScore ? {
                    score: firstScore.totalScore,
                    qualityGateBlocked: firstScore.qualityGateBlocked,
                    action: firstScore.action,
                    guardrailReason: firstScore.guardrailReason || ''
                } : {};

                // Gemini AI analysis (all camps at once)
                let aiResults = null;
                if (cfg.gemini_enabled && cfg.gemini_api_key) {
	                    lbLog('🤖 Đang hỏi Gemini AI...', 'info');
	                    try {
		                        aiResults = await strangettsGeminiAnalyze(state.camps, liveData, cfg, aggEngineState, 'scheduled_review', lbBuildGeminiExtraContext());
		                        if (!state.running || state._ending) return;
	                        if (aiResults) {
                            aiResults.forEach(ar => {
                                state.aiResults[ar.name] = ar;
                            });
                            lbLog(`🤖 Gemini trả ${aiResults.length} gợi ý`, 'success');
                        }
                    } catch (e) { lbLog(`🤖 Gemini lỗi: ${e.message}`, 'error'); }
                }

	                for (let camp of state.camps) {
	                    if (!state.running || state._ending) return;
	                    let score = strangettsLiveScore(camp, liveData, cfg);
                    let aiResult = state.aiResults[String(camp.id)] || state.aiResults[camp.name] || null;

                    lbLog(`📋 ${camp.name?.substring(0, 25) || camp.id}: ${score.emoji} Score ${score.totalScore}/100 — ${score.actionText}`, score.action.startsWith('scale') ? 'scheduled' : 'info');

	                    // Decide budget action based on score
	                    if (score.budgetAdd > 0 && cfg.data_ads_enabled && stratActive && cfg.strat_owns_scheduled_writes !== false) {
	                        lbLog(`⚡ V3 đang bật: Score Engine chỉ báo cáo, quyền sửa NS/ROI do V3 xử lý`, 'info');
	                    } else if (score.budgetAdd > 0 && cfg.data_ads_enabled) {
                        let actionId = `act_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
                        let timeoutMin = cfg.telegram_action_timeout_min || 5;

                        if (isTelegramReady(cfg) && cfg.telegram_mode === 'confirm') {
                            // === CONFIRM MODE: ask Telegram first ===
                            let teleMsg = strangettsTelegramFormatReport(camp, score, aiResult, lv3State.creatorName);
                            teleMsg += `\n🆔 <code>${actionId}</code>`;
                            teleMsg += `\n⏳ <b>Reply "ok" để duyệt, "no" để bỏ</b> (${timeoutMin} phút)`;
                            let msgId = await strangettsNotifySend(teleMsg, cfg);
                            if (msgId) {
                                // Track pending action
                                state.pendingConfirms.push({
                                    actionId, campId: camp.id, campName: camp.name,
                                    budgetAdd: score.budgetAdd, score: score.totalScore,
                                    oldBudget: parseFloat(String(camp.budget || '0').replace(/\./g, '').replace(/,/g, '')) || 0,
                                    msgId, sentAt: Date.now(), expiresAt: Date.now() + timeoutMin * 60000,
                                });
                                lbLog(`📱 Gửi Telegram chờ duyệt [${actionId}]: ${camp.name?.substring(0, 20)}`, 'scheduled');

	                                let reply = await strangettsTelegramPollConfirm(cfg, msgId, timeoutMin * 60000);
	                                if (!state.running || state._ending) return;
	                                // Remove from pending
                                state.pendingConfirms = state.pendingConfirms.filter(p => p.actionId !== actionId);

                                if (reply === 'approved') {
                                    // === LOCK: prevent double-apply ===
                                    if (state._executingAction) {
                                        lbLog(`🔒 Đang thực thi action khác, bỏ qua`, 'info');
                                        continue;
                                    }
                                    state._executingAction = actionId;
                                    try {
	                                        // === STATE RECHECK: verify budget hasn't changed ===
	                                        let freshCamps = await strangettsFetchCampaignListApi('today', ['no_delete'], ['305']);
	                                        if (!state.running || state._ending) return;
	                                        let freshCamp = freshCamps?.find(fc => String(fc.id) === String(camp.id));
                                        if (freshCamp) {
                                            let freshBudget = parseFloat(String(freshCamp.budget || '0').replace(/\./g, '').replace(/,/g, '')) || 0;
                                            let originalBudget = parseFloat(String(camp.budget || '0').replace(/\./g, '').replace(/,/g, '')) || 0;
                                            if (Math.abs(freshBudget - originalBudget) > 1000) {
                                                lbLog(`⚠️ Budget đã thay đổi (${strangettsShortVN(originalBudget)} → ${strangettsShortVN(freshBudget)}), bỏ action`, 'error');
                                                await strangettsNotifySend(`⚠️ Budget thay đổi, action [${actionId}] bị hủy cho ${camp.name?.substring(0, 30)}`, cfg);
                                                continue;
                                            }
                                        }
		                                        await applyBudgetIncrease(camp, score.budgetAdd, `${score.emoji} Score ${score.totalScore} — Telegram approved [${actionId}]`, { source: 'scheduled' });
	                                        if (!state.running || state._ending) return;
	                                        await strangettsNotifySend(
                                            `✅ Đã duyệt [${actionId}]! NS +${strangettsShortVN(score.budgetAdd)} cho ${camp.name?.substring(0, 30)}\n` +
                                            lbCampActualMetricLines(camp),
                                            cfg
                                        );
                                    } finally {
                                        state._executingAction = null;
                                    }
                                } else {
                                    lbLog(`📱 ${reply === 'rejected' ? 'Bị từ chối' : 'Hết thời gian'}: ${camp.name?.substring(0, 20)}`, reply === 'rejected' ? 'error' : 'info');
                                    await strangettsNotifySend(`${reply === 'rejected' ? '❌ Đã bỏ qua' : '⏰ Hết thời gian chờ'} [${actionId}]: ${camp.name?.substring(0, 30)}`, cfg);
                                }
                            }
                        } else {
                            // === AUTO MODE: apply immediately ===
                            if (state._executingAction) continue;
                            state._executingAction = actionId;
	                            try {
			                                await applyBudgetIncrease(camp, score.budgetAdd, `${score.emoji} Score ${score.totalScore} [${actionId}]`, { source: 'scheduled' });
			                                if (!state.running || state._ending) return;
		                                if (isNotifyReady(cfg)) {
	                                    let teleMsg = strangettsTelegramFormatReport(camp, score, aiResult, lv3State.creatorName);
	                                    teleMsg += `\n${lbCampActualMetricLines(camp)}\n`;
	                                    teleMsg += `\n✅ <b>Đã tự động tăng NS +${strangettsShortVN(score.budgetAdd)}</b> [${actionId}]`;
	                                    if (camp.__lastBudgetRoiRamp) {
	                                        teleMsg += `\n🎯 <b>ROI ${camp.__lastBudgetRoiRamp.oldRoi} → ${camp.__lastBudgetRoiRamp.newRoi}</b> (mốc ${camp.__lastBudgetRoiRamp.targetRoi}/2h)`;
	                                    }
	                                    await strangettsNotifySend(teleMsg, cfg);
	                                }
                            } finally {
                                state._executingAction = null;
                            }
                        }
                    } else if (isNotifyReady(cfg) && score.action === 'stop') {
                        let teleMsg = strangettsTelegramFormatReport(camp, score, aiResult, lv3State.creatorName);
                        await strangettsNotifySend(teleMsg, cfg);
                    }

                    // ═══════════════════════════════════════════════════════════
                    // STRATEGY V3 (mới) hoặc RULE ENGINE V1 (cũ) — feature flag
                    // ═══════════════════════════════════════════════════════════
                    if (cfg.strat_enabled && state.strategy?.enabled) {
                        // LOCK: skip V3 block nếu action đang chạy
                        if (state._executingAction) {
                            lbLog(`🔒 [STRAT] busy, skip tick`, 'info');
                        } else {
                            // Chỉ chạy một lần cho primary camp (tránh multi-camp double write)
                            // primary = camp spend cao nhất trong selected set
                            if (!state._stratHandledThisTick) {
                                state._stratHandledThisTick = true;

                                const selectedCamps = state.camps.filter(c => state.selectedCampIds.has(String(c.id)));
                                const _pn = v => parseFloat(String(v||'0').replace(/\./g,'').replace(/,/g,'')) || 0;
                                const primaryCamp = selectedCamps.reduce((best, c) =>
                                    _pn(c.spend) > _pn(best?.spend) ? c : best
                                , selectedCamps[0] || null);

                                if (primaryCamp) {
                                    const primarySpend = _pn(primaryCamp.spend);
                                    const primaryGmv = _pn(primaryCamp.gmv);
                                    const currentDayKey = strangettsDayKey();
                                    const dayRolled = state.strategy.session_day_key && state.strategy.session_day_key !== currentDayKey;
                                    const switchedCamp = state.strategy.active_campaign_id && state.strategy.active_campaign_id !== String(primaryCamp.id);
                                    const spendReset = state.strategy.last_checkpoint_spend != null && primarySpend + 1000 < state.strategy.last_checkpoint_spend;

                                    if (dayRolled || switchedCamp || spendReset) {
                                        let resetReason = dayRolled ? 'qua ngày mới'
                                            : switchedCamp ? `đổi camp chính -> ${String(primaryCamp.id).slice(-6)}`
                                                : 'chi tiêu ngày mới reset';
                                        lbResetStrategySession(primaryCamp, primarySpend, primaryGmv, resetReason);
                                    }

                                    // Safety fill nếu startEngine chưa fill được
                                    if (state.strategy.start_spend === null) {
                                        state.strategy.active_campaign_id = String(primaryCamp.id);
                                        state.strategy.session_day_key = currentDayKey;
                                        state.strategy.start_spend = primarySpend;
                                        state.strategy.start_gmv   = primaryGmv;
                                        state.strategy.last_checkpoint_spend = primarySpend;
                                    }

                                    const dash = cfg.data_live_dash_enabled ? (window.__STRANGETTS_LIVE_DASHBOARD__ || null) : null;

                                    // Rolling metrics — CHỈ primary camp, 1 snapshot/tick
                                    strangettsUpdateRollingMetrics(state.strategy, primaryCamp, dash, Date.now());

                                    const dec = lbGetDueManualStrategyDecision(primaryCamp, cfg, state.strategy)
                                        || strangettsEvalLiveStrategy(primaryCamp, state.strategy, cfg, dash, primarySpend, primaryGmv);
                                    lbLog(`[${dec.phase}] ${dec.emoji} ${dec.reason}`,
                                        dec.action === 'no_action' ? 'info' : 'scheduled');

                                    // Log secondary camps (info only, không write)
                                    for (let sc of selectedCamps.filter(x => String(x.id) !== String(primaryCamp.id)))
                                        lbLog(`📊 [STRAT•sec] ${sc.name?.substring(0,20)}: spend=${strangettsShortVN(_pn(sc.spend))}`, 'info');

		                                    if (!['no_action','evaluate_only','hold','freeze','protect_roi'].includes(dec.action) && cfg.data_ads_enabled) {
		                                        if (!dec.write_budget && !dec.write_roi) {
		                                            lbLog(`[STRAT] skip write: ${dec.reason}`, 'info');
		                                            continue;
		                                        }
		                                        if (dec.write_budget && dec.new_budget && dec.phase !== 'MANUAL') {
		                                            let campaignBudgetTarget = parseNum(state.strategy.campaign_budget_target);
		                                            let currentCampaignBudget = parseNum(primaryCamp.budget);
		                                            let wantsBeyondUserBudget = campaignBudgetTarget > 0 && dec.new_budget > campaignBudgetTarget + 1000;
		                                            if (wantsBeyondUserBudget && currentCampaignBudget < campaignBudgetTarget - 1000) {
		                                                dec.new_budget = campaignBudgetTarget;
		                                                dec.reason += ` | chạm trần NS phiên ${strangettsShortVN(campaignBudgetTarget)}`;
		                                                lbLog(`[STRAT] Cap action về đúng trần NS phiên ${strangettsShortVN(campaignBudgetTarget)}`, 'info');
		                                            } else if (wantsBeyondUserBudget) {
		                                                let roiStrongEnough = (state.strategy.rolling_roi_15m || 0) >= (state.strategy.target_roi || 0);
		                                                if (!roiStrongEnough) {
		                                                    dec.write_budget = false;
		                                                    dec.new_budget = null;
		                                                    dec.reason += ` | chặn vượt NS phiên vì ROI ${Number(state.strategy.rolling_roi_15m || 0).toFixed(2)} < mục tiêu ${state.strategy.target_roi}`;
		                                                    lbLog(`[STRAT] Giữ trần NS phiên ${strangettsShortVN(campaignBudgetTarget)}: ROI chưa đạt mục tiêu nên không nới thêm`, 'info');
		                                                } else {
		                                                    dec.extend_budget_cap = Math.max(dec.extend_budget_cap || 0, Math.ceil((dec.new_budget - campaignBudgetTarget) / 1000) * 1000);
		                                                    lbLog(`[STRAT] Cho phép vượt NS phiên vì ROI đạt: ${Number(state.strategy.rolling_roi_15m || 0).toFixed(2)} ≥ ${state.strategy.target_roi}`, 'scheduled');
		                                                }
		                                            }
		                                        }
		                                        if (!dec.write_budget && !dec.write_roi) {
		                                            lbLog(`[STRAT] skip write sau guard NS phiên: ${dec.reason}`, 'info');
		                                            continue;
		                                        }
		                                        const actionId = `strat_${dec.phase}_${Date.now()}_${Math.random().toString(36).slice(2,6)}`;
		                                        let budgetOk = false, roiOk = false, addAmt = 0;

	                                        if (dec.write_budget && dec.new_budget) {
	                                            addAmt = dec.new_budget - _pn(primaryCamp.budget);
                                            state._executingAction = actionId;
                                            try {
	                                                budgetOk = await applyBudgetIncrease(primaryCamp, addAmt, `[STRAT ${dec.phase}] ${dec.reason}`, {
	                                                    source: 'strat',
	                                                    newRoi: dec.write_roi ? dec.new_roi : undefined
	                                                });
                                                state.strategy.api_last_edit_ok = !!budgetOk;
		                                                if (budgetOk) {
	                                                    state.strategy.last_budget_edit_at = Date.now();
	                                                    state.strategy.budget_edit_count++;
	                                                    state.strategy.p1_budget_added += addAmt;
	                                                    if (dec.write_roi && dec.new_roi) {
	                                                        roiOk = true;
	                                                        state.strategy.last_roi_edit_at = Date.now();
	                                                        state.strategy.roi_edit_count++;
	                                                        if (!state.strategy.p1_roi_set && ['P1A','P1B'].includes(dec.phase))
	                                                            state.strategy.p1_roi_set = true;
	                                                    }
	                                                    if (dec.extend_budget_cap > 0) {
	                                                        state.strategy.budget_cap += dec.extend_budget_cap;
	                                                    }
	                                                    if (dec.manual_key) {
	                                                        [...(dec.manual_mark_keys || []), dec.manual_key].forEach(key => { state.strategy.manual_adjust_applied[key] = Date.now(); });
	                                                    }
		                                                }
		                                            } finally { state._executingAction = null; }
		                                            if (!state.running || state._ending) return;
		                                        }

		                                        if (dec.write_roi && dec.new_roi && !dec.write_budget) {
                                            state._executingAction = actionId + '_roi';
                                            try {
	                                                roiOk = await applyRoiChange(primaryCamp, dec.new_roi, `[STRAT ${dec.phase}] ${dec.reason}`, { absolute: true, minRoi: lbGetConfiguredInitialRoi(cfg, LIVE_START_BASELINE_ROI) });
                                                state.strategy.api_last_edit_ok = !!roiOk;
                                                if (roiOk) {
                                                    state.strategy.last_roi_edit_at = Date.now();
                                                    state.strategy.roi_edit_count++;
                                                    if (!state.strategy.p1_roi_set && ['P1A','P1B'].includes(dec.phase))
                                                        state.strategy.p1_roi_set = true;
	                                                if (dec.manual_key) {
	                                                    [...(dec.manual_mark_keys || []), dec.manual_key].forEach(key => { state.strategy.manual_adjust_applied[key] = Date.now(); });
	                                                }
	                                                }
	                                            } finally { state._executingAction = null; }
	                                            if (!state.running || state._ending) return;
	                                        }

		                                        if (budgetOk || roiOk) {
		                                            if (!state.running || state._ending) return;
		                                            state.strategy.last_checkpoint_spend = primarySpend;
	                                            if (isNotifyReady(cfg)) {
	                                                let ramp = primaryCamp.__lastBudgetRoiRamp || null;
	                                                let teleMsg = `${getLiveAccountLabel()}\n⚡ <b>Strategy V3 ${dec.phase}</b>\n`;
	                                                teleMsg += `🎯 <b>${primaryCamp.name?.substring(0, 30) || primaryCamp.id}</b>\n`;
	                                                teleMsg += `📐 ${dec.reason}\n`;
	                                                teleMsg += `${lbCampActualMetricLines(primaryCamp)}\n`;
	                                                if (budgetOk) teleMsg += `💰 NS +${strangettsShortVN(addAmt)}\n`;
	                                                if (roiOk && ramp) teleMsg += `🎯 ROI ${ramp.oldRoi} → ${ramp.newRoi} (mốc ${ramp.targetRoi}/2h)\n`;
	                                                else if (roiOk && dec.new_roi) teleMsg += `🎯 ROI → ${dec.new_roi}\n`;
	                                                if (dec.metrics_snapshot?.pace_status) {
	                                                    teleMsg += `📊 ${dec.metrics_snapshot.pace_status} | ROI15 ${dec.metrics_snapshot.rolling_roi} | DT ${dec.metrics_snapshot.revenue_attainment}`;
	                                                }
	                                                await strangettsNotifySend(teleMsg.trim(), cfg);
	                                            }
	                                        }
                                    }
                                }
                            }
                        }
                    } else {
                        // ═══ RULE ENGINE V1 — GIỮ NGUYÊN 100% ═══
                        if (cfg.data_ads_enabled && typeof evaluateLiveCamp === 'function') {
                            // Inject last adjust time from state
                            let campWithTime = { ...camp, _last_adjust_time: state.lastInstantTime[String(camp.id)] || 0 };
                            // Get config for rule engine (uses different config keys)
                            let ruleConfig = await strangettsGetLiveAdjustConfig();
                            let ruleResult = evaluateLiveCamp(ruleConfig, campWithTime);

                            if (ruleResult && ruleResult.action !== 'hold' && ruleResult.status !== 'cooldown' && ruleResult.status !== 'not_enough_data' && ruleResult.status !== 'collecting_data') {
                                await applyRuleAction(camp, ruleResult, cfg);
                            } else if (ruleResult) {
                                lbLog(`📐 Rule: ${camp.name?.substring(0, 25) || camp.id}: ${ruleResult.emoji} ${ruleResult.message}`, 'info');
                            }
                        }
                    }
                }
                // Reset flag sau khi xong for-loop
                state._stratHandledThisTick = false;


                // === AI AUTO-COMMENTARY: summarize decisions + send to Telegram ===
	                if (cfg.gemini_enabled && cfg.gemini_api_key && aiResults && aiResults.length > 0 && isNotifyReady(cfg)) {
	                    try {
	                        if (!state.running || state._ending) return;
			                        let aiSummary = `${getLiveAccountLabel()}\n🤖 <b>AI nhận xét lần đánh giá #${state.scheduledCount}</b>\n`;
		                        if (aiResults._modelUsed) aiSummary += `🧠 Model: <b>${strangettsGeminiModelLabel(aiResults._modelUsed)}</b>\n`;
	                        aiResults.forEach(r => {
	                            let conf = r.confidence === 'high' ? '🟢' : r.confidence === 'medium' ? '🟡' : '🔴';
	                            aiSummary += `\n\n${conf} <b>${strangettsGeminiShortText(r.name || '', 80)}</b>`;
	                            if (r.summary) aiSummary += `\n📝 ${strangettsGeminiShortText(r.summary, 220)}`;
	                            if (r.risk) aiSummary += `\n⚠️ ${strangettsGeminiShortText(r.risk, 220)}`;
	                            if (r.suggestion) aiSummary += `\n💡 ${strangettsGeminiShortText(r.suggestion, 240)}`;
	                        });
                        // Add revenue context
                        let startEl = document.getElementById('lb-live-start');
                        let endEl = document.getElementById('lb-live-end');
                        if (startEl?.value && endEl?.value) {
                            let revTarget = document.getElementById('lb-rev-target')?.textContent;
                            let revProj = document.getElementById('lb-rev-projected')?.textContent;
                            let timeRemain = document.getElementById('lb-time-remain')?.textContent;
                            if (revTarget && revTarget !== '—') {
                                aiSummary += `\n\n💰 DT mục tiêu: ${revTarget} | Dự kiến: ${revProj || '—'} | Còn: ${timeRemain || '—'}`;
                            }
                        }
	                        if (!state.running || state._ending) return;
	                        await strangettsNotifySend(aiSummary, cfg);
                    } catch (e) { console.warn('[STRANGE TTS] AI commentary error:', e); }
                }

                // Re-render with AI results
                renderCampList();
            }

	        // Save state + cleanup memory every 5 ticks
	        if (state.tickCount % 5 === 0) {
            lbSaveState();
            lbCleanupMemory();
        }
        state._consecutiveErrors = 0;

        // Viewer=0 / GMV stuck → WARNING only, do NOT stop
        let liveStats = window.__STRANGETTS_LIVE_DASHBOARD__;
        if (liveStats && state.tickCount > 5) {
            let currentGmv = liveStats.gmv || 0;
            let viewers = liveStats.viewers || 0;
            if (viewers === 0 || (state._lastLiveGmv !== null && currentGmv === state._lastLiveGmv && currentGmv > 0)) {
                state._staleStatsTicks = (state._staleStatsTicks || 0) + 1;
                if (state._staleStatsTicks === 3 || state._staleStatsTicks % 10 === 0)
                    lbLog(`⚠️ Stats không đổi ${state._staleStatsTicks} tick (viewer=${viewers}, GMV=${strangettsFormatVN(currentGmv)}) — chỉ cảnh báo, không dừng`, 'info');
            } else {
                state._staleStatsTicks = 0;
            }
            state._lastLiveGmv = currentGmv;
        }

        // === HEARTBEAT AUTO-STOP CHECK (uses state from 60s heartbeat timer) ===
        if (state.tickCount > 3) {
            // status=0 confirmed 2+ times → LIVE ended
	            if (state._roomStatusOffCount >= 2) {
	                if (!lbBeginLiveEndOnce('auto_live_end')) return;
	                let ld = state._liveDuration || 0;
	                let durStr = Math.floor(ld / 3600) + 'h' + String(Math.floor((ld % 3600) / 60)).padStart(2, '0') + 'p';
	                lbLog('🔴 Phiên LIVE đã kết thúc (xác nhận qua room/status API)', 'info');
		                if (isNotifyReady(cfg)) {
		                    let runtime = Math.round((Date.now() - state.startTime) / 60000);
			                    let liveData = cfg.data_live_dash_enabled ? (window.__STRANGETTS_LIVE_DASHBOARD__ || null) : null;
			                    await lbRefreshResultRoomMetricsForSummary();
				                    let resultLines = lbLiveResultLines(liveData, { durationText: durStr, runtimeMin: runtime, endedAt: new Date() });
		                    await strangettsNotifySend(
	                        `${getLiveAccountLabel()}\n🔴 <b>LIVE ĐÃ KẾT THÚC</b>\n` +
	                        `⏱ Thời gian theo dõi: ${runtime} phút | Thời lượng live: ${durStr}\n` +
	                        resultLines +
	                        `📊 Số lần quét: ${state.tickCount} | Điều chỉnh nhanh: ${state.instantCount} | Đánh giá định kỳ: ${state.scheduledCount}\n` +
	                        `✅ Hệ thống đã tự dừng.`, cfg
	                    );
	                }
			                try {
			                    let runtime = Math.round((Date.now() - state.startTime) / 60000);
			                    await lbSendLiveEndSummaryOnly(cfg, { runtimeMin: runtime, durationText: durStr, endedAt: new Date(), reason: 'room_status_end' });
			                } catch (e) {
			                    console.warn('[STRANGE TTS] live summary channel send failed:', e);
			                }
	                stopEngine('auto_live_end');
                return;
            }
            // 10+ consecutive heartbeat errors → fallback stop
	            if (state._roomStatusErrCount >= 10) {
	                if (!lbBeginLiveEndOnce('auto_heartbeat_lost')) return;
	                lbLog('🔴 Mất heartbeat quá lâu (10 lần) — tự dừng engine', 'info');
		                if (isNotifyReady(cfg)) {
		                    let runtime = state.startTime ? Math.round((Date.now() - state.startTime) / 60000) : 0;
		                    let liveData = cfg.data_live_dash_enabled ? (window.__STRANGETTS_LIVE_DASHBOARD__ || null) : null;
		                    await lbRefreshResultRoomMetricsForSummary();
		                    let resultLines = lbLiveResultLines(liveData, { runtimeMin: runtime, endedAt: new Date() });
	                    await strangettsNotifySend(
	                        `${getLiveAccountLabel()}\n🔴 <b>MẤT TÍN HIỆU KIỂM TRA LIVE</b>\n` +
	                        resultLines +
	                        `📊 Đã quét ${state.tickCount} lần — không lấy được trạng thái live ${state._roomStatusErrCount} lần liên tiếp\n` +
	                        `✅ Hệ thống đã tự dừng an toàn.`, cfg
	                    );
	                }
                stopEngine('auto_heartbeat_lost');
                return;
            }
        }

	        lbUpdateMonitor();
	        } catch (err) {
	            lbLog(`❌ Poll error: ${err.message}`, 'error');
	            state._consecutiveErrors = (state._consecutiveErrors || 0) + 1;
	            if (state._consecutiveErrors >= 10) {
	                lbLog('🔴 Quá nhiều lỗi liên tiếp — tự động dừng!', 'error');
	                if (!lbBeginLiveEndOnce('auto_error')) return;
	                if (isNotifyReady(cfg)) strangettsNotifySend(`${getLiveAccountLabel()}\n🔴 Hệ thống theo dõi live tự dừng do lỗi liên tiếp. Cần kiểm tra tab trình duyệt.`, cfg);
	                stopEngine('auto_error');
	                return;
	            }
	        } finally {
	            state._pollBusy = false;
	        }
    }

    // ===== LIVE HEARTBEAT (independent 60s timer) =====
    let _heartbeatTimer = null;
    async function _liveHeartbeatFetch() {
        if (!state.running || state._ending) return;
        let roomId = lbGetMetricRoomId();
        if (!roomId) return;
        try {
            let roomData = await lbFetchRoomStatus(roomId);
            if (roomData && roomData.status !== undefined) {
                state._roomStatusErrCount = 0;
                state._liveDuration = roomData.duration || 0;
                let ld = state._liveDuration;
                let durStr = Math.floor(ld / 3600) + 'h' + String(Math.floor((ld % 3600) / 60)).padStart(2, '0') + 'p';
                // Update UI
                let durEl = document.getElementById('lb-ov-duration');
                if (durEl) durEl.textContent = durStr;

                if (roomData.status === 1) {
                    state._roomStatusOffCount = 0;
                    state._liveRoomConfirmed = true;
                    state._liveRoomConfirmedRoomId = String(roomId);
                    console.log(`[STRANGE TTS] 💓 Heartbeat OK — LIVE đang chạy (${durStr})`);
                } else {
                    state._roomStatusOffCount = (state._roomStatusOffCount || 0) + 1;
                    lbLog(`⚠️ Room status=${roomData.status} (${state._roomStatusOffCount}/2 — cần 2 nhịp liên tiếp để dừng)`, 'info');
                }
            } else {
                state._roomStatusErrCount = (state._roomStatusErrCount || 0) + 1;
            }
        } catch (e) {
            state._roomStatusErrCount = (state._roomStatusErrCount || 0) + 1;
            console.warn('[STRANGE TTS] Heartbeat error:', e.message);
        }
    }
    function _startHeartbeat() {
        _stopHeartbeat();
        _liveHeartbeatFetch(); // First fetch immediately
        _heartbeatTimer = setInterval(_liveHeartbeatFetch, 60000); // Then every 60s
    }
	    function _stopHeartbeat() {
	        if (_heartbeatTimer) { clearInterval(_heartbeatTimer); _heartbeatTimer = null; }
	    }

	    let _autoLiveTimer = null;
	    let _autoLiveState = {
	        enabled: false,
	        busy: false,
	        busySince: 0,
	        liveStartedAt: 0,
	        roomOnCount: 0,
	        campActiveSeen: false,
	        switchedAfterInactive: false,
	        lastEndedRoomId: '',
	        lastEndedAt: 0,
	    };

	    function lbSetAutoLiveButton(active, text) {
	        let btn = document.getElementById('lb-auto-live-toggle');
	        if (!btn) return;
	        btn.textContent = text || (active ? '🛰 Đang chờ' : '🛰 Auto');
	        btn.style.background = active ? 'linear-gradient(135deg,#0891B2,#06B6D4)' : 'rgba(34,211,238,0.16)';
	        btn.style.color = active ? 'white' : '#67E8F9';
	    }

	    function lbEnsureAutoLiveTimer() {
	        if (!_autoLiveTimer) _autoLiveTimer = setInterval(lbAutoLiveWatcherTick, 15000);
	    }

		    function lbForceCurrentLiveScan(reason = 'wake') {
		        if (!_autoLiveState?.enabled) return;
		        if (state._starting) return;
		        if (state.running) {
		            if (state._wakePollBusy) return;
		            state._wakePollBusy = true;
		            lbLog(`🛰 Wake poll: ${reason}`, 'info');
		            (async () => {
		                let cfg = state._cfg || await strangettsGetLiveBetaConfig();
		                await pollTick(cfg);
		            })().catch(e => lbLog(`🛰 Wake poll lỗi: ${e.message}`, 'error'))
		                .finally(() => { state._wakePollBusy = false; });
		            return;
		        }
		        if (_autoLiveState.busy) return;
		        lbLog(`🛰 Wake scan: ${reason}`, 'info');
		        lbAutoLiveWatcherTick();
		    }

			    function lbResetAutoLiveCycle(text = '🛰 Chờ ca mới', kickDelay = 3000) {
			        if (!state.running && state._ending) state._ending = false;
			        _autoLiveState.busy = false;
			        _autoLiveState.busySince = 0;
		        _autoLiveState.liveStartedAt = 0;
		        _autoLiveState.roomOnCount = 0;
		        _autoLiveState.campActiveSeen = false;
		        _autoLiveState.switchedAfterInactive = false;
		        // Keep lastEndedRoomId/lastEndedAt across cycles so stale Ads status
		        // cannot restart the same finished live session.
		        state._roomSessionCache = {};
			        state._currentRoomId = null;
			        state._resultRoomId = null;
			        state._currentRoomMatchedCampId = null;
			        state._currentRoomSession = null;
			        state._pendingStartRoomId = null;
			        state._pendingStartRoomSession = null;
			        state._pendingStartCampId = null;
		        lbSetAutoLiveButton(true, text);
		        lbEnsureAutoLiveTimer();
	        if (kickDelay >= 0) {
	            setTimeout(() => {
	                if (_autoLiveState.enabled && !state.running) lbAutoLiveWatcherTick();
	            }, kickDelay);
	        }
	    }

	    function lbMarkAutoLiveRunning(text = '🟢 Đang chạy') {
	        lbSetAutoLiveButton(true, text);
	        lbEnsureAutoLiveTimer();
	    }

	    function lbIsCampActive(camp) {
	        return String(camp?.status || '').includes('delivery_ok');
	    }

		    function lbSelectCampIds(ids, persist = true) {
		        state.selectedCampIds = new Set((ids || []).filter(Boolean).map(String));
		        if (persist) lbPersistSelectedCampIds();
		        lbSyncCampCheckboxSelection();
		    }

		    let _lbLevel1AutoScanPromise = null;
		    let _lbLevel1AutoScanAt = 0;
		    async function lbEnsureLevel1AdsLoaded(reason = 'auto', opts = {}) {
		        if (_lbLevel1AutoScanPromise) return _lbLevel1AutoScanPromise;
		        _lbLevel1AutoScanPromise = (async () => {
		            let clickUi = opts.clickUi !== false;
		            let force = !!opts.force;
		            let minIntervalMs = opts.minIntervalMs ?? 30000;
		            let btn = document.getElementById('lb-load-camps');
		            let canClick = clickUi && btn && !btn.disabled && typeof btn.click === 'function'
		                && (force || Date.now() - _lbLevel1AutoScanAt > minIntervalMs);
		            if (canClick) {
		                _lbLevel1AutoScanAt = Date.now();
		                lbLog(`🔄 Tự quét Cấp 1 Ads (${reason})`, 'info');
		                btn.click();
		                let end = Date.now() + (opts.waitMs || 10000);
		                while (btn.disabled && Date.now() < end) {
		                    await new Promise(r => setTimeout(r, 250));
		                }
		            }
		            if (!Array.isArray(state.allCamps) || !state.allCamps.length || opts.rawFallback) {
		                let camps = await strangettsFetchCampaignListApi('today', ['no_delete'], ['305']);
		                state.allCamps = camps || state.allCamps || [];
		            }
		            return state.allCamps || [];
		        })().finally(() => { _lbLevel1AutoScanPromise = null; });
		        return _lbLevel1AutoScanPromise;
		    }

		    async function lbFetchLiveCampsForWatcher() {
		        return await lbEnsureLevel1AdsLoaded('watcher', {
		            clickUi: true,
		            rawFallback: true,
		            minIntervalMs: 30000
		        });
		    }

		    async function lbStartEngineFromWatcher(reason, camps) {
		        if (camps?.length) {
		            let existingRoomId = String((camps.find(c => c.__roomSession?.roomId) || {}).__roomSession?.roomId || '').match(/\d{10,}/)?.[0] || '';
		            let roomResult = existingRoomId
		                ? { applied: 1, roomId: existingRoomId, camp: camps.find(c => String(c.__roomSession?.roomId) === existingRoomId), session: camps.find(c => String(c.__roomSession?.roomId) === existingRoomId)?.__roomSession || null }
		                : await lbApplyActiveRoomMetricsToCamps(camps, {
		                    force: true,
		                    activeOnly: false,
		                    persistRoom: true,
		                    log: true
		                });
		            if (!state.running && !roomResult?.roomId) {
		                lbSetAutoLiveButton(true, '🛰 Chờ room');
		                lbLog('⏳ Chưa có room_id live_status=1 từ post_room_list nên chưa bật Auto-Adjust.', 'info');
		                return;
		            }
		            if (!state.running && roomResult?.roomId) {
		                state._pendingStartRoomId = String(roomResult.roomId);
		                state._pendingStartRoomSession = roomResult.session || null;
		                state._pendingStartCampId = roomResult.camp?.id || roomResult.camp?.campaign_id || null;
		            }
	            state.camps = camps.filter(c => state.selectedCampIds.has(String(c.id)));
	            state.camps.forEach(c => addSnapshot(c));
	            renderCampList();
	        }
	        if (!state.running) {
	            lbLog(`🛰 ${reason} → tự bật Auto-Adjust`, 'success');
	            await startEngine();
	        } else {
	            lbLog(`🛰 ${reason} → cập nhật camp đang theo dõi`, 'success');
	            renderCampList();
	            lbUpdateMonitor();
	        }
	    }

			    async function lbAutoLiveWatcherTick() {
			        if (!_autoLiveState.enabled) return;
			        if (state.running || state._starting || state._ending) {
			            if (state.running) lbMarkAutoLiveRunning();
			            return;
			        }
			        if (_autoLiveState.busy) {
		            if (_autoLiveState.busySince && Date.now() - _autoLiveState.busySince > 90000) {
		                lbLog('🛰 Watcher bị kẹt quá 90s — mở khóa để quét lại', 'error');
		                _autoLiveState.busy = false;
		                _autoLiveState.busySince = 0;
		            } else {
		                return;
		            }
		        }
		        _autoLiveState.busy = true;
		        _autoLiveState.busySince = Date.now();
		        try {
		            let selectedIds = [...state.selectedCampIds].map(String);
	            let camps = await lbWithTimeout(lbFetchLiveCampsForWatcher(), 12000, 'quét camp LIVE');
	            let selectedCamps = selectedIds.length ? camps.filter(c => selectedIds.includes(String(c.id))) : [];
	            let selectedActive = selectedCamps.some(lbIsCampActive);
	            let activeCamps = camps.filter(lbIsCampActive);
	            let selectedActiveRoom = selectedCamps.length
	                ? await lbWithTimeout(lbApplyActiveRoomMetricsToCamps(selectedCamps, {
	                    force: true,
	                    selectedOnly: false,
	                    activeOnly: false,
	                    persistRoom: true,
	                    log: true
	                }), 16000, 'lấy room live_status=1 từ camp đã chọn')
	                : null;
	            if (selectedActiveRoom?.applied) selectedActive = true;
	            let adsActiveRoom = (!selectedActiveRoom?.roomId && activeCamps.length)
	                ? await lbWithTimeout(lbApplyActiveRoomMetricsToCamps(activeCamps, {
	                    force: true,
	                    activeOnly: false,
	                    persistRoom: true,
	                    log: true
	                }), 16000, 'lấy room live_status=1 từ Ads')
	                : null;
	            let roomId = selectedActiveRoom?.roomId || adsActiveRoom?.roomId || null;
	            let now = Date.now();
	            if (roomId && !state.running && _autoLiveState.lastEndedRoomId === String(roomId) && now - (_autoLiveState.lastEndedAt || 0) < 10 * 60 * 1000) {
	                lbSetAutoLiveButton(true, '🛰 Chờ ca mới');
	                if (!_autoLiveState.lastEndedSkipLogAt || now - _autoLiveState.lastEndedSkipLogAt > 60000) {
	                    _autoLiveState.lastEndedSkipLogAt = now;
	                    lbLog(`🛰 Bỏ qua room vừa kết thúc (${String(roomId).slice(-8)}), chờ room mới để tránh spam restart`, 'info');
	                }
	                return;
	            }

	            if ((selectedActive || activeCamps.length) && !roomId && !state.running) {
	                _autoLiveState.campActiveSeen = true;
	                if (!_autoLiveState.liveStartedAt) _autoLiveState.liveStartedAt = now;
	                lbSetAutoLiveButton(true, '🛰 Chờ room');
	                if (!_autoLiveState.lastNoRoomLogAt || now - _autoLiveState.lastNoRoomLogAt > 60000) {
	                    _autoLiveState.lastNoRoomLogAt = now;
	                    lbLog('⏳ Camp Ads đang chạy nhưng post_room_list chưa trả room_id live_status=1. Auto tiếp tục chờ, không lấy room cũ/DOM.', 'info');
	                }
	                return;
	            }

	            if (selectedActive) {
	                _autoLiveState.campActiveSeen = true;
	                if (!_autoLiveState.liveStartedAt) _autoLiveState.liveStartedAt = now;
	                lbSetAutoLiveButton(true, '🟢 Camp chạy');
	                if (!state.running) {
	                    let selectedToRun = selectedCamps.filter(c => lbIsCampActive(c) || strangettsRoomSessionIsActive(c.__roomSession));
	                    lbSelectCampIds(selectedToRun.map(c => c.id));
	                    await lbStartEngineFromWatcher('Camp đã chọn chuyển sang hoạt động', selectedCamps);
	                }
	                lbMarkAutoLiveRunning();
	                return;
	            }

	            let roomLive = false;
	            if (roomId) {
	                if (selectedActiveRoom?.roomId || adsActiveRoom?.roomId) {
	                    roomLive = true;
	                    _autoLiveState.roomOnCount++;
	                } else {
	                    let roomData = await lbWithTimeout(lbFetchRoomStatus(roomId), 8000, 'kiểm tra trạng thái room');
	                    roomLive = roomData?.status === 1;
	                    _autoLiveState.roomOnCount = roomLive ? (_autoLiveState.roomOnCount + 1) : 0;
	                }
	                if (roomLive && camps.length) {
		                    let roomMatch = await lbWithTimeout(lbRefreshRoomMatchedSelection(camps, { roomId, forceFetch: false }), 15000, 'khớp room với camp Ads');
	                    if (roomMatch.match && (lbIsCampActive(roomMatch.match.camp) || strangettsRoomSessionIsActive(roomMatch.match.session)) && !state.running) {
		                        await lbStartEngineFromWatcher('Room khớp camp Ads đang chạy', [roomMatch.match.camp]);
		                        lbMarkAutoLiveRunning();
	                        return;
	                    }
	                }
	            }

	            if (adsActiveRoom?.camp && !state.running) {
	                lbSelectCampIds([adsActiveRoom.camp.id], true);
	                await lbStartEngineFromWatcher('post_room_list báo camp đang có phiên LIVE', [adsActiveRoom.camp]);
	                lbMarkAutoLiveRunning();
	                return;
	            }

	            if (roomLive && _autoLiveState.roomOnCount >= 2 && !_autoLiveState.liveStartedAt) {
	                _autoLiveState.liveStartedAt = now;
	                lbLog('🛰 Phát hiện phiên LIVE đang hoạt động qua room/status', 'success');
	            }
	            if (activeCamps.length && !_autoLiveState.liveStartedAt) {
	                _autoLiveState.liveStartedAt = now;
	                lbLog('🛰 Phát hiện LIVE qua camp ads đang hoạt động', 'success');
	            }

	            if (!_autoLiveState.liveStartedAt) {
	                lbSetAutoLiveButton(true, selectedIds.length ? '🛰 Chờ camp' : '🛰 Chờ live');
	                return;
	            }

		            let elapsedLiveMs = now - _autoLiveState.liveStartedAt;
		            if (selectedIds.length && !_autoLiveState.switchedAfterInactive) {
		                if (elapsedLiveMs < 120000) {
		                    let remain = Math.ceil((120000 - elapsedLiveMs) / 1000);
		                    lbSetAutoLiveButton(true, `🛰 Chờ ${remain}s`);
		                    return;
		                }
	                if (activeCamps.length) {
	                    if (!roomId) {
	                        lbSetAutoLiveButton(true, '🛰 Chờ room');
	                        return;
	                    }
	                    _autoLiveState.switchedAfterInactive = true;
	                    lbSelectCampIds(activeCamps.map(c => c.id));
	                    await lbStartEngineFromWatcher('Camp cũ chưa hoạt động sau 2 phút, chuyển sang camp đang chạy', activeCamps);
	                    lbMarkAutoLiveRunning();
	                    return;
	                }
	                lbSetAutoLiveButton(true, '🛰 Tìm camp');
	                return;
	            }

	            if (activeCamps.length) {
	                if (!roomId) {
	                    lbSetAutoLiveButton(true, '🛰 Chờ room');
	                    return;
	                }
	                lbSelectCampIds(activeCamps.map(c => c.id));
	                await lbStartEngineFromWatcher('Tìm thấy camp LIVE đang chạy', activeCamps);
	                lbMarkAutoLiveRunning();
	                return;
	            }
	            lbSetAutoLiveButton(true, '🛰 Tìm camp');
		        } catch (err) {
		            lbLog(`🛰 Auto watcher lỗi: ${err.message}`, 'error');
		        } finally {
		            _autoLiveState.busy = false;
		            _autoLiveState.busySince = 0;
		        }
		    }

	    function lbStartAutoLiveWatcher(restored = false) {
	        if (_autoLiveTimer) clearInterval(_autoLiveTimer);
	        _autoLiveTimer = null;
		        _autoLiveState = {
		            enabled: true,
		            busy: false,
		            busySince: 0,
		            liveStartedAt: 0,
		            roomOnCount: 0,
		            campActiveSeen: false,
	            switchedAfterInactive: false,
	        };
	        lbPersistOpsSettings({ autoLiveWatcher: true });
	        if (!restored) lbLog('🛰 Auto chờ LIVE/camp ads đã bật', 'success');
	        lbResetAutoLiveCycle('🛰 Đang chờ', 0);
	    }

	    function lbStopAutoLiveWatcher(persist = true) {
	        _autoLiveState.enabled = false;
	        if (_autoLiveTimer) { clearInterval(_autoLiveTimer); _autoLiveTimer = null; }
	        lbSetAutoLiveButton(false, '🛰 Auto');
	        if (persist) lbPersistOpsSettings({ autoLiveWatcher: false });
	    }

	    if (!window.__STRANGETTS_LIVE_WAKE_BOUND__) {
	        window.__STRANGETTS_LIVE_WAKE_BOUND__ = true;
	        document.addEventListener('visibilitychange', () => {
	            if (document.visibilityState === 'visible') lbForceCurrentLiveScan('tab visible');
	        });
	        window.addEventListener('focus', () => lbForceCurrentLiveScan('window focus'));
	        chrome.runtime.onMessage.addListener((msg) => {
	            if (msg?.action === 'STRANGETTS_LIVE_WAKE_CHECK') {
	                lbForceCurrentLiveScan('background alarm');
	            }
	        });
	    }

	    // ===== START / STOP =====
	    async function startEngine() {
	        if (state.running || state._starting) {
	            lbLog('🔒 Auto-Adjust đang chạy/đang khởi động, bỏ qua lệnh start lặp', 'info');
	            return true;
	        }
	        let cfg = await strangettsGetLiveBetaConfig();
	        lbPersistSelectedCampIds();
	        state._cfg = cfg;
	        state.running = true;
	        state._ending = false;
	        state._stopInProgress = false;
	        state._pollBusy = false;
	        state._wakePollBusy = false;
	        state._liveEndNotifyKey = '';
	        state._liveEndNotifySentAt = 0;
	        state._diagnosisGeneratedKey = '';
        state.startTime = Date.now();
	        state.tickCount = 0;
	        state.instantCount = 0;
	        state.budgetEditCount = 0;
	        state.budgetEditBySource = {};
	        state.scheduledCount = 0;
        state.firstScheduledDone = false;
        state.lastScheduledTime = 0;
	        state.snapshots = {};
	        state.lastInstantTime = {};
	        state.pendingConfirms = [];
	        state._emptyTicks = 0;
	        state._hadRunningCamps = false;
	        state._consecutiveErrors = 0;
		        state._staleStatsTicks = 0;
		        state._starting = true;
		        state._executingAction = null;
		        state._stratHandledThisTick = false;
		        state._lastLiveGmv = null;
		        state._lockedRoomId = null;
		        state._lockedRoomAt = 0;
		        window.__STRANGETTS_LOCKED_ROOM_ID__ = '';
	        state._roomStatusOffCount = 0;
        state._roomStatusErrCount = 0;
	        state._liveDuration = 0;
	        state._startBaselineApplied = false;
	        state._liveRoomConfirmed = false;
	        state._liveRoomConfirmedRoomId = null;
	        state._liveSummarySentRoomId = null;
	        state._liveSummarySentAt = 0;
		        state._roomSessionCache = {};
		        state._currentRoomId = null;
		        state._resultRoomId = null;
		        state._currentRoomMatchedCampId = null;
		        state._currentRoomSession = null;
			        lbClearRoomId('bắt đầu phiên mới, chỉ nhận room từ post_room_list live_status=1', { force: true });
		        lbResetLiveUiForRoomChange('', '');

	        // Every new run represents a fresh LIVE shift: start now, keep the configured session duration.
	        lbApplyDefaultLiveWindow(cfg, lbGetConfiguredLiveDurationHours(cfg, 3), 'start');

	        // ═══ STRATEGY V3: init state ═══
	        {
	            const rawBudget = lbGetConfiguredSessionBudget(cfg);
	            const rawRoi = lbGetConfiguredSessionRoi(cfg, 5.0);
	            const startupBudget = lbGetConfiguredInitialBudget(cfg);
	            const startupRoi = lbGetConfiguredInitialRoi(cfg);
	            const startupWindowMin = lbGetConfiguredInitialWindowMin(cfg);
            const liveStartStr = cfg.strat_live_start_time || document.getElementById('lb-live-start')?.value || '';
            const liveEndStr   = cfg.strat_live_end_time || document.getElementById('lb-live-end')?.value || '';
            function parseHHMM(str) {
                if (!str || !str.includes(':')) return null;
                const [h, m] = str.split(':').map(Number);
                if (isNaN(h) || isNaN(m)) return null;
                const d = new Date(); d.setHours(h, m, 0, 0); return d.getTime();
            }
            const liveStartTs  = parseHHMM(liveStartStr) || Date.now();
            const liveEndTs    = parseHHMM(liveEndStr)   || (liveStartTs + 150 * 60000);
            const totalMinutes = Math.max(30, Math.round((liveEndTs - liveStartTs) / 60000));
            const p1PullRoi = startupRoi;

            state.strategy = {
                enabled:      cfg.strat_enabled,
                goal_mode:    cfg.strat_goal_mode || 'balanced',
                target_roi:   rawRoi,
                budget_cap:   rawBudget,
                target_revenue: rawBudget * rawRoi,
                live_start:   liveStartTs,
                live_end:     liveEndTs,
                total_minutes: totalMinutes,
                session_day_key: strangettsDayKey(),
                active_campaign_id: null,
                p1_pull_roi:  p1PullRoi,
                initial_budget: startupBudget,
                initial_roi: startupRoi,
                initial_window_min: startupWindowMin,
                manual_adjust_applied: {},
                start_spend:  null,
                start_gmv:    null,
                last_checkpoint_spend:    null,
                last_budget_edit_at:      0,
                last_roi_edit_at:         0,
                roi_edit_count:           0,
                budget_edit_count:        0,
                p1_roi_set:               false,
                p1_budget_added:          0,
                p1_hard_cold_checkpoints: 0,
                lastTrafficHeat:          'UNKNOWN',
                rolling_roi_15m:          rawRoi,
                rolling_spend_10m:        0,
                spend_pace_per_min:       0,
                rolling_gpm_10m:          0,
                tick_history:             [],
                api_last_edit_ok:         true,
            };
            if (cfg.strat_enabled) {
                lbLog(`⚡ Strategy V3 INIT: target_roi=${rawRoi} budget_cap=${strangettsShortVN(rawBudget)} target_revenue=${strangettsShortVN(rawBudget*rawRoi)} baseline=${startupWindowMin}p ${strangettsShortVN(startupBudget)} / ROI ${p1PullRoi} phiên=${totalMinutes}p`, 'success');
            }
        }

        let btn = document.getElementById('lb-toggle');
        btn.textContent = '⏹ Dừng';
        btn.style.background = 'linear-gradient(135deg,#DC2626,#EF4444)';

        lbLog('🚀 Auto-Adjust started!', 'success');
        lbLog(`📺 Theo dõi ${state.selectedCampIds.size} camp | Poll: ${cfg.poll_interval_sec}s | Instant: ${cfg.instant_enabled ? 'ON' : 'OFF'}`, 'info');

	        // Show emergency stop button
	        let sosBtn = document.getElementById('lb-emergency-stop');
	        if (sosBtn) sosBtn.style.display = '';

	        // Initial prime FIRST: load selected camps, set start baseline, then let normal rules run from next poll.
				        let primedStart = await lbPrimeStartCamps(cfg);
				        if (!primedStart) {
				            state._starting = false;
				            state._pendingStartRoomId = null;
				            state._pendingStartRoomSession = null;
				            state._pendingStartCampId = null;
				            lbAbortStartWithoutNotification('⚠️ Không tìm thấy camp đã chọn trong dữ liệu Ads hiện tại. Bấm "Quét camp" để kiểm tra lại, hoặc bật 🛰 Auto để chờ camp xuất hiện.');
				            if (_autoLiveState?.enabled) lbResetAutoLiveCycle('🛰 Chờ camp', 3000);
				            return false;
				        }
			        let sessionRoomId = lbGetMetricRoomId();
				        if (!sessionRoomId) {
				            state._starting = false;
				            state._pendingStartRoomId = null;
				            state._pendingStartRoomSession = null;
				            state._pendingStartCampId = null;
				            lbAbortStartWithoutNotification('⚠️ Không lấy được room_id live_status=1 từ post_room_list. Auto sẽ chờ room để tránh lấy nhầm phiên cũ.');
				            if (_autoLiveState?.enabled) lbResetAutoLiveCycle('🛰 Chờ room', 3000);
				            return false;
				        }
			        lbLockRoomIdForSession(sessionRoomId, 'khởi động live');
			        state._starting = false;

	        if (chatState.autoReminder && !chatState.reminderTimer) lbStartReminderTimerFromSettings();
	        if (lbGiveawayAutoRequested() && !giveawayState.timer) lbStartGiveawayTimer();
	        if (document.getElementById('lb-autopin-toggle')?.checked && !lv3State.autoPinRunning) lbStartAutoPin();

        // ═══ STRATEGY V3: fill start_spend/gmv sau poll đầu ═══
        if (state.strategy?.enabled && state.camps?.length > 0) {
            const sel = state.camps.filter(c => state.selectedCampIds.has(String(c.id)));
            const _pn = v => parseFloat(String(v||'0').replace(/\./g,'').replace(/,/g,'')) || 0;
            const primaryCamp = sel.reduce((best, c) =>
                _pn(c.spend) > _pn(best?.spend) ? c : best
            , sel[0] || null);
            if (primaryCamp) {
                const primarySpend = _pn(primaryCamp.spend);
                const primaryGmv = _pn(primaryCamp.gmv);
                state.strategy.active_campaign_id = String(primaryCamp.id);
                state.strategy.session_day_key = strangettsDayKey();
                state.strategy.start_spend = primarySpend;
                state.strategy.start_gmv   = primaryGmv;
                state.strategy.last_checkpoint_spend = primarySpend;
                lbLog(`⚡ Strategy V3 snapshot: start_spend=${strangettsShortVN(primarySpend)} start_gmv=${strangettsShortVN(primaryGmv)}`, 'info');
            }
        }

	        // Send Telegram start notification AFTER first poll (so camps + account name are loaded)
	        if (isNotifyReady(cfg)) {
	            let campNames = state.camps.filter(c => state.selectedCampIds.has(String(c.id))).map(c => c.name?.substring(0, 40) || c.id).join('\n📌 ');
	            let firstReviewMin = state.strategy?.enabled
	                ? Math.min(parseInt(cfg.sched_first_min, 10) || 30, parseInt(cfg.strat_first_review_min, 10) || 10)
	                : (parseInt(cfg.sched_first_min, 10) || 30);
	            await strangettsNotifySend(`${getLiveAccountLabel()}\n🚀 <b>BẮT ĐẦU THEO DÕI LIVE</b>\n📌 Camp đang theo dõi:\n${campNames}\n⏱ Quét mỗi: ${cfg.poll_interval_sec} giây | Đánh giá đầu: ${firstReviewMin} phút`, cfg);
	        }

        // Start polling loop
        state.pollTimer = setInterval(() => pollTick(cfg), cfg.poll_interval_sec * 1000);

        // Start heartbeat (room/status every 60s)
        _startHeartbeat();

        lbUpdateMonitor();
    }

	    async function stopEngine(reason = 'manual') {
	        if (state._stopInProgress) {
	            lbLog(`🔒 stopEngine đang xử lý, bỏ qua lệnh lặp (${reason})`, 'info');
	            return;
	        }
	        state._stopInProgress = true;
		        state.running = false;
		        state._ending = true;
		        state._starting = false;
	        if (state.pollTimer) { clearInterval(state.pollTimer); state.pollTimer = null; }
	        _stopHeartbeat();
	        lbStopGiveawayTimer();
	        lbStopAutoPin();
	        // Stop chat reminder timer
	        if (chatState.reminderTimer) { clearInterval(chatState.reminderTimer); chatState.reminderTimer = null; }
	        if (_gwCountdownTimer) { clearInterval(_gwCountdownTimer); _gwCountdownTimer = null; }

        let btn = document.getElementById('lb-toggle');
        btn.textContent = '▶ Bắt đầu';
        btn.style.background = 'linear-gradient(135deg,#16A34A,#22C55E)';
        updateToggleBtn();

        // Hide emergency stop button
        let sosBtn = document.getElementById('lb-emergency-stop');
        if (sosBtn) sosBtn.style.display = 'none';

		        // Clear saved state so it doesn't auto-resume. Keep room/session until after diagnosis,
		        // otherwise the final summary cannot refresh exact room_id metrics.
		        chrome.storage.local.remove('tt_livebeta_state');

        lbLog(`⏹ Dừng sau ${state.tickCount} tick, ${state.instantCount} instant, ${state.scheduledCount} scheduled`, 'info');
        lbUpdateMonitor();

	        const isConfigRestart = reason === 'config_restart';
	        const isAutoStop = String(reason || '').startsWith('auto_');
	        const isEmergencyStop = reason === 'emergency';
	        // Auto/end and emergency paths already send their own context message.
	        let cfg = state._cfg;
		        if (!isConfigRestart && !isAutoStop && !isEmergencyStop && isNotifyReady(cfg)) {
			            let runtime = state.startTime ? Math.floor((Date.now() - state.startTime) / 60000) : 0;
			            let liveData = cfg?.data_live_dash_enabled ? (window.__STRANGETTS_LIVE_DASHBOARD__ || null) : null;
			            await lbRefreshResultRoomMetricsForSummary();
			            let resultLines = lbLiveResultLines(liveData, { runtimeMin: runtime, endedAt: new Date() });
		            await strangettsNotifySend(`${getLiveAccountLabel()}\n⏹ <b>ĐÃ DỪNG THEO DÕI LIVE</b>\n⏱ Thời gian chạy: ${runtime} phút\n${resultLines}📊 Số lần quét: ${state.tickCount} | Điều chỉnh nhanh: ${state.instantCount} | Đánh giá định kỳ: ${state.scheduledCount}`, cfg);
	        }

		        // Auto-generate post-LIVE diagnosis before clearing room/session data.
		        if (!isConfigRestart && !isEmergencyStop) await generateSessionDiagnosis();

	        if (String(reason || '').startsWith('auto_')) {
		            lbClearRoomId('phiên live đã kết thúc');
		            state._lockedRoomId = null;
		            state._lockedRoomAt = 0;
		            window.__STRANGETTS_LOCKED_ROOM_ID__ = '';
		            state._roomSessionCache = {};
		            state._currentRoomId = null;
		            state._resultRoomId = null;
		            state._currentRoomMatchedCampId = null;
		            state._currentRoomSession = null;
		        }

	        if (_autoLiveState?.enabled) {
	            if (String(reason || '').startsWith('auto_')) {
	                lbLog('🛰 Auto chờ LIVE vẫn bật — reset về chế độ chờ ca tiếp theo', 'info');
	                lbResetAutoLiveCycle('🛰 Chờ ca mới', 3000);
	            } else if (reason === 'manual' || reason === 'emergency') {
	                lbStopAutoLiveWatcher(true);
	                lbLog('🛰 Auto chờ LIVE đã tắt do dừng thủ công', 'info');
	            }
	        }
	    }

    // Emergency stop — stops all + clears pending + notifies Telegram
    async function emergencyStop() {
        lbLog('🔴 DẪNH KHẨN CẤP — dừng tất cả!', 'error');
        let cfg = state._cfg || await strangettsGetLiveBetaConfig();
        // Clear pending confirms
        let pendingCount = state.pendingConfirms.length;
        state.pendingConfirms = [];
        state._executingAction = null;
	        stopEngine('emergency');
        if (isNotifyReady(cfg)) {
            await strangettsNotifySend(`${getLiveAccountLabel()}\n🔴 <b>EMERGENCY STOP</b>\nDừng tất cả auto-adjust.\n❤ ${pendingCount} pending actions bị hủy.`, cfg);
        }
    }

    // ===== EVENT HANDLERS =====

    // Emergency stop button
    document.getElementById('lb-emergency-stop').onclick = () => emergencyStop();

    // GMV Formula Bottleneck Detection
    // GMV = Duration × Impressions/hr × Enter Rate × GPM × 1000
    function detectGMVBottleneck(liveData, durationMin) {
        if (!liveData) return null;
        let factors = [];
        let duration = durationMin || 0;
        let impressionsPerHr = liveData.impressions ? (liveData.impressions / Math.max(1, duration / 60)) : 0;
        let enterRate = liveData.enterRate || 0;
        let gpm = liveData.gpm || 0;

        // Score each factor 0-100
        let durationScore = duration >= 120 ? 100 : duration >= 60 ? 60 + (duration - 60) / 60 * 40 : duration / 60 * 60;
        let impScore = impressionsPerHr >= 5000 ? 100 : impressionsPerHr >= 2000 ? 50 + (impressionsPerHr - 2000) / 3000 * 50 : impressionsPerHr / 2000 * 50;
        let enterScore = enterRate >= 5 ? 100 : enterRate >= 2 ? 40 + (enterRate - 2) / 3 * 60 : enterRate / 2 * 40;
        let gpmScore = gpm >= 30000 ? 100 : gpm >= 15000 ? 50 + (gpm - 15000) / 15000 * 50 : gpm / 15000 * 50;

	        factors.push({ name: 'Thời lượng live', score: Math.round(durationScore), value: `${duration}p`, emoji: '⏱' });
	        factors.push({ name: 'Lượt hiển thị/giờ', score: Math.round(impScore), value: Math.round(impressionsPerHr).toLocaleString('vi-VN'), emoji: '👁' });
	        factors.push({ name: 'Tỷ lệ vào phòng', score: Math.round(enterScore), value: `${enterRate.toFixed(1)}%`, emoji: '🚪' });
	        factors.push({ name: 'Doanh thu/1.000 hiển thị', score: Math.round(gpmScore), value: strangettsFormatVN(gpm), emoji: '💰' });

        factors.sort((a, b) => a.score - b.score);
        return {
            factors,
            weakest: factors[0],
            strongest: factors[factors.length - 1],
	            bottleneckMsg: `Cần ưu tiên cải thiện: ${factors[0].emoji} ${factors[0].name} (${factors[0].score}/100 — ${factors[0].value})`
	        };
	    }

    // Post-LIVE Session Diagnosis
	    async function generateSessionDiagnosis() {
	        if (!state.startTime) return;
	        let diagnosisKey = state._liveEndNotifyKey || lbCurrentLiveEndKey('diagnosis');
	        if (state._diagnosisGeneratedKey === diagnosisKey) {
	            lbLog('📊 Bỏ qua post-live diagnosis lặp cho cùng phiên', 'info');
	            return null;
	        }
	        state._diagnosisGeneratedKey = diagnosisKey;
	        let durationMin = Math.round((Date.now() - state.startTime) / 60000);
	        let cfg = state._cfg || await strangettsGetLiveBetaConfig();
	        let liveData = null;
        if (cfg.data_live_dash_enabled) {
            try { liveData = window.__STRANGETTS_LIVE_DASHBOARD__; } catch (e) { }
        }

	        await lbRefreshResultRoomMetricsForSummary();

	        // Collect action history
        let actions = state.log.filter(l => l.type === 'instant' || l.type === 'scheduled');
        let budgetActions = actions.filter(l => l.newBudget > l.oldBudget);
        let totalBudgetAdded = budgetActions.reduce((s, l) => s + (l.newBudget - l.oldBudget), 0);

        // GMV bottleneck
        let bottleneck = detectGMVBottleneck(liveData, durationMin);

        // Quality checklist (5 criteria from TikTok)
        let qualityChecklist = [];
        if (liveData) {
	            qualityChecklist.push({ name: 'Tỷ lệ vào phòng', value: `${(liveData.enterRate || 0).toFixed(1)}%`, pass: (liveData.enterRate || 0) >= 2 });
	            qualityChecklist.push({ name: 'Thời gian xem trung bình', value: `${(liveData.avgViewDuration || 0).toFixed(0)}s`, pass: (liveData.avgViewDuration || 0) >= 20 });
	            qualityChecklist.push({ name: 'Doanh thu/1.000 hiển thị', value: strangettsFormatVN(liveData.gpm || 0), pass: (liveData.gpm || 0) >= 10000 });
	            qualityChecklist.push({ name: 'Tỷ lệ đặt hàng', value: `${(liveData.orderRate || 0).toFixed(1)}%`, pass: (liveData.orderRate || 0) >= 1.5 });
	            qualityChecklist.push({ name: 'Vi phạm', value: liveData.hasViolation ? '❌ Có' : '✅ Không', pass: !liveData.hasViolation });
	        }

	        // Build report
		        let resultLines = lbLiveResultLines(liveData, { runtimeMin: durationMin, endedAt: new Date() });
	        let report = `${getLiveAccountLabel()}\n📊 <b>TỔNG KẾT SAU LIVE</b>\n━━━━━━━━━━━━\n`;
	        report += `⏱ Thời lượng theo dõi: <b>${durationMin} phút</b>\n`;
	        report += resultLines;
	        report += `⚙️ Đã tăng ngân sách: ${budgetActions.length} lần\n`;
	        report += `➕ Tổng ngân sách đã thêm: <b>${strangettsShortVN(totalBudgetAdded)}</b>\n`;
	        report += `🔁 Số lần quét: ${state.tickCount} | Điều chỉnh nhanh: ${state.instantCount} | Đánh giá định kỳ: ${state.scheduledCount}\n`;

	        if (bottleneck) {
	            report += `\n🔍 <b>Điểm nghẽn doanh thu</b>\n`;
	            bottleneck.factors.forEach(f => {
	                let bar = f.score >= 70 ? '✅' : f.score >= 40 ? '⚠️' : '❌';
	                report += `${bar} ${f.emoji} ${f.name}: ${f.value} (${f.score}/100)\n`;
	            });
	            report += `👉 ${bottleneck.bottleneckMsg}\n`;
	        }

	        if (qualityChecklist.length) {
	            report += `\n📋 <b>Chất lượng phiên live</b>\n`;
	            qualityChecklist.forEach(q => {
	                report += `${q.pass ? '✅' : '❌'} ${q.name}: ${q.value}\n`;
	            });
	            let passCount = qualityChecklist.filter(q => q.pass).length;
	            report += `📈 ${passCount}/${qualityChecklist.length} đạt\n`;
	        }

	        // Camp scores summary
	        if (state.camps.length) {
	            report += `\n📺 <b>Điểm camp quảng cáo</b>\n`;
	            for (let camp of state.camps) {
	                let score = strangettsLiveScore(camp, liveData, cfg);
	                report += `${score.emoji} ${(camp.name || camp.id).substring(0, 25)}: ${score.totalScore}/100\n`;
            }
        }

        // Log locally
        lbLog('📊 === POST-LIVE DIAGNOSIS ===', 'success');
	        lbLog(`⏱ ${durationMin}p | ⚡${budgetActions.length} tăng NS | 💰+${strangettsShortVN(totalBudgetAdded)}`, 'info');
        if (bottleneck) lbLog(`🔍 ${bottleneck.bottleneckMsg}`, 'info');

        // Send to Telegram
        if (isNotifyReady(cfg)) {
            await strangettsNotifySend(report, cfg);
        }

        // Call Gemini AI for post-live analysis
        if (cfg.gemini_enabled && cfg.gemini_api_key && state.camps.length > 0) {
            try {
	                let aiResult = await strangettsGeminiAnalyze(state.camps, liveData, cfg, {}, 'post-live', lbBuildGeminiExtraContext());
                if (aiResult && aiResult.length > 0) {
                    // Send AI analysis to Telegram
                    if (isNotifyReady(cfg)) {
	                        let teleMsg = `🤖 <b>AI Tổng kết LIVE</b>\n`;
	                        if (aiResult._modelUsed) teleMsg += `🧠 Model: <b>${strangettsGeminiModelLabel(aiResult._modelUsed)}</b>\n`;
                        aiResult.forEach(r => {
                            let conf = r.confidence === 'high' ? '🟢' : r.confidence === 'medium' ? '🟡' : '🔴';
                            teleMsg += `\n${conf} <b>${r.name || ''}</b>\n`;
                            if (r.summary) teleMsg += `📝 ${r.summary}\n`;
                            if (r.risk) teleMsg += `⚠️ ${r.risk}\n`;
                            if (r.suggestion) teleMsg += `💡 ${r.suggestion}\n`;
                        });
                        await strangettsNotifySend(teleMsg, cfg);
                    }
                    lbLog('🤖 AI đã phân tích post-live → gửi Telegram ✅', 'success');
                }
            } catch (e) { lbLog('🤖 AI post-live error: ' + e.message, 'error'); }
        }

        return report;
    }

